// ============================================================
//          AUTH SESSION BRIDGE — server session cookie only
//          جلسة سيرفر عبر mbk_session فقط
// ============================================================

const AUTH_COOKIE_NAME = process.env.MURABBIK_AUTH_COOKIE || "mbk_session";
const AUTH_SESSION_DAYS = Number(process.env.MURABBIK_SESSION_DAYS || 7);
const AUTH_SESSION_EXPIRES_MS = Math.max(1, AUTH_SESSION_DAYS) * 24 * 60 * 60 * 1000;

function authDigitsBridgeSrv(raw) {
  const map = {
    "٠":"0","١":"1","٢":"2","٣":"3","٤":"4","٥":"5","٦":"6","٧":"7","٨":"8","٩":"9",
    "۰":"0","۱":"1","۲":"2","۳":"3","۴":"4","۵":"5","۶":"6","۷":"7","۸":"8","۹":"9"
  };

  return String(raw || "")
    .trim()
    .replace(/[٠-٩۰-۹]/g, d => map[d] || d)
    .replace(/\D/g, "");
}

function authCookieValueBridgeSrv(req, name) {
  const raw = String(req.headers.cookie || "");
  if (!raw) return "";

  for (const part of raw.split(";")) {
    const i = part.indexOf("=");
    if (i < 0) continue;

    const k = part.slice(0, i).trim();
    if (k !== name) continue;

    try {
      return decodeURIComponent(part.slice(i + 1).trim());
    } catch (_) {
      return part.slice(i + 1).trim();
    }
  }

  return "";
}

function authIsHttpsReqBridgeSrv(req) {
  return Boolean(
    req.secure ||
    String(req.headers["x-forwarded-proto"] || "").split(",")[0].trim() === "https"
  );
}

function authSetSessionCookieBridgeSrv(req, res, sessionCookie) {
  res.cookie(AUTH_COOKIE_NAME, sessionCookie, {
    httpOnly: true,
    secure: authIsHttpsReqBridgeSrv(req),
    sameSite: "lax",
    path: "/",
    maxAge: AUTH_SESSION_EXPIRES_MS
  });
}

function authClearSessionCookieBridgeSrv(req, res) {
  res.clearCookie(AUTH_COOKIE_NAME, {
    httpOnly: true,
    secure: authIsHttpsReqBridgeSrv(req),
    sameSite: "lax",
    path: "/"
  });
}

function authPublicUserBridgeSrv(profile = {}, uid = "", userId = "") {
  return {
    uid,
    userId,
    name: profile.name || profile.displayName || profile.fullName || "",
    phone: profile.phone || profile.phoneNumber || "",
    role: profile.role || profile.accountRole || "",
    farmName: profile.farmName || profile.farm || ""
  };
}

async function authReadUserProfileBridgeSrv(uid) {
  if (!db || !uid) return {};

  try {
    const snap = await db.collection("users").doc(uid).get();
    return snap.exists ? (snap.data() || {}) : {};
  } catch (e) {
    console.warn("auth bridge user profile read failed:", e.message || e);
    return {};
  }
}

async function authSessionFromRequestBridgeSrv(req) {
  try {
    const sessionCookie = authCookieValueBridgeSrv(req, AUTH_COOKIE_NAME);
    if (!sessionCookie || !admin.apps.length) return null;

    const decoded = await admin.auth().verifySessionCookie(sessionCookie, false);
    const uid = String(decoded.uid || "").trim();
    if (!uid) return null;

    const profile = await authReadUserProfileBridgeSrv(uid);

    // نفس userId القديم، حتى لا تنفصل بيانات الحساب
    const userId = tenantKey(profile.userId || profile.tenantId || profile.ownerUid || uid);

    return {
      uid,
      userId,
      decoded,
      user: authPublicUserBridgeSrv(profile, uid, userId)
    };
  } catch (_) {
    return null;
  }
}

async function authPasswordLoginBridgeSrv(email, password) {
  const apiKey =
    process.env.FIREBASE_WEB_API_KEY ||
    process.env.FIREBASE_API_KEY ||
    process.env.MURABBIK_FIREBASE_API_KEY ||
    "";

  if (!apiKey) {
    const err = new Error("firebase_web_api_key_missing");
    err.publicMessage = "❌ خدمة تسجيل الدخول غير متاحة الآن. حاول مرة أخرى لاحقًا.";
    throw err;
  }

  const r = await fetch(
    `https://identitytoolkit.googleapis.com/v1/accounts:signInWithPassword?key=${encodeURIComponent(apiKey)}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        email,
        password,
        returnSecureToken: true
      })
    }
  );

  const data = await r.json().catch(() => ({}));

  if (!r.ok || !data.idToken) {
    const err = new Error(data?.error?.message || "login_failed");
    err.publicMessage = "❌ رقم الهاتف أو كلمة المرور غير صحيحة.";
    throw err;
  }

  return data;
}
function authRegisterTextBridgeSrv(v) {
  return String(v || "").trim().replace(/\s+/g, " ");
}
const AUTH_OTP_TTL_MS = Number(process.env.MURABBIK_OTP_TTL_MS || 10 * 60 * 1000);
const AUTH_OTP_MAX_ATTEMPTS = Number(process.env.MURABBIK_OTP_MAX_ATTEMPTS || 5);
const AUTH_OTP_DEV_RETURN = process.env.MURABBIK_OTP_DEV_RETURN === "1";

function authSha256BridgeSrv(v) {
  return crypto.createHash("sha256").update(String(v || "")).digest("hex");
}

function authOtpCodeBridgeSrv() {
  return String(crypto.randomInt(100000, 1000000));
}

function authOtpHashBridgeSrv(code, salt) {
  return authSha256BridgeSrv(`${salt}:${code}`);
}

function authRegisterPasswordIssueBridgeSrv(password, ctx = {}) {
  const p = String(password || "");
  const phoneKey = String(ctx.phoneKey || "").trim();
  const fullName = String(ctx.fullName || "").trim().toLowerCase();

  if (p.length < 8) return "كلمة المرور يجب أن تكون ٨ أحرف أو أكثر.";
  if (!/[A-Za-z\u0600-\u06FF]/.test(p)) return "كلمة المرور يجب أن تحتوي على حرف واحد على الأقل.";
  if (!/[0-9٠-٩۰-۹]/.test(p)) return "كلمة المرور يجب أن تحتوي على رقم واحد على الأقل.";

  const passDigits = authDigitsBridgeSrv(p);
  if (phoneKey && (passDigits === phoneKey || p.includes(phoneKey))) {
    return "لا تستخدم رقم الهاتف داخل كلمة المرور.";
  }

  const weakList = ["12345678", "11111111", "00000000", "password", "qwerty", "murabbik", "مربيك"];
  if (weakList.includes(p.toLowerCase())) return "كلمة المرور ضعيفة جدًا، اختر كلمة أقوى.";

  const nameParts = fullName.split(/\s+/).map(s => s.trim()).filter(s => s.length >= 3);
  for (const part of nameParts) {
    if (part && p.toLowerCase().includes(part)) return "لا تستخدم اسمك داخل كلمة المرور.";
  }

  if (/^(.)\1{7,}$/.test(p)) {
    return "كلمة المرور ضعيفة جدًا، لا تستخدم نفس الحرف أو الرقم مكررًا.";
  }

  return "";
}

async function authSendOtpBridgeSrv(phoneRaw, code) {
  const webhook = String(process.env.MURABBIK_SMS_WEBHOOK_URL || "").trim();

  if (!webhook) {
    if (AUTH_OTP_DEV_RETURN) return { ok: true, dev: true };
    return {
      ok: false,
      error: "sms_provider_missing",
      message: "❌ تعذّر إرسال كود التحقق الآن. حاول مرة أخرى لاحقًا."
    };
  }

  const text = `كود التحقق من مُرَبِّيك: ${code}. صالح لمدة 10 دقائق.`;

  try {
    const r = await fetch(webhook, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        to: phoneRaw,
        message: text,
        code,
        purpose: "register"
      })
    });

    if (!r.ok) {
      return {
        ok: false,
        error: "sms_send_failed",
        message: "❌ تعذّر إرسال كود التحقق الآن. حاول مرة أخرى."
      };
    }

    return { ok: true };

  } catch (e) {
    console.warn("otp sms send failed:", e.message || e);
    return {
      ok: false,
      error: "sms_send_failed",
      message: "❌ تعذّر إرسال كود التحقق الآن. حاول مرة أخرى."
    };
  }
}
function authRegisterValidateBridgeSrv(body = {}) {
  const fullName = authRegisterTextBridgeSrv(body.fullName || body.name || body.displayName);
  const phoneRaw = authRegisterTextBridgeSrv(body.phone || body.phoneNumber);
  const phoneKey = authDigitsBridgeSrv(phoneRaw);
  const country = authRegisterTextBridgeSrv(body.country);
  const region = authRegisterTextBridgeSrv(body.region || body.governorate || body.area);
  const role = authRegisterTextBridgeSrv(body.role);
  const password = String(body.password || "");
  const confirmPassword = String(body.confirmPassword || body.passwordConfirm || "");

  if (!fullName || !phoneRaw || !country || !region || !role || !password || !confirmPassword) {
    return {
      ok: false,
      status: 400,
      error: "register_fields_required",
      message: "❌ أكمل جميع بيانات إنشاء الحساب."
    };
  }

  if (!phoneKey) {
    return {
      ok: false,
      status: 400,
      error: "register_phone_invalid",
      message: "❌ أدخل رقم هاتف صحيحًا."
    };
  }

  if (country === "مصر" && !/^01\d{9}$/.test(phoneKey)) {
    return {
      ok: false,
      status: 400,
      error: "register_phone_country_invalid",
      message: "❌ رقم الهاتف لا يطابق الدولة المختارة."
    };
  }

  if (country !== "مصر" && !/^\d{7,15}$/.test(phoneKey)) {
    return {
      ok: false,
      status: 400,
      error: "register_phone_country_invalid",
      message: "❌ رقم الهاتف لا يطابق الدولة المختارة."
    };
  }

 const passwordIssue = authRegisterPasswordIssueBridgeSrv(password, {
  fullName,
  phoneKey
});

if (passwordIssue) {
  return {
    ok: false,
    status: 400,
    error: "register_password_weak",
    message: passwordIssue
  };
}

  if (password !== confirmPassword) {
    return {
      ok: false,
      status: 400,
      error: "register_password_mismatch",
      message: "❌ تأكيد كلمة المرور لا يطابق كلمة المرور."
    };
  }

  return {
    ok: true,
    fullName,
    phoneRaw,
    phoneKey,
    country,
    region,
    role,
    password
  };
}

async function authRegisterStartHandlerBridgeSrv(req, res) {
  try {
    if (!admin.apps.length || !db) {
      return res.status(503).json({
        ok: false,
        error: "firebase_admin_disabled",
        message: "❌ خدمة إنشاء الحساب غير متاحة الآن. حاول مرة أخرى لاحقًا."
      });
    }

    const v = authRegisterValidateBridgeSrv(req.body || {});

    if (!v.ok) {
      return res.status(v.status || 400).json({
        ok: false,
        error: v.error || "register_invalid",
        message: v.message || "راجع بيانات إنشاء الحساب."
      });
    }

    const pseudoEmail = `${v.phoneKey}@murabbik.local`;

    try {
      await admin.auth().getUserByEmail(pseudoEmail);
      return res.status(409).json({
        ok: false,
        error: "phone_already_registered",
        message: "ℹ️ رقم الهاتف مسجّل بالفعل. سجّل الدخول أو استعد كلمة المرور."
      });
    } catch (e) {
      if (e?.code && e.code !== "auth/user-not-found") throw e;
    }

    const code = authOtpCodeBridgeSrv();
    const otpSalt = crypto.randomBytes(16).toString("hex");
    const passwordSalt = crypto.randomBytes(16).toString("hex");
    const requestId = crypto.randomBytes(18).toString("hex");

    const sent = await authSendOtpBridgeSrv(v.phoneRaw, code);

    if (!sent.ok) {
      return res.status(503).json({
        ok: false,
        error: sent.error || "otp_send_failed",
        message: sent.message || "❌ تعذّر إرسال كود التحقق الآن. حاول مرة أخرى."
      });
    }

    await db.collection("auth_register_otps").doc(requestId).set({
      type: "register",
      phoneRaw: v.phoneRaw,
      phoneKey: v.phoneKey,
      fullName: v.fullName,
      country: v.country,
      region: v.region,
      role: v.role,

      otpHash: authOtpHashBridgeSrv(code, otpSalt),
      otpSalt,

      passwordHash: authOtpHashBridgeSrv(v.password, passwordSalt),
      passwordSalt,

      attempts: 0,
      maxAttempts: AUTH_OTP_MAX_ATTEMPTS,
      usedAt: null,
      expiresAt: admin.firestore.Timestamp.fromDate(new Date(Date.now() + AUTH_OTP_TTL_MS)),
      createdAt: admin.firestore.FieldValue.serverTimestamp(),
      source: "server:/api/auth/register/start"
    }, { merge: false });

    const out = {
      ok: true,
      otpRequired: true,
      requestId,
      expiresInSeconds: Math.floor(AUTH_OTP_TTL_MS / 1000),
      message: "✅ أرسلنا كود التحقق إلى رقم الهاتف. الكود صالح لمدة 10 دقائق."
    };

    if (AUTH_OTP_DEV_RETURN) out.devOtp = code;

    return res.json(out);

  } catch (e) {
    console.warn("auth register start failed:", e.message || e);
    return res.status(500).json({
      ok: false,
      error: "register_start_failed",
      message: "❌ تعذّر بدء إنشاء الحساب الآن. حاول مرة أخرى."
    });
  }
}

app.post("/api/auth/register/start", authRegisterStartHandlerBridgeSrv);

app.post("/api/auth/register", async (req, res) => {
  return res.status(409).json({
    ok: false,
    error: "otp_flow_required",
    message: "ℹ️ تم تفعيل التحقق برقم الهاتف. حدّث الصفحة ثم أعد المحاولة."
  });
});

app.post("/api/auth/register/verify", async (req, res) => {
  try {
    if (!admin.apps.length || !db) {
      return res.status(503).json({
        ok: false,
        error: "firebase_admin_disabled",
        message: "❌ خدمة إنشاء الحساب غير متاحة الآن. حاول مرة أخرى لاحقًا."
      });
    }

    const requestId = String(req.body?.requestId || "").trim();
    const otp = authDigitsBridgeSrv(req.body?.otp || req.body?.code || "");
    const password = String(req.body?.password || "");
    const confirmPassword = String(req.body?.confirmPassword || req.body?.passwordConfirm || "");

    if (!requestId || !otp || !password || !confirmPassword) {
      return res.status(400).json({
        ok: false,
        error: "otp_fields_required",
        message: "❌ أدخل كود التحقق وكلمة المرور وتأكيدها."
      });
    }

    const ref = db.collection("auth_register_otps").doc(requestId);
    const snap = await ref.get();

    if (!snap.exists) {
      return res.status(404).json({
        ok: false,
        error: "otp_not_found",
        message: "❌ كود التحقق غير صالح أو انتهت صلاحيته. اطلب كودًا جديدًا."
      });
    }

    const p = snap.data() || {};

    if (p.usedAt) {
      return res.status(409).json({
        ok: false,
        error: "otp_already_used",
        message: "ℹ️ تم استخدام كود التحقق بالفعل. اطلب كودًا جديدًا."
      });
    }

    const expiresAt = p.expiresAt?.toDate ? p.expiresAt.toDate() : null;
    if (!expiresAt || expiresAt.getTime() < Date.now()) {
      return res.status(410).json({
        ok: false,
        error: "otp_expired",
        message: "❌ انتهت صلاحية كود التحقق. اطلب كودًا جديدًا."
      });
    }

    const attempts = Number(p.attempts || 0);
    const maxAttempts = Number(p.maxAttempts || AUTH_OTP_MAX_ATTEMPTS);

    if (attempts >= maxAttempts) {
      return res.status(429).json({
        ok: false,
        error: "otp_attempts_exceeded",
        message: "🚫 انتهت محاولات التحقق. اطلب كودًا جديدًا."
      });
    }

    const otpHash = authOtpHashBridgeSrv(otp, p.otpSalt || "");

    if (otpHash !== p.otpHash) {
      await ref.set({
        attempts: attempts + 1,
        lastAttemptAt: admin.firestore.FieldValue.serverTimestamp()
      }, { merge: true });

      return res.status(400).json({
        ok: false,
        error: "otp_invalid",
        attemptsLeft: Math.max(0, maxAttempts - attempts - 1),
        message: `❌ كود التحقق غير صحيح. متبقي ${Math.max(0, maxAttempts - attempts - 1)} محاولة.`
      });
    }

    if (password !== confirmPassword) {
      return res.status(400).json({
        ok: false,
        error: "register_password_mismatch",
        message: "❌ تأكيد كلمة المرور لا يطابق كلمة المرور."
      });
    }

    const passwordIssue = authRegisterPasswordIssueBridgeSrv(password, {
      fullName: p.fullName,
      phoneKey: p.phoneKey
    });

    if (passwordIssue) {
      return res.status(400).json({
        ok: false,
        error: "register_password_weak",
        message: passwordIssue
      });
    }

    const passwordHash = authOtpHashBridgeSrv(password, p.passwordSalt || "");

    if (passwordHash !== p.passwordHash) {
      return res.status(400).json({
        ok: false,
        error: "register_password_changed",
        message: "❌ أدخل نفس كلمة المرور التي استخدمتها عند بدء إنشاء الحساب."
      });
    }

    const pseudoEmail = `${p.phoneKey}@murabbik.local`;

    try {
      await admin.auth().getUserByEmail(pseudoEmail);
      return res.status(409).json({
        ok: false,
        error: "phone_already_registered",
        message: "ℹ️ رقم الهاتف مسجّل بالفعل. سجّل الدخول أو استعد كلمة المرور."
      });
    } catch (e) {
      if (e?.code && e.code !== "auth/user-not-found") throw e;
    }

    const created = await admin.auth().createUser({
      email: pseudoEmail,
      password,
      displayName: p.fullName,
      disabled: false
    });

    const uid = String(created.uid || "").trim();

    const profile = {
      uid,
      ownerUid: uid,
      userId: uid,
      fullName: p.fullName,
      name: p.fullName,
      displayName: p.fullName,
      phone: p.phoneRaw,
      phoneKey: p.phoneKey,
      country: p.country,
      region: p.region,
      role: p.role,
      phoneVerified: true,
      phoneVerifiedAt: admin.firestore.FieldValue.serverTimestamp(),
      createdAt: admin.firestore.FieldValue.serverTimestamp(),
      updatedAt: admin.firestore.FieldValue.serverTimestamp(),
      source: "server:/api/auth/register/verify"
    };

    await db.collection("users").doc(uid).set(profile, { merge: true });

    await ref.set({
      usedAt: admin.firestore.FieldValue.serverTimestamp(),
      verifiedUid: uid
    }, { merge: true });

    const login = await authPasswordLoginBridgeSrv(pseudoEmail, password);
    const sessionCookie = await admin.auth().createSessionCookie(login.idToken, {
      expiresIn: AUTH_SESSION_EXPIRES_MS
    });

    authSetSessionCookieBridgeSrv(req, res, sessionCookie);

    return res.json({
      ok: true,
      message: "✅ تم إنشاء حسابك وتأكيد رقم الهاتف بنجاح.",
      uid,
      userId: uid,
      user: authPublicUserBridgeSrv(profile, uid, uid),
      redirectUrl: "add-animal.html"
    });

  } catch (e) {
    console.warn("auth register verify failed:", e.message || e);

    let message = "❌ تعذّر إتمام إنشاء الحساب الآن. حاول مرة أخرى.";
    let error = "register_verify_failed";
    let status = 500;

    if (e?.code === "auth/email-already-exists") {
      status = 409;
      error = "phone_already_registered";
      message = "ℹ️ رقم الهاتف مسجّل بالفعل. سجّل الدخول أو استعد كلمة المرور.";
    } else if (e?.code === "auth/invalid-password" || e?.code === "auth/weak-password") {
      status = 400;
      error = "register_password_invalid";
      message = "كلمة المرور يجب أن تكون ٨ أحرف أو أكثر وتحتوي على حرف ورقم.";
    }

    return res.status(status).json({
      ok: false,
      error,
      message
    });
  }
});
async function authPasswordResetSendOtpBridgeSrv(phoneRaw, code) {
  const webhook = String(process.env.MURABBIK_SMS_WEBHOOK_URL || "").trim();

  if (!webhook) {
    if (AUTH_OTP_DEV_RETURN) return { ok: true, dev: true };
    return {
      ok: false,
      error: "sms_provider_missing",
      message: "❌ تعذّر إرسال كود التحقق الآن. حاول مرة أخرى لاحقًا."
    };
  }

  const text = `كود استعادة كلمة المرور في مُرَبِّيك: ${code}. صالح لمدة 10 دقائق.`;

  try {
    const r = await fetch(webhook, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        to: phoneRaw,
        message: text,
        code,
        purpose: "password_reset"
      })
    });

    if (!r.ok) {
      return {
        ok: false,
        error: "sms_send_failed",
        message: "❌ تعذّر إرسال كود التحقق الآن. حاول مرة أخرى."
      };
    }

    return { ok: true };

  } catch (e) {
    console.warn("password reset otp send failed:", e.message || e);
    return {
      ok: false,
      error: "sms_send_failed",
      message: "❌ تعذّر إرسال كود التحقق الآن. حاول مرة أخرى."
    };
  }
}

app.post("/api/auth/password-reset/start", async (req, res) => {
  try {
    if (!admin.apps.length || !db) {
      return res.status(503).json({
        ok: false,
        error: "firebase_admin_disabled",
        message: "❌ خدمة استعادة كلمة المرور غير متاحة الآن. حاول مرة أخرى لاحقًا."
      });
    }

    const phoneRaw = authRegisterTextBridgeSrv(req.body?.phone || req.body?.phoneNumber || "");
    const phoneKey = authDigitsBridgeSrv(phoneRaw);

    if (!phoneKey) {
      return res.status(400).json({
        ok: false,
        error: "password_reset_phone_required",
       message: "❌ أدخل رقم الهاتف المسجّل في مُرَبِّيك."
      });
    }

    const pseudoEmail = `${phoneKey}@murabbik.local`;

    let userRecord = null;
    try {
      userRecord = await admin.auth().getUserByEmail(pseudoEmail);
    } catch (e) {
      if (e?.code === "auth/user-not-found") {
        return res.status(404).json({
          ok: false,
          error: "password_reset_user_not_found",
         message: "❌ رقم الهاتف غير مسجّل في مُرَبِّيك."
        });
      }
      throw e;
    }

    const uid = String(userRecord?.uid || "").trim();
    if (!uid) {
      return res.status(404).json({
        ok: false,
        error: "password_reset_user_not_found",
        message: "❌ رقم الهاتف غير مسجّل في مُرَبِّيك."
      });
    }

    const profile = await authReadUserProfileBridgeSrv(uid);

    const code = authOtpCodeBridgeSrv();
    const otpSalt = crypto.randomBytes(16).toString("hex");
    const requestId = crypto.randomBytes(18).toString("hex");

    const sent = await authPasswordResetSendOtpBridgeSrv(phoneRaw || phoneKey, code);

    if (!sent.ok) {
      return res.status(503).json({
        ok: false,
        error: sent.error || "otp_send_failed",
        message: sent.message || "❌ تعذّر إرسال كود التحقق الآن. حاول مرة أخرى."
      });
    }

    await db.collection("auth_password_reset_otps").doc(requestId).set({
      type: "password_reset",
      uid,
      phoneRaw: profile.phone || phoneRaw,
      phoneKey,
      fullName: profile.fullName || profile.name || profile.displayName || userRecord.displayName || "",

      otpHash: authOtpHashBridgeSrv(code, otpSalt),
      otpSalt,

      attempts: 0,
      maxAttempts: AUTH_OTP_MAX_ATTEMPTS,
      usedAt: null,
      expiresAt: admin.firestore.Timestamp.fromDate(new Date(Date.now() + AUTH_OTP_TTL_MS)),
      createdAt: admin.firestore.FieldValue.serverTimestamp(),
      source: "server:/api/auth/password-reset/start"
    }, { merge: false });

    const out = {
      ok: true,
      otpRequired: true,
      requestId,
      expiresInSeconds: Math.floor(AUTH_OTP_TTL_MS / 1000),
      message: "✅ تم إرسال كود التحقق إلى رقم الهاتف. الكود صالح لمدة 10 دقائق."
    };

    if (AUTH_OTP_DEV_RETURN) out.devOtp = code;

    return res.json(out);

  } catch (e) {
    console.warn("password reset start failed:", e.message || e);
    return res.status(500).json({
      ok: false,
      error: "password_reset_start_failed",
      message: "❌ تعذّر بدء استعادة كلمة المرور الآن. حاول مرة أخرى."
    });
  }
});

app.post("/api/auth/password-reset/verify", async (req, res) => {
  try {
    if (!admin.apps.length || !db) {
      return res.status(503).json({
        ok: false,
        error: "firebase_admin_disabled",
        message: "❌ خدمة استعادة كلمة المرور غير متاحة الآن. حاول مرة أخرى لاحقًا."
      });
    }

    const requestId = String(req.body?.requestId || "").trim();
    const otp = authDigitsBridgeSrv(req.body?.otp || req.body?.code || "");
    const password = String(req.body?.password || "");
    const confirmPassword = String(req.body?.confirmPassword || req.body?.passwordConfirm || "");

    if (!requestId || !otp || !password || !confirmPassword) {
      return res.status(400).json({
        ok: false,
        error: "password_reset_fields_required",
        message: "❌ أدخل كود التحقق وكلمة المرور الجديدة وتأكيدها."
      });
    }

    const ref = db.collection("auth_password_reset_otps").doc(requestId);
    const snap = await ref.get();

    if (!snap.exists) {
      return res.status(404).json({
        ok: false,
        error: "otp_not_found",
        message: "❌ كود التحقق غير صالح أو انتهت صلاحيته. اطلب كودًا جديدًا."
      });
    }

    const p = snap.data() || {};

    if (p.usedAt) {
      return res.status(409).json({
        ok: false,
        error: "otp_already_used",
        message: "ℹ️ تم استخدام كود التحقق بالفعل. اطلب كودًا جديدًا."
      });
    }

    const expiresAt = p.expiresAt?.toDate ? p.expiresAt.toDate() : null;
    if (!expiresAt || expiresAt.getTime() < Date.now()) {
      return res.status(410).json({
        ok: false,
        error: "otp_expired",
        message: "❌ انتهت صلاحية كود التحقق. اطلب كودًا جديدًا."
      });
    }

    const attempts = Number(p.attempts || 0);
    const maxAttempts = Number(p.maxAttempts || AUTH_OTP_MAX_ATTEMPTS);

    if (attempts >= maxAttempts) {
      return res.status(429).json({
        ok: false,
        error: "otp_attempts_exceeded",
        message: "🚫 انتهت محاولات التحقق. اطلب كودًا جديدًا."
      });
    }

    const otpHash = authOtpHashBridgeSrv(otp, p.otpSalt || "");

    if (otpHash !== p.otpHash) {
      await ref.set({
        attempts: attempts + 1,
        lastAttemptAt: admin.firestore.FieldValue.serverTimestamp()
      }, { merge: true });

      return res.status(400).json({
        ok: false,
        error: "otp_invalid",
        attemptsLeft: Math.max(0, maxAttempts - attempts - 1),
        message: `❌ كود التحقق غير صحيح. متبقي ${Math.max(0, maxAttempts - attempts - 1)} محاولة.`
      });
    }

    if (password !== confirmPassword) {
      return res.status(400).json({
        ok: false,
        error: "password_reset_mismatch",
        message: "❌ تأكيد كلمة المرور لا يطابق كلمة المرور الجديدة."
      });
    }

    const passwordIssue = authRegisterPasswordIssueBridgeSrv(password, {
      fullName: p.fullName,
      phoneKey: p.phoneKey
    });

    if (passwordIssue) {
      return res.status(400).json({
        ok: false,
        error: "password_reset_weak_password",
        message: passwordIssue
      });
    }

    const uid = String(p.uid || "").trim();
    if (!uid) {
      return res.status(400).json({
        ok: false,
        error: "password_reset_uid_missing",
        message: "❌ تعذّر إكمال طلب استعادة كلمة المرور. ابدأ الطلب من جديد."
      });
    }

    await admin.auth().updateUser(uid, { password });
    await admin.auth().revokeRefreshTokens(uid);

    await ref.set({
      usedAt: admin.firestore.FieldValue.serverTimestamp(),
      resetUid: uid
    }, { merge: true });

    authClearSessionCookieBridgeSrv(req, res);

    return res.json({
      ok: true,
      message: "✅ تم تغيير كلمة المرور بنجاح. سجّل الدخول بكلمة المرور الجديدة.",
      redirectUrl: "login.html"
    });

  } catch (e) {
    console.warn("password reset verify failed:", e.message || e);
    return res.status(500).json({
      ok: false,
      error: "password_reset_verify_failed",
      message: "❌ تعذّر تغيير كلمة المرور الآن. حاول مرة أخرى."
    });
  }
});
app.post("/api/auth/login", async (req, res) => {
  try {
    if (!admin.apps.length) {
      return res.status(503).json({
        ok: false,
        error: "firebase_admin_disabled",
        message: "❌ خدمة تسجيل الدخول غير متاحة الآن. حاول مرة أخرى لاحقًا."
      });
    }

    const phoneKey = authDigitsBridgeSrv(req.body?.phone || req.body?.phoneNumber || "");
    const password = String(req.body?.password || "");

    if (!phoneKey || !password) {
      return res.status(400).json({
        ok: false,
        error: "login_fields_required",
        message: "❌ أدخل رقم الهاتف وكلمة المرور."
      });
    }

    const pseudoEmail = `${phoneKey}@murabbik.local`;

    const login = await authPasswordLoginBridgeSrv(pseudoEmail, password);
    const decoded = await admin.auth().verifyIdToken(login.idToken);
    const uid = String(decoded.uid || login.localId || "").trim();

    if (!uid) {
      return res.status(401).json({
        ok: false,
        error: "login_failed",
        message: "❌ رقم الهاتف أو كلمة المرور غير صحيحة."
      });
    }

    const profile = await authReadUserProfileBridgeSrv(uid);

    // مهم جدًا:
    // نرجّع نفس userId القديم، ونحفظ معه جلسة سيرفر.
    const userId = tenantKey(profile.userId || profile.tenantId || profile.ownerUid || uid);

    const sessionCookie = await admin.auth().createSessionCookie(login.idToken, {
      expiresIn: AUTH_SESSION_EXPIRES_MS
    });

    authSetSessionCookieBridgeSrv(req, res, sessionCookie);

    return res.json({
      ok: true,
      message: "✅ تم تسجيل الدخول بنجاح.",
      uid,
      userId,
      user: authPublicUserBridgeSrv(profile, uid, userId),
      redirectUrl: "dashboard.html"
    });

  } catch (e) {
    console.warn("auth bridge login failed:", e.message || e);

    return res.status(401).json({
      ok: false,
      error: "login_failed",
      message: e.publicMessage || "❌ رقم الهاتف أو كلمة المرور غير صحيحة."
    });
  }
});

