//                  WEATHER / THI CENTRAL SOURCE
// ============================================================
const WEATHER_DEFAULT_LAT = Number(process.env.WEATHER_LAT || 30.0444);
const WEATHER_DEFAULT_LON = Number(process.env.WEATHER_LON || 31.2357);
const WEATHER_CACHE_MS = 5 * 60 * 1000;
function farmLocationNumberSrv(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function farmLocationValidSrv(lat, lon) {
  const a = farmLocationNumberSrv(lat);
  const b = farmLocationNumberSrv(lon);

  return (
    a !== null &&
    b !== null &&
    a >= -90 &&
    a <= 90 &&
    b >= -180 &&
    b <= 180
  );
}

function farmLocationAccuracySrv(v) {
  const n = Number(v);
  if (!Number.isFinite(n) || n < 0) return null;
  return Math.round(n);
}
let weatherThiCache = {
  at: 0,
  data: null
};
const weatherThiFarmCache = new Map();
function calcTHI(tempC, humidityPct) {
  const t = Number(tempC);
  const h = Number(humidityPct);

  if (!Number.isFinite(t) || !Number.isFinite(h)) return null;

  const tf = (t * 9 / 5) + 32;
  return Math.round(tf - ((0.55 - (0.0055 * h)) * (tf - 58)));
}

function classifyTHI(thi) {
  const n = Number(thi);

  if (!Number.isFinite(n)) {
    return {
      level: 'unknown',
      label: 'غير متاح',
      severity: 0
    };
  }

  if (n < 68) {
    return {
      level: 'comfort',
      label: 'راحة',
      severity: 0
    };
  }

  if (n < 72) {
    return {
      level: 'mild',
      label: 'إجهاد خفيف',
      severity: 1
    };
  }

  if (n < 78) {
    return {
      level: 'moderate',
      label: 'إجهاد متوسط',
      severity: 2
    };
  }

  return {
    level: 'high',
    label: 'إجهاد عالي',
    severity: 3
  };
}
