function belongs(rec, tenant){
  const t = rec && rec.userId ? rec.userId : '';
  return tenantKey(t) === tenantKey(tenant);
}

async function requireUserId(req, res, next){
  try {
    const session = await authSessionFromRequestBridgeSrv(req);

    if (!session?.userId) {
      return res.status(401).json({
        ok: false,
        error: 'auth_required',
        message: '❌ يلزم تسجيل الدخول أولًا.'
      });
    }

    req.authSession = session;
    req.userId = session.userId;
    return next();

  } catch (e) {
    console.error('requireUserId failed:', e.message || e);

    return res.status(401).json({
      ok: false,
      error: 'auth_required',
      message: '❌ يلزم تسجيل الدخول أولًا.'
    });
  }
}
