app.post("/api/add-animal/import-preview", requireUserId, async (req, res) => {
  try {
    if (!db) {
      return res.status(503).json({
        ok: false,
        error: "firestore_disabled",
        message: "❌ تعذّرت معاينة ملف الحيوانات الآن. حاول مرة أخرى.",
        rows: []
      });
    }

    const uid = req.userId;
    const body = req.body || {};
    const importKind = addAnimalImportKindSrv(body);
    const rows = addAnimalImportRowsFromBodySrv(body);

    if (!rows.length) {
      return res.status(400).json({
        ok: false,
        error: "import_rows_required",
        message: "❌ لم أجد بيانات قابلة للقراءة في الملف. راجع الملف وحاول مرة أخرى.",
        importKind,
        rows: []
      });
    }

    const seenInFile = new Set();
    const previewRows = [];

    let readyCount = 0;
    let rejectedCount = 0;

    for (let i = 0; i < rows.length; i++) {
      const rowNumber = i + 1;
      const row = rows[i] || {};
      const fd = addAnimalImportFdSrv(row, importKind);
      const numberStr = addAnimalDigitsSrv(fd.animalNumber || fd.number || fd.calfNumber);

      const item = {
        row: rowNumber,
        animalNumber: numberStr,
        importKind,
        status: "ready",
        ok: true,
        reason: null,
        message: "جاهز للاستيراد.",
        data: fd
      };

      if (!numberStr) {
        item.status = "rejected";
        item.ok = false;
        item.reason = "animal_number_required";
        item.message = `السطر ${rowNumber}: أدخل رقم الحيوان.`;
        previewRows.push(item);
        rejectedCount++;
        continue;
      }

      if (seenInFile.has(numberStr)) {
        item.status = "rejected";
        item.ok = false;
        item.reason = "duplicate_in_file";
        item.message = `السطر ${rowNumber}: رقم الحيوان ${numberStr} مكرر داخل الملف.`;
        previewRows.push(item);
        rejectedCount++;
        continue;
      }

      seenInFile.add(numberStr);

      const fieldErrors = addAnimalBasicFieldsDecisionSrv(fd);

      if (Object.keys(fieldErrors).length) {
        item.status = "rejected";
        item.ok = false;
        item.reason = "fields_invalid";
        item.message = `السطر ${rowNumber}: راجع الحقول المطلوبة لهذا الحيوان.`;
        item.fieldErrors = fieldErrors;
        previewRows.push(item);
        rejectedCount++;
        continue;
      }

      const guardMessage = addAnimalDecisionSrv(fd);

      if (guardMessage) {
        item.status = "rejected";
        item.ok = false;
        item.reason = "decision_failed";
        item.message = `السطر ${rowNumber}: ${guardMessage}`;
        previewRows.push(item);
        rejectedCount++;
        continue;
      }

      const duplicate = await addAnimalDuplicateCheckSrv(uid, numberStr);

      if (!duplicate.ok) {
        item.status = "rejected";
        item.ok = false;
        item.reason = duplicate.duplicate ? "duplicate_animal_number" : "duplicate_check_failed";
        item.collection = duplicate.collection || null;
        item.message = `السطر ${rowNumber}: ${duplicate.message}`;
        previewRows.push(item);
        rejectedCount++;
        continue;
      }

      previewRows.push(item);
      readyCount++;
    }

    return res.json({
      ok: true,
      importKind,
      totalCount: rows.length,
      readyCount,
      rejectedCount,
      partial: readyCount > 0 && rejectedCount > 0,
     message: readyCount > 0
  ? (
      rejectedCount > 0
        ? `راجعت ${rows.length} سجلًا: ${readyCount} جاهز للاستيراد، و${rejectedCount} يحتاج مراجعة.`
        : `✅ تمت معاينة ${rows.length} سجلًا، وكلها جاهزة للاستيراد.`
    )
  : `❌ تمت معاينة ${rows.length} سجلًا، ولا يوجد أي سجل جاهز للاستيراد.`,
      rows: previewRows
    });

  } catch (e) {
    console.error("add-animal-import-preview failed", e);

    return res.status(500).json({
      ok: false,
      error: "add_animal_import_preview_failed",
     message: "❌ تعذّرت معاينة ملف الحيوانات الآن. حاول مرة أخرى.",
      rows: []
    });
  }
});
app.post("/api/add-animal/import", requireUserId, async (req, res) => {
  try {
    if (!db) {
      return res.status(503).json({
        ok: false,
        error: "firestore_disabled",
        message: "❌ تعذّر استيراد الحيوانات الآن. حاول مرة أخرى.",
        saved: [],
        rejected: []
      });
    }

    const uid = req.userId;
    const body = req.body || {};
    const importKind = addAnimalImportKindSrv(body);
   const rows = addAnimalImportRowsFromBodySrv(body);

    if (!rows.length) {
      return res.status(400).json({
        ok: false,
        error: "import_rows_required",
        message: "❌ لم أجد بيانات صالحة للاستيراد في الملف.",
        saved: [],
        rejected: []
      });
    }

    const saved = [];
    const rejected = [];
    const seenInFile = new Set();

    let batch = db.batch();
    let ops = 0;

    for (let i = 0; i < rows.length; i++) {
      const rowNumber = i + 1;
      const row = rows[i] || {};
      const fd = addAnimalImportFdSrv(row, importKind);
      const numberStr = addAnimalDigitsSrv(fd.animalNumber || fd.number || fd.calfNumber);

      if (!numberStr) {
        rejected.push({
          row: rowNumber,
          animalNumber: "",
          reason: "animal_number_required",
          message: `السطر ${rowNumber}: أدخل رقم الحيوان.`
        });
        continue;
      }

      if (seenInFile.has(numberStr)) {
        rejected.push({
          row: rowNumber,
          animalNumber: numberStr,
          reason: "duplicate_in_file",
          message: `السطر ${rowNumber}: رقم الحيوان ${numberStr} مكرر داخل الملف.`
        });
        continue;
      }

      seenInFile.add(numberStr);

      const fieldErrors = addAnimalBasicFieldsDecisionSrv(fd);

      if (Object.keys(fieldErrors).length) {
        rejected.push({
          row: rowNumber,
          animalNumber: numberStr,
          reason: "fields_invalid",
          message: `السطر ${rowNumber}: راجع الحقول المطلوبة لهذا الحيوان.`,
          fieldErrors
        });
        continue;
      }

      const guardMessage = addAnimalDecisionSrv(fd);

      if (guardMessage) {
        rejected.push({
          row: rowNumber,
          animalNumber: numberStr,
          reason: "decision_failed",
          message: `السطر ${rowNumber}: ${guardMessage}`
        });
        continue;
      }

      const duplicate = await addAnimalDuplicateCheckSrv(uid, numberStr);

      if (!duplicate.ok) {
        rejected.push({
          row: rowNumber,
          animalNumber: numberStr,
          reason: duplicate.duplicate ? "duplicate_animal_number" : "duplicate_check_failed",
          collection: duplicate.collection || null,
          message: `السطر ${rowNumber}: ${duplicate.message}`
        });
        continue;
      }

      const { collectionName, payload } = addAnimalBuildSinglePayloadSrv(uid, fd);
      const ref = db.collection(collectionName).doc();

      batch.set(ref, payload);
      ops++;

      saved.push({
        row: rowNumber,
        animalNumber: numberStr,
        animalId: ref.id,
        collection: collectionName,
        message: `تم استيراد الحيوان رقم ${numberStr} بنجاح.`
      });

      if (ops >= 400) {
        await batch.commit();
        batch = db.batch();
        ops = 0;
      }
    }

    if (ops > 0) {
      await batch.commit();
    }

    if (saved.length && typeof scheduleGroupsRebuildSrv === "function") {
      scheduleGroupsRebuildSrv(uid, "add_animal_import");
    }

    return res.status(saved.length ? 200 : 400).json({
      ok: saved.length > 0,
      partial: saved.length > 0 && rejected.length > 0,
 message: saved.length
  ? (
      rejected.length
        ? `✅ تم استيراد ${saved.length} حيوان، ولم يتم استيراد ${rejected.length} سجل يحتاج مراجعة.`
        : `✅ تم استيراد ${saved.length} حيوان بنجاح.`
    )
  : "❌ لم يتم استيراد أي حيوان. راجع أسباب الرفض الظاهرة.",
      importKind,
      savedCount: saved.length,
      rejectedCount: rejected.length,
      saved,
      rejected
    });

  } catch (e) {
    console.error("add-animal-import failed", e);

    return res.status(500).json({
      ok: false,
      error: "add_animal_import_failed",
     message: "❌ تعذّر استيراد الحيوانات الآن. حاول مرة أخرى.",
      saved: [],
      rejected: []
    });
  }
});
