//                 API: HOOF TRIMMING SAVE
//                 حفظ تقليم الحوافر فردي/جماعي من السيرفر فقط
// ============================================================

async function eventsPageFindAnimalByNumberSrv(uid, number) {
  const n = eventsPageParseNumbersSrv(number)[0] || "";

  if (!db || !n) return null;

  const snap = await db.collection("animals")
    .where("userId", "==", uid)
    .where("number", "==", n)
    .limit(1)
    .get();

  if (snap.empty) return null;

  const doc = snap.docs[0];

  return {
    id: doc.id,
    data: doc.data() || {}
  };
}

async function existsHoofTrimmingSameDaySrv(uid, animalNumber, eventDate) {
  if (!db) return false;

  const n = eventsPageParseNumbersSrv(animalNumber)[0] || "";
  const d = eventsPageDateSrv(eventDate);

  const snap = await db.collection("events")
    .where("userId", "==", uid)
    .where("animalNumber", "==", n)
    .where("eventTypeNorm", "==", "hoof_trimming")
    .where("eventDate", "==", d)
    .limit(1)
    .get();

  return !snap.empty;
}
function eventsPageStableDocIdSrv(...parts) {
  return parts
    .map(v => encodeURIComponent(String(v || "").trim()))
    .filter(Boolean)
    .join("__");
}
app.post("/api/hoof-trimming/save", requireUserId, async (req, res) => {
  try {
    if (!db) {
      return res.status(503).json({
        ok: false,
        error: "firestore_disabled",
        message: "❌ تعذّر تسجيل تقليم الحوافر الآن. حاول مرة أخرى.",
        saved: [],
        failed: [],
        rejected: []
      });
    }

    const uid = req.userId;
    const body = req.body || {};

    const numbers = eventsPageParseNumbersSrv(
      body.animalNumbers ||
      body.numbers ||
      body.animalNumber ||
      body.number ||
      ""
    );

    const eventDate = eventsPageDateSrv(body.eventDate || body.date);
    const notes = String(body.notes || "").trim() || null;

    if (!numbers.length) {
      return res.status(400).json({
        ok: false,
        error: "animal_number_required",
        message: "أدخل رقم الحيوان أو اختر مجموعة لتسجيل تقليم الحوافر.",
        saved: [],
        failed: [],
        rejected: []
      });
    }

    const saved = [];
    const failed = [];

    for (const animalNumber of numbers) {
      const animal = await eventsPageFindAnimalByNumberSrv(uid, animalNumber);

      if (!animal) {
        failed.push({
          animalNumber,
          reason: "animal_not_found",
          message: `❌ لم أجد الحيوان رقم ${animalNumber} في القطيع المسجل بحسابك.`,
        });
        continue;
      }

      const payload = {
        userId: uid,

        animalNumber,
        animalId: animal.id,

        eventDate,
        date: eventDate,

        eventType: "تقليم الحوافر",
        eventTypeNorm: "hoof_trimming",
        type: "تقليم الحوافر",

        notes,

        source: "server:/api/hoof-trimming/save",
        createdAt: admin.firestore.FieldValue.serverTimestamp()
      };

      const idempotencyKey = `${uid}|${animalNumber}|hoof_trimming|${eventDate}`;
      const eventDocId = eventsPageStableDocIdSrv(uid, "hoof_trimming", animalNumber, eventDate);

      const eventRef = db.collection("events").doc(eventDocId);
      const animalRef = db.collection("animals").doc(animal.id);

      payload.idempotencyKey = idempotencyKey;

      let created = false;

      await db.runTransaction(async (tx) => {
        const existing = await tx.get(eventRef);

        if (existing.exists) {
          return;
        }

        tx.set(eventRef, payload);

        tx.set(animalRef, {
          lastHoofTrimmingDate: eventDate,
          updatedAt: admin.firestore.FieldValue.serverTimestamp()
        }, { merge: true });

        created = true;
      });

      saved.push({
        animalNumber,
        animalId: animal.id,
        eventId: eventRef.id,
        alreadyExists: !created,
        message: created
          ? `✅ سجلت تقليم الحوافر للحيوان رقم ${animalNumber} بنجاح.`
         : `ℹ️ تقليم الحوافر مسجل بالفعل للحيوان رقم ${animalNumber} في هذا التاريخ.`
        
      });
    }

    const redirectUrl = numbers.length === 1 && saved.length === 1
      ? `/event-list.html?number=${encodeURIComponent(saved[0].animalNumber)}&eventDate=${encodeURIComponent(eventDate)}`
      : null;

    return res.json({
      ok: saved.length > 0,
      partial: false,
      message: saved.length
  ? `✅ اكتمل تسجيل تقليم الحوافر لعدد ${saved.length} حيوان.`
  : "❌ لم يتم تسجيل تقليم الحوافر لأي حيوان.",
      saved,
      failed,
      rejected: [],
      eventDate,
      redirectUrl
    });

  } catch (e) {
    console.error("hoof-trimming-save failed", e);

    return res.status(500).json({
      ok: false,
      error: "hoof_trimming_save_failed",
     message: "❌ تعذّر تسجيل تقليم الحوافر الآن. حاول مرة أخرى.",
      saved: [],
      failed: [],
      rejected: []
    });
  }
});
