function eventsPagePickSrv(obj, keys, def = "") {
  for (const k of keys) {
    if (!k.includes(".")) {
      if (obj && obj[k] != null && obj[k] !== "") return obj[k];
      continue;
    }

    const parts = k.split(".");
    let cur = obj;

    for (const p of parts) {
      cur = cur?.[p];
    }

    if (cur != null && cur !== "") return cur;
  }

  return def;
}

