function eventsPageEventAnimalNumberSrv(ev = {}) {
  return String(eventsPagePickSrv(ev, [
    "animalNumber",
    "number",
    "animalId",
    "animalID",
    "calfNumber"
  ], "")).trim();
}
function eventsPageListDateSrv(ev = {}) {
  const raw = eventsPagePickSrv(ev, [
    "eventDate",
    "date",
    "dt",
    "createdAt",
    "timestamp"
  ], "");

  const d = toDate(raw);
  if (d && !Number.isNaN(d.getTime())) {
    return toYYYYMMDD(d);
  }

  const s = String(raw || "").trim().slice(0, 10);
  return /^\d{4}-\d{2}-\d{2}$/.test(s) ? s : "";
}

function eventsPageListSortMsSrv(ev = {}) {
  const raw = eventsPagePickSrv(ev, [
    "eventDate",
    "date",
    "dt",
    "createdAt",
    "timestamp"
  ], "");

  const d = toDate(raw);
  return d && !Number.isNaN(d.getTime()) ? d.getTime() : 0;
}

