// ============================================================
//                 CALVING RULES — moved from frontend rules
//                 نقل كما هو من form-rules.js
// ============================================================

const CALVING_THRESHOLDS_SRV = {
  "أبقار": { minGestationDays: 255 },
  "جاموس": { minGestationDays: 285 },
};

function calvingToDateSrv(v) {
  return (v instanceof Date ? v : (v ? new Date(v) : null));
}

function calvingDaysBetweenSrv(a, b) {
  const d1 = calvingToDateSrv(a), d2 = calvingToDateSrv(b);
  if (!d1 || !d2) return NaN;
  d1.setHours(0, 0, 0, 0);
  d2.setHours(0, 0, 0, 0);
  return Math.round((d2 - d1) / 86400000);
}

function calvingIsDateSrv(v) {
  return !Number.isNaN(calvingToDateSrv(v)?.getTime());
}

function calvingStripArSrv(s) {
  return String(s || "")
    .trim()
    .replace(/\s+/g, "")
    .replace(/[ًٌٍَُِّْ]/g, "");
}

function calvingNormalizeSpeciesSrv(spRaw) {
  let sp = String(spRaw || "").trim();
  if (/cow|بقر/i.test(sp)) return "أبقار";
  if (/buffalo|جاموس/i.test(sp)) return "جاموس";
  return sp;
}

function calvingNormDigitsOnlySrv(s) {
  const map = {
    '٠':'0','١':'1','٢':'2','٣':'3','٤':'4','٥':'5','٦':'6','٧':'7','٨':'8','٩':'9',
    '۰':'0','۱':'1','۲':'2','۳':'3','۴':'4','۵':'5','۶':'6','۷':'7','۸':'8','۹':'9'
  };
  return String(s || '')
    .trim()
    .replace(/[^\d٠-٩۰-۹]/g, '')
    .replace(/[٠-٩۰-۹]/g, d => map[d]);
}

function calvingIsOddSrv(n) {
  return Number(n) % 2 === 1;
}

function calvingIsEvenSrv(n) {
  return Number(n) % 2 === 0;
}

function calvingDecisionSrv(fd) {
  const doc = fd.documentData;
  const animalNumber = calvingNormDigitsOnlySrv(fd.animalNumber || "");
  const animalText = animalNumber ? `الحيوان رقم ${animalNumber}` : "الحيوان";

  if (!doc) {
    return `❌ لم أجد ${animalText}. راجع الرقم ثم حاول مرة أخرى.`;
  }

  const st = String(doc.status ?? "").trim().toLowerCase();
  if (st === "inactive" || st === "archived") {
    return `❌ ${animalText} خارج القطيع، لذلك لا يمكن تسجيل ولادة له.`;
  }

  let sp = String(fd.species || doc.species || doc.animalTypeAr || doc.animalType || "").trim();
  if (/cow|بقر/i.test(sp)) sp = "أبقار";
  if (/buffalo|جاموس/i.test(sp)) sp = "جاموس";

  const th = CALVING_THRESHOLDS_SRV[sp]?.minGestationDays;
  if (!th) {
    return `❌ لا أستطيع تحديد نوع ${animalText}. راجع بيانات الحيوان أولًا.`;
  }

  const rsRaw = String(doc.reproductiveStatus || doc.reproStatus || "").trim();

  const rsNorm = rsRaw
    .replace(/\s+/g, "")
    .replace(/[ًٌٍَُِّْ]/g, "")
    .replace(/[أإآ]/g, "ا")
    .replace(/ة/g, "ه")
    .replace(/ى/g, "ي");

  const shownStatus = rsRaw ? rsRaw : "غير معروفة";

  if (!rsNorm.includes("عشار")) {
    return `❌ ${animalText} حالته التناسلية «${shownStatus}». تسجيل الولادة متاح للحيوانات العِشار فقط.`;
  }

  const lf = String(
    fd.lastInseminationDate ||
    doc.lastInseminationDate ||
    doc.lastAI ||
    doc.lastInsemination ||
    doc.lastServiceDate ||
    ""
  ).trim();

  if (!calvingIsDateSrv(lf)) {
    return `❌ لا يوجد لـ${animalText} تاريخ مسجل لآخر تلقيح مُخصِّب، لذلك لا أستطيع حساب عمر الحمل. راجع بيانات التلقيح أولًا.`;
  }

  if (!calvingIsDateSrv(fd.eventDate)) {
    return "❌ أدخل تاريخ ولادة صحيحًا.";
  }

  const gDays = calvingDaysBetweenSrv(lf, fd.eventDate);
  if (Number.isNaN(gDays)) {
    return "❌ لم أستطع حساب عمر الحمل. راجع تاريخ آخر تلقيح وتاريخ الولادة.";
  }

  if (gDays < th) {
    return `OFFER_ABORT|التاريخ مبكر للولادة — عمر الحمل ${gDays} يوم فقط.`;
  }

  return null;
}
function calvingRequiredFieldsSrv(fd) {
  const kind = String(fd.calvingKind || "").trim();
 if (!kind) return "❌ اختر نوع الولادة.";

  const lf = String(fd.lastInseminationDate || "").trim();
  if (!calvingIsDateSrv(lf)) {
   return "❌ تعذّر تأكيد تاريخ آخر تلقيح مُخصِّب. أعد التحقق من الحيوان.";
  }

  if (kind === "نافقة") return null;

  const count = Number(String(fd.calfCount || "").trim());
  if (!(count === 1 || count === 2 || count === 3)) {
    return { field: "calfCount", msg: "❌ اختر عدد المواليد: 1 أو 2 أو 3." };
  }

  if (!String(fd.calf1Sex || "").trim()) {
  return { field: "calf1Sex", msg: "❌ اختر جنس المولود الأول." };
  }

  if (!String(fd.calfId || "").trim()) {
    return { field: "calfId", msg: "❌ أدخل رقم المولود الأول." };
  }

  if (!String(fd.calf1Fate || "").trim()) {
   return { field: "calf1Fate", msg: "❌ اختر مصير المولود الأول." };
  }

  if (count >= 2) {
    if (!String(fd.calf2Sex || "").trim()) {
    return { field: "calf2Sex", msg: "❌ اختر جنس المولود الثاني." };
    }

    if (!String(fd.calf2Id || "").trim()) {
     return { field: "calf2Id", msg: "❌ أدخل رقم المولود الثاني." };
    }

    if (!String(fd.calf2Fate || "").trim()) {
      return { field: "calf2Fate", msg: "❌ اختر مصير المولود الثاني." };
    }
  }

  if (count >= 3) {
    if (!String(fd.calf3Sex || "").trim()) {
      return { field: "calf3Sex", msg: "❌ اختر جنس المولود الثالث." };
    }

    if (!String(fd.calf3Id || "").trim()) {
   return { field: "calf3Id", msg: "❌ أدخل رقم المولود الثالث." };
    }

    if (!String(fd.calf3Fate || "").trim()) {
      return { field: "calf3Fate", msg: "❌ اختر مصير المولود الثالث." };
    }
  }

  const nums = [
    calvingNormDigitsOnlySrv(fd.calfId),
    count >= 2 ? calvingNormDigitsOnlySrv(fd.calf2Id) : "",
    count >= 3 ? calvingNormDigitsOnlySrv(fd.calf3Id) : ""
  ].filter(Boolean);

  if (nums.length !== count) {
   return { field: "calfId", msg: "❌ أحد أرقام المواليد غير صحيح. راجع الأرقام." };
  }

  const s = new Set(nums);
  if (s.size !== nums.length) {
   return { field: "calfId", msg: "❌ لا يمكن استخدام نفس الرقم لأكثر من مولود. أدخل رقمًا مختلفًا لكل مولود." };
  }

  return null;
}
// ============================================================
//                 CALVING SIGNALS — moved from forms-init.js
//                 نقل كما هو من fetchCalvingSignalsFromEvents
// ============================================================

async function fetchCalvingSignalsFromEventsSrv(uid, number) {
  const num = String(calvingNormDigitsOnlySrv(number || "")).trim();

  if (!uid || !num) {
    return {
      reproStatusFromEvents: "",
      lastBoundary: "",
      lastBoundaryType: "",
      lastInseminationDateFromEvents: ""
    };
  }

  const snap = await db.collection("events")
    .where("userId", "==", uid)
    .where("animalNumber", "==", num)
    .limit(60)
    .get();

  const arr = snap.docs
    .map((d) => d.data() || {})
    .filter((ev) => ev.eventDate)
    .sort((a, b) => String(b.eventDate).localeCompare(String(a.eventDate)));

  let reproStatusFromEvents = "";
  let lastBoundary = "";
  let lastBoundaryType = "";
  let lastInseminationDateFromEvents = "";

  for (const ev of arr) {
    const type = String(ev.eventType || ev.type || "").trim();
    const res  = String(ev.result || ev.status || "").trim();
    const dt   = String(ev.eventDate || "").trim();

    if ((type === "ولادة" || type === "إجهاض") && !lastBoundary) {
      lastBoundary = dt;
      lastBoundaryType = type;
      if (!reproStatusFromEvents) reproStatusFromEvents = "مفتوحة";
      continue;
    }

    // ✅ آخر تلقيح من الأحداث (حتى لو وثيقة الحيوان لم تتحدث بعد)
    if ((type === "تلقيح" || type === "insemination") && !lastInseminationDateFromEvents) {
      lastInseminationDateFromEvents = dt;
    }

    if (type === "تشخيص حمل") {
      const r = calvingStripArSrv(res);
      if (!reproStatusFromEvents) {
        if (r.includes("عشار")) reproStatusFromEvents = "عشار";
        if (r.includes("فارغه") || r.includes("فارغة")) reproStatusFromEvents = "مفتوحة";
      }
    }

    if (reproStatusFromEvents && lastBoundary) break;
  }

  return {
    reproStatusFromEvents,
    lastBoundary,
    lastBoundaryType,
    lastInseminationDateFromEvents
  };
}
// ============================================================
//                 INSEMINATION VALIDATION + DECISION
//                 نقل فاليديشن وقرار التلقيح كما هو للسيرفر
// ============================================================

function inseminationReqSrv(v) {
  return !(v === undefined || v === null || String(v).trim() === "");
}

function inseminationIsDateSrv(v) {
  const d = v instanceof Date ? v : (v ? new Date(v) : null);
  return !Number.isNaN(d?.getTime());
}

function inseminationDaysBetweenSrv(a, b) {
  const d1 = a instanceof Date ? a : (a ? new Date(a) : null);
  const d2 = b instanceof Date ? b : (b ? new Date(b) : null);
  if (!d1 || !d2) return NaN;
  d1.setHours(0, 0, 0, 0);
  d2.setHours(0, 0, 0, 0);
  return Math.round((d2 - d1) / 86400000);
}

function validateInseminationFieldsSrv(fd = {}) {
  const fieldErrors = {};

  if (!inseminationReqSrv(fd.animalNumber)) {
   fieldErrors.animalNumber = "أدخل رقم الحيوان.";
  }

  if (!inseminationReqSrv(fd.eventDate) || !inseminationIsDateSrv(fd.eventDate)) {
   fieldErrors.eventDate = "أدخل تاريخ تلقيح صحيحًا.";
  }

  if (!fd.documentData) {
   fieldErrors.documentData = "لم أجد بيانات الحيوان. راجع الرقم.";
  }

  if (!inseminationReqSrv(fd.species)) {
    fieldErrors.species = "لم أتعرف على نوع الحيوان. راجع بياناته.";
  }

  if (!inseminationReqSrv(fd.inseminationMethod)) {
    fieldErrors.inseminationMethod = "اختر طريقة التلقيح.";
  }

  if (!inseminationReqSrv(fd.semenCode)) {
    fieldErrors.semenCode = "أدخل كود السائل المنوي.";
  }

  if (!inseminationReqSrv(fd.inseminator)) {
    fieldErrors.inseminator = "أدخل اسم الملقّح.";
  }

  if (!inseminationReqSrv(fd.inseminationTime)) {
    fieldErrors.inseminationTime = "اختر وقت التلقيح.";
  }

  if (!inseminationReqSrv(fd.heatStatus)) {
   fieldErrors.heatStatus = "اختر حالة الشياع.";
  }

  return fieldErrors;
}
function inseminationBoolSrv(v) {
  const s = String(v ?? "").trim().toLowerCase();

  return (
    v === true ||
    s === "true" ||
    s === "1" ||
    s === "yes" ||
    s === "y" ||
    s === "نعم" ||
    s === "مؤكد" ||
    s === "تم" ||
    s === "confirmed"
  );
}

function inseminationIsPregnantStatusSrv(v) {
  const s = calvingStripArSrv(String(v || "").trim());
  return s.includes("عشار") || s.includes("حامل");
}

function inseminationConfirmEmbryonicLossSrv(fd = {}) {
  return inseminationBoolSrv(
    fd.confirmEmbryonicLoss ||
    fd.embryonicLossConfirmed ||
    fd.confirmPregnancyLoss ||
    fd.pregnancyLossConfirmed ||
    fd.confirmNegativePregnancyCheck ||
    fd.forceInseminationAfterPregnancyCheck
  );
}

function inseminationEventTypeIsAISrv(ev = {}) {
  const t = String(
    ev.eventTypeNorm ||
    ev.eventType ||
    ev.type ||
    ev.name ||
    ""
  ).trim().toLowerCase();

  return (
    t === "insemination" ||
    t.includes("insemination") ||
    t.includes("تلقيح")
  );
}

async function countInseminationsSameDaySrv(uid, animalNumber, eventDate) {
  const num = calvingNormDigitsOnlySrv(animalNumber || "");
  const dt = String(eventDate || "").trim().slice(0, 10);

  if (!db || !uid || !num || !calvingIsDateSrv(dt)) return 0;

  const vals = typeof findAnimalNumberMatches === "function"
    ? findAnimalNumberMatches(num)
    : [num, Number(num)].filter(v => v !== "" && v !== null && v !== undefined);

  const seen = new Set();

  for (const field of ["animalNumber", "number"]) {
    for (const v of vals) {
      try {
        const snap = await db.collection("events")
          .where("userId", "==", uid)
          .where(field, "==", v)
          .limit(120)
          .get();

        snap.docs.forEach(d => {
          const ev = d.data() || {};
          const evDate = String(ev.eventDate || ev.date || "").trim().slice(0, 10);

          if (evDate === dt && inseminationEventTypeIsAISrv(ev)) {
            seen.add(d.id);
          }
        });

      } catch (e) {
        console.warn("countInseminationsSameDaySrv failed:", e.message || e);
      }
    }
  }

  return seen.size;
}
function inseminationDecisionSrv(fd) {
  const doc = fd.documentData;
 if (!doc) return "❌ لم أجد بيانات الحيوان. راجع الرقم وحاول مرة أخرى.";

  const warnings = [];

  // ❌ خارج القطيع
  const st = String(doc.status ?? "").trim().toLowerCase();
  if (st === "inactive" || st === "archived") {
   return "❌ هذا الحيوان خارج القطيع، لذلك لا يمكن تسجيل التلقيح له.";
  }

  // ✅ تحديد النوع
  let sp = String(fd.species || doc.species || doc.animalTypeAr || "").trim();
  if (/cow|بقر/i.test(sp)) sp = "أبقار";
  if (/buffalo|جاموس/i.test(sp)) sp = "جاموس";

  const recommendedPostCalving = { "أبقار": 56, "جاموس": 45 };
  const hardBlockPostCalving = { "أبقار": 45, "جاموس": 35 };

  // ⚠️ العشار لا يُرفض مباشرة — يحتاج تأكيد فقد جنيني/فحص
  const repro = String(fd.reproStatusFromEvents || fd.reproductiveStatus || doc.reproductiveStatus || "").trim();

  if (inseminationIsPregnantStatusSrv(repro)) {
    if (!inseminationConfirmEmbryonicLossSrv(fd)) {
     return "CONFIRM_EMBRYONIC_LOSS|⚠️ الحيوان مسجّل عِشار. أكّد نتيجة الفحص التي تثبت فقد الحمل قبل تسجيل التلقيح. عند التأكيد سيحفظ مُرَبِّيك الفقد الجنيني أولًا ثم يسجل التلقيح.";
    }

    warnings.push("⚠️ تم تأكيد فقد الحمل. عند الحفظ سيسجل مُرَبِّيك الفقد الجنيني أولًا ثم التلقيح.");
  }

  // ⚠️ آخر ولادة:
  // المنع الصلب فقط قبل 45 يوم في الأبقار و35 يوم في الجاموس.
  // من بعد المنع الصلب حتى الحد التشغيلي المفضل → تحذير فقط ويسمح بالتسجيل.
 const lastCalving =
  String(fd.lastCalvingDate || "").trim() ||
  String(doc.lastCalvingDate || "").trim() ||
  (String(fd.lastBoundaryType || "").trim() === "ولادة" ? String(fd.lastBoundary || "").trim() : "");

  const recommendedDaysAfterCalving = Number(recommendedPostCalving[sp] || 56);
  const hardBlockDaysAfterCalving = Number(hardBlockPostCalving[sp] || 45);

  const dimFallback = Number(
    fd.dimAtEvent ??
    doc.daysInMilk ??
    doc.dimAtEvent ??
    doc.DIM
  );

  function inseminationPostCalvingDecisionSrv(daysAfterCalving) {
    const d = Math.round(Number(daysAfterCalving));
    if (!Number.isFinite(d) || d < 0) return "";

   if (d < hardBlockDaysAfterCalving) {
  return `❌ مرّ ${d} يومًا فقط منذ الولادة. يمكن تسجيل التلقيح بعد ${hardBlockDaysAfterCalving} يومًا على الأقل.`;
}

if (d < recommendedDaysAfterCalving) {
  warnings.push(
   `⚠️ مرّ ${d} يومًا منذ الولادة. يمكن حفظ التلقيح، لكن التوقيت المفضل بعد ${recommendedDaysAfterCalving} يومًا من الولادة.`
  );
}

    return "";
  }

  if (!lastCalving) {
    const blockReason = inseminationPostCalvingDecisionSrv(dimFallback);
    if (blockReason) return blockReason;

    if (!Number.isFinite(dimFallback)) {
      warnings.push("⚠️ لم أجد تاريخ آخر ولادة، لذلك لا أستطيع حساب المدة منذ الولادة بدقة.");
    }
  } else {
    const gapCalving = inseminationDaysBetweenSrv(lastCalving, fd.eventDate);

    if (!Number.isFinite(gapCalving)) {
     warnings.push("⚠️ لم أستطع حساب المدة منذ آخر ولادة. راجع تاريخ الولادة.");
    } else {
      const blockReason = inseminationPostCalvingDecisionSrv(gapCalving);
      if (blockReason) return blockReason;
    }
  }
  // ✅ تلقيح نفس اليوم: مرة إعادة واحدة فقط
  const sameDayCount = Number(fd.sameDayInseminationCount || 0);

  if (sameDayCount >= 2) {
    return "❌ سبق تسجيل تلقيحين لهذا الحيوان في اليوم نفسه، لذلك لا يمكن تسجيل تلقيح ثالث.";
  }

  if (sameDayCount === 1) {
   warnings.push("⚠️ سبق تسجيل تلقيح لهذا الحيوان اليوم. يُسمح بإعادة واحدة فقط؛ تأكد أن هذا التسجيل مقصود.");
  }

  // ✅ آخر تلقيح: من الأحداث أولًا ثم الوثيقة
  const lastAI = String(fd.lastInseminationDate || doc.lastInseminationDate || "").trim();

  if (lastAI) {
    const gapAI = inseminationDaysBetweenSrv(lastAI, fd.eventDate);

    if (Number.isFinite(gapAI) && gapAI > 0 && gapAI < 11) {
      warnings.push(`⚠️ آخر تلقيح كان منذ ${gapAI} يومًا فقط. تأكد أن إعادة التلقيح مقصودة.`);
    }
  }

  return warnings.length ? `WARN|${warnings.join("\n")}` : null;
}
// ============================================================
//                 ABORTION DECISION — moved from form-rules.js
//                 نقل قرار الإجهاض للسيرفر فقط
