async function existsCalvingSameDaySrv(uid, number, dateISO) {
  const num = String(number || '').trim();

  const snap = await db.collection('events')
    .where('userId', '==', uid)
    .where('animalNumber', '==', num)
    .where('eventType', '==', 'ولادة')
    .where('eventDate', '==', dateISO)
    .limit(1)
    .get();

  return !snap.empty;
}
// ============================================================
