function inseminationCleanReasonTextSrv(v = "") {
  return String(v || "")
    .trim()
    .replace(/^[✅❌⚠️🚫\s]+/gu, "")
    .replace(/^لا يمكن تسجيل التلقيح\s*[—\-:]\s*/u, "")
    .replace(/^لم يتم تسجيل التلقيح\s*[—\-:]\s*/u, "")
    .replace(/\s+/g, " ")
    .trim();
}

function inseminationNumbersTextSrv(list = []) {
  const nums = (Array.isArray(list) ? list : [])
    .map(x => String(x?.animalNumber || x?.number || x || "").trim())
    .filter(Boolean);

  if (!nums.length) return "";

  return nums.slice(0, 12).join("، ") + (
    nums.length > 12 ? `، … و${nums.length - 12} رقم آخر` : ""
  );
}

function inseminationFieldErrorsTextSrv(fieldErrors = {}) {
  return Object.values(fieldErrors || {})
    .map(v => inseminationCleanReasonTextSrv(v))
    .filter(Boolean)
    .join("، ");
}

function inseminationRejectReasonSrv(x = {}) {
  const fieldsText = inseminationFieldErrorsTextSrv(x.fieldErrors);
  if (fieldsText) return fieldsText;

  return inseminationCleanReasonTextSrv(
    x.message ||
    x.reason ||
    x.error ||
   "لا يمكن تسجيل التلقيح لهذا الحيوان."
  );
}

function inseminationRejectedReasonsTextSrv(list = [], title = "الأرقام التي لا يمكن تسجيل التلقيح لها") {
  const items = Array.isArray(list) ? list : [];
  if (!items.length) return "";

  const lines = items
    .slice(0, 12)
    .map(x => {
      const n = String(x.animalNumber || x.number || "").trim();
      const reason = inseminationRejectReasonSrv(x);
      return n
         ? `الرقم ${n}: ${reason}`
         : reason;
    })
    .filter(Boolean);

  if (!lines.length) return "";

  const more = items.length > 12
    ? `\n… و${items.length - 12} رقم آخر`
    : "";

  return `${title}:\n${lines.join("\n")}${more}`;
}

function inseminationSavedNumbersMessageSrv(saved = [], rejected = []) {
  const savedItems = Array.isArray(saved) ? saved : [];
  const rejectedItems = Array.isArray(rejected) ? rejected : [];
  const numsText = inseminationNumbersTextSrv(savedItems);

  if (!savedItems.length) {
    return "❌ لم يتم تسجيل التلقيح لأي حيوان.";
  }

  const base = savedItems.length === 1
  ? `✅ سجلت التلقيح للحيوان رقم ${numsText}.`
  : `✅ سجلت التلقيح لعدد ${savedItems.length} حيوانات — الأرقام: ${numsText}.`;

  if (!rejectedItems.length) return base;

 return `${base}\nولم أتمكن من تسجيل التلقيح لعدد ${rejectedItems.length} حيوانات.`;
}

function inseminationAcceptedWarningsTextSrv(accepted = []) {
  const items = (Array.isArray(accepted) ? accepted : [])
    .filter(x => String(x.message || x.warning || "").trim());

  if (!items.length) return "";

  const lines = items
    .slice(0, 12)
    .map(x => {
      const n = String(x.animalNumber || x.number || "").trim();
      const msg = inseminationCleanReasonTextSrv(x.message || x.warning || "");
      return n ? `الحيوان رقم ${n}: ${msg}` : msg;
    })
    .filter(Boolean);

  if (!lines.length) return "";

  const more = items.length > 12
    ? `\n… و${items.length - 12} تنبيه آخر`
    : "";

  return `تنبيهات التلقيح:\n${lines.join("\n")}${more}`;
}

function inseminationJoinMessageSrv(...parts) {
  return parts
    .map(x => String(x || "").trim())
    .filter(Boolean)
    .join("\n\n");
}
// ============================================================
//                 API: INSEMINATION GATE
//                 تحقق التلقيح من السيرفر فقط — فردي/جماعي — بدون حفظ
// ============================================================

app.post("/api/insemination/gate", requireUserId, async (req, res) => {
  try {
    if (!db) {
      return res.status(503).json({
        ok: false,
        allowed: false,
        error: "firestore_disabled",
        message: "❌ تعذّر فحص بيانات التلقيح الآن. حاول مرة أخرى."
      });
    }

    const uid = req.userId;
    const body = req.body || {};

    const rawNumbers =
      body.animalNumbers ||
      body.numbers ||
      body.animalNumber ||
      body.number ||
      "";

    const numbers = typeof parsePregnancyBulkNumbersSrv === "function"
      ? parsePregnancyBulkNumbersSrv(rawNumbers)
      : [calvingNormDigitsOnlySrv(rawNumbers)].filter(Boolean);

    const eventDate = String(
      body.eventDate ||
      body.date ||
      ""
    ).trim().slice(0, 10);

    if (!numbers.length || !eventDate) {
      return res.json({
        ok: true,
        allowed: false,
        silent: true,
        stage: "missing_basic",
        message: "أدخل رقم الحيوان وتاريخ التلقيح.",
        acceptedCount: 0,
        rejectedCount: 0,
        accepted: [],
        rejected: []
      });
    }

if (!calvingIsDateSrv(eventDate)) {
  const invalidDateRejected = numbers.map(n => ({
    animalNumber: String(n || ""),
    reason: "أدخل تاريخ تلقيح صحيحًا."
  }));

  return res.status(400).json({
    ok: false,
    allowed: false,
    stage: "invalid_date",
    message: inseminationJoinMessageSrv(
      "❌ أدخل تاريخ تلقيح صحيحًا.",
      inseminationRejectedReasonsTextSrv(
        invalidDateRejected,
        "الأرقام التي لا يمكن تسجيل التلقيح لها"
      )
    ),
    acceptedCount: 0,
    rejectedCount: invalidDateRejected.length,
    accepted: [],
    rejected: invalidDateRejected
  });
}
    const accepted = [];
    const rejected = [];

    for (const rawNum of numbers) {
      const animalNumber = calvingNormDigitsOnlySrv(rawNum);

      if (!animalNumber) {
        rejected.push({
          animalNumber: String(rawNum || ""),
         reason: "رقم الحيوان غير صحيح."
        });
        continue;
      }

      try {
        const animal = await fetchAnimalByNumberForCalvingGateSrv(uid, animalNumber);

        if (!animal) {
          rejected.push({
            animalNumber,
           reason: "لم أجد الحيوان في حسابك. راجع الرقم."
          });
          continue;
        }

        const doc = animal.data || {};
        const signals = await fetchCalvingSignalsFromEventsSrv(uid, animalNumber);

        let species = String(
          body.species ||
          doc.species ||
          doc.animalTypeAr ||
          doc.animalType ||
          doc.animaltype ||
          doc.type ||
          ""
        ).trim();

        if (/cow|بقر/i.test(species)) species = "أبقار";
        if (/buffalo|جاموس/i.test(species)) species = "جاموس";

        const reproFromEvents = String(signals.reproStatusFromEvents || "").trim();
        const reproFromDoc = String(doc.reproductiveStatus || "").trim();
        const reproStatus = reproFromEvents || reproFromDoc || "";

        const lastInseminationDate = String(
          signals.lastInseminationDateFromEvents ||
          doc.lastInseminationDate ||
          ""
        ).trim();

        const sameDayInseminationCount = await countInseminationsSameDaySrv(
          uid,
          animalNumber,
          eventDate
        );

        const gateData = {
          animalNumber,
          eventDate,
          animalId: animal.id || "",
          species,
          documentData: doc,
          reproductiveStatus: reproStatus,
          reproStatusFromEvents: reproFromEvents,
          lastInseminationDate,
          sameDayInseminationCount,
          confirmEmbryonicLoss: body.confirmEmbryonicLoss,
          embryonicLossConfirmed: body.embryonicLossConfirmed,
          confirmPregnancyLoss: body.confirmPregnancyLoss,
          pregnancyLossConfirmed: body.pregnancyLossConfirmed,
          lastBoundary: String(signals.lastBoundary || "").trim(),
          lastBoundaryType: String(signals.lastBoundaryType || "").trim()
        };

        const errMsg = inseminationDecisionSrv(gateData);

        if (errMsg) {
          const raw = String(errMsg || "");
          const isWarn = raw.startsWith("WARN|");
          const needsEmbryonicConfirm = raw.startsWith("CONFIRM_EMBRYONIC_LOSS|");

          const message = needsEmbryonicConfirm
            ? raw.replace(/^CONFIRM_EMBRYONIC_LOSS\|/, "")
            : isWarn
              ? raw.replace(/^WARN\|/, "")
              : raw;

          if (!isWarn && !needsEmbryonicConfirm) {
            rejected.push({
              animalNumber,
              reason: message
            });
            continue;
          }

          accepted.push({
            animalNumber,
            animalId: animal.id || "",
            species,
            reproductiveStatus: reproStatus,
            warning: true,
            message,
            requiresEmbryonicLossConfirmation: needsEmbryonicConfirm,
            sameDayInseminationCount,
            stage: "pre_gate"
          });
          continue;
        }
        accepted.push({
          animalNumber,
          animalId: animal.id || "",
          species,
          reproductiveStatus: reproStatus,
          lastInseminationDate,
          stage: "pre_gate"
        });

      } catch (oneErr) {
        console.error("insemination-gate-one", animalNumber, oneErr);

        rejected.push({
          animalNumber,
         reason: "تعذّر فحص بيانات هذا الحيوان الآن."
        });
      }
    }

const acceptedCount = accepted.length;
const rejectedCount = rejected.length;
const isBulk = numbers.length > 1;

if (!isBulk) {
  if (!acceptedCount) {
    const r0 = rejected[0] || {};
    const n = String(r0.animalNumber || numbers[0] || "").trim();

    return res.status(400).json({
      ok: false,
      allowed: false,
      stage: "not_eligible",
      message: inseminationJoinMessageSrv(
        n
          ? `❌ لا يمكن تسجيل التلقيح للحيوان رقم ${n}.`
          : "❌ لا يمكن تسجيل التلقيح لهذا الحيوان.",
        inseminationRejectedReasonsTextSrv(
          rejected,
          "سبب عدم تسجيل التلقيح"
        )
      ),
      acceptedCount,
      rejectedCount,
      accepted,
      rejected
    });
  }

  const a0 = accepted[0];

  return res.json({
    ok: true,
    allowed: true,
    stage: "pre_gate",
    message: inseminationJoinMessageSrv(
      `✅ راجعت بيانات الحيوان رقم ${a0.animalNumber || ""}، ويمكنك استكمال تسجيل التلقيح.`,
      inseminationAcceptedWarningsTextSrv(accepted)
    ),
    animalId: a0.animalId || "",
    animalNumber: a0.animalNumber || "",
    species: a0.species || "",
    reproductiveStatus: a0.reproductiveStatus || "",
    lastInseminationDate: a0.lastInseminationDate || "",
    acceptedCount,
    rejectedCount,
    accepted,
    rejected
  });
}
const acceptedNumbersMessage = acceptedCount
  ? `يمكن تسجيل التلقيح للأرقام التالية: ${inseminationNumbersTextSrv(accepted)}.`
  : "";

const gateBaseMessage = acceptedCount
  ? `راجعت ${numbers.length} حيوانًا: يمكن استكمال التلقيح لـ${acceptedCount}، ولا يمكن استكماله لـ${rejectedCount}.`
  : "❌ لا يمكن استكمال تسجيل التلقيح لأي من الأرقام المدخلة.";

return res.json({
  ok: true,
  allowed: acceptedCount > 0,
  stage: "pre_gate",
  message: inseminationJoinMessageSrv(
    gateBaseMessage,
    acceptedNumbersMessage,
    inseminationRejectedReasonsTextSrv(
      rejected,
     "الأرقام التي لا يمكن تسجيل التلقيح لها"
    ),
    inseminationAcceptedWarningsTextSrv(accepted)
  ),
  acceptedCount,
  rejectedCount,
  accepted,
  rejected
});
  } catch (e) {
    console.error("insemination-gate", e);

    return res.status(500).json({
      ok: false,
      allowed: false,
      error: "insemination_gate_failed",
     message: "❌ تعذّر فحص بيانات التلقيح الآن. حاول مرة أخرى."
    });
  }
});
