//                 API: VACCINATION GATE ONLY
//                 تحقق التحصين من السيرفر فقط — فردي/جماعي — بدون حفظ
// ============================================================

function vaccinationParseNumbersSrv(raw) {
  let arr = [];

  if (Array.isArray(raw)) {
    arr = raw;
  } else {
    const txt = String(raw || "").trim();
    if (!txt) return [];
    arr = txt.split(/\n|,|;|،|\s+/g);
  }

  return [...new Set(
    arr
      .map(x => calvingNormDigitsOnlySrv(x))
      .filter(Boolean)
  )];
}

async function vaccinationHasSameDaySrv(uid, animalNumber, eventDate, vaccine) {
  const num = calvingNormDigitsOnlySrv(animalNumber);
  const dt = String(eventDate || "").trim().slice(0, 10);
  const vx = String(vaccine || "").trim();

  if (!db || !uid || !num || !dt || !vx) return false;

  const snap = await db.collection("events")
    .where("userId", "==", uid)
    .where("animalNumber", "==", num)
    .limit(80)
    .get();

  let found = false;

  snap.forEach(ds => {
    const ev = ds.data() || {};

    const t = String(ev.eventType || ev.type || ev.eventTypeNorm || "").trim();
    const ed = String(ev.eventDate || ev.date || "").trim().slice(0, 10);
    const v = String(ev.vaccine || ev.vaccineName || "").trim();

    const isVaccination =
      t === "تحصين" ||
      t === "vaccination" ||
      t.includes("تحصين") ||
      t.includes("vaccination");

    if (isVaccination && ed === dt && v === vx) {
      found = true;
    }
  });

  return found;
}
function vaccinationDoseNormSrv(v) {
  const s = String(v || "").trim().toLowerCase();

  if (
    s === "prime" ||
    s === "primary" ||
    s.includes("primary") ||
    s.includes("أساسي") ||
    s.includes("اساسي") ||
    s.includes("أولى") ||
    s.includes("اولى") ||
    s.includes("أولية") ||
    s.includes("اولية")
  ) {
    return "primary";
  }

  if (
    s === "booster" ||
    s === "periodic" ||
    s.includes("booster") ||
    s.includes("periodic") ||
    s.includes("منشط") ||
    s.includes("دوري")
  ) {
    return "booster";
  }

  return s;
}

function vaccinationTextKeySrv(v) {
  return String(v || "")
    .trim()
    .toLowerCase()
    .replace(/[أإآ]/g, "ا")
    .replace(/ة/g, "ه")
    .replace(/ى/g, "ي")
    .replace(/[^\p{L}\p{N}]+/gu, "_")
    .replace(/^_+|_+$/g, "");
}

function vaccinationTaskPendingSrv(t = {}) {
  const st = String(t.status || "").trim().toLowerCase();

  return (
    t.done !== true &&
    !t.completedAt &&
    st !== "done" &&
    st !== "completed" &&
    st !== "cancelled" &&
    st !== "canceled"
  );
}

function vaccinationSameVaccineKeySrv(a, b) {
  const x = vaccinationTextKeySrv(a);
  const y = vaccinationTextKeySrv(b);

  if (!x || !y) return false;
  if (x === y) return true;

  return (
    x.length >= 3 &&
    y.length >= 3 &&
    (x.includes(y) || y.includes(x))
  );
}

async function vaccinationDueWarningSrv({
  uid,
  animalNumber,
  eventDate,
  vaccine,
  doseType
} = {}) {
  const num = calvingNormDigitsOnlySrv(animalNumber);
  const dt = String(eventDate || "").trim().slice(0, 10);
  const vx = String(vaccine || "").trim();
  const incomingDose = vaccinationDoseNormSrv(doseType);

  if (!db || !uid || !num || !dt || !vx) return null;

  const snap = await db.collection("tasks")
    .where("userId", "==", uid)
    .where("animalNumber", "==", num)
    .limit(120)
    .get();

  let nearest = null;

  snap.forEach(ds => {
    const t = ds.data() || {};

    const taskType = String(t.taskType || t.type || "").trim().toLowerCase();
    const isVaccinationTask =
      taskType === "vaccination" ||
      taskType.includes("vaccination") ||
      taskType.includes("تحصين");

    if (!isVaccinationTask) return;
    if (!vaccinationTaskPendingSrv(t)) return;

    const taskVaccine = String(t.vaccine || t.vaccineKey || "").trim();
    if (!vaccinationSameVaccineKeySrv(taskVaccine, vx)) return;

    const taskDose = vaccinationDoseNormSrv(t.doseType || "");
    if (taskDose && incomingDose && taskDose !== incomingDose) return;

    const dueDate = String(t.dueDate || "").trim().slice(0, 10);
    if (!/^\d{4}-\d{2}-\d{2}$/.test(dueDate)) return;

    if (!nearest || dueDate < nearest.dueDate) {
      nearest = {
        taskId: ds.id,
        dueDate,
        windowStart: String(t.windowStart || dueDate).slice(0, 10),
        windowEnd: String(t.windowEnd || dueDate).slice(0, 10),
        doseType: taskDose,
        cycle: t.cycle || ""
      };
    }
  });

  if (!nearest) return null;

  if (dt < nearest.dueDate) {
    return {
      level: "warn",
      code: "vaccination_early",
      dueDate: nearest.dueDate,
      taskId: nearest.taskId,
     message: `⚠️ موعد هذه الجرعة المسجل هو ${nearest.dueDate}، والتاريخ المختار أبكر منه. يمكنك الحفظ إذا كان تقديم الجرعة مقصودًا.`
    };
  }

  const windowEnd = String(nearest.windowEnd || "").slice(0, 10);
  if (/^\d{4}-\d{2}-\d{2}$/.test(windowEnd) && dt > windowEnd) {
    return {
      level: "warn",
      code: "vaccination_overdue",
      dueDate: nearest.dueDate,
      windowEnd,
      taskId: nearest.taskId,
     message: `⚠️ موعد هذه الجرعة كان ${nearest.dueDate} وانتهت نافذتها المتوقعة. يمكنك الحفظ، لكن الجرعة متأخرة عن موعدها.`
    };
  }

  return {
    level: "info",
    code: "vaccination_due_ok",
    dueDate: nearest.dueDate,
    taskId: nearest.taskId,
    message: "✅ توقيت الجرعة داخل موعد التحصين المتوقع."
  };
}
function vaccinationProgramModeNormSrv(raw) {
  const mode = String(raw || "").trim().toLowerCase();

  if (mode === "farm") return "farm";
  if (mode === "murabbik_default") return "murabbik_default";

  return "";
}

function vaccinationProgramContextSrv(mode, saved = false) {
  const programMode = vaccinationProgramModeNormSrv(mode);

  return {
    programMode,

    programLabel:
      programMode === "farm"
        ? "برنامج المزرعة"
        : programMode === "murabbik_default"
          ? "برنامج مُرَبِّيك الخبير"
          : "",

    message:
      programMode === "farm"
        ? (
            saved
              ? "برنامج المزرعة هو البرنامج التشغيلي المعتمد للتحصينات."
              : "تم اختيار برنامج المزرعة."
          )
        : programMode === "murabbik_default"
          ? (
              saved
                ? "برنامج مُرَبِّيك الخبير هو البرنامج التشغيلي المعتمد للتحصينات."
                : "تم اختيار برنامج مُرَبِّيك الخبير."
            )
          : "اختر برنامج المزرعة أو برنامج مُرَبِّيك الخبير.",

    saved: Boolean(saved && programMode)
  };
}

async function vaccinationReadProgramContextSrv(
  uid,
  requestedMode = ""
) {
  const requested =
    vaccinationProgramModeNormSrv(requestedMode);

  if (!db || !uid) {
    return vaccinationProgramContextSrv(
      requested,
      false
    );
  }

  const snap = await db
    .collection("vaccination_program_settings")
    .doc(uid)
    .get();

  const stored = snap.exists
    ? (snap.data() || {})
    : {};

  const storedMode =
    vaccinationProgramModeNormSrv(
      stored.programMode
    );

  const activeMode =
    requested ||
    storedMode;

  return vaccinationProgramContextSrv(
    activeMode,
    Boolean(
      storedMode &&
      storedMode === activeMode
    )
  );
}

async function vaccinationSaveProgramContextSrv(
  uid,
  rawMode
) {
  const programMode =
    vaccinationProgramModeNormSrv(rawMode);

  if (!db || !uid || !programMode) {
    const err =
      new Error("vaccination_program_required");

    err.publicMessage =
      "❌ اختر برنامج المزرعة أو برنامج مُرَبِّيك الخبير.";

    throw err;
  }

  const ref = db
    .collection("vaccination_program_settings")
    .doc(uid);

  const snap = await ref.get();

  const old = snap.exists
    ? (snap.data() || {})
    : {};

  const previousMode =
    vaccinationProgramModeNormSrv(
      old.programMode
    );

  await ref.set({
    userId: uid,

    programMode,

    programLabel:
      programMode === "farm"
        ? "برنامج المزرعة"
        : "برنامج مُرَبِّيك الخبير",

    previousMode,

    source:
      "server:/api/vaccination/program-mode",

    updatedAt:
      admin.firestore.FieldValue.serverTimestamp(),

    ...(snap.exists
      ? {}
      : {
          createdAt:
            admin.firestore.FieldValue.serverTimestamp()
        })
  }, { merge: true });

  return vaccinationProgramContextSrv(
    programMode,
    true
  );
}

app.post(
  "/api/vaccination/program-mode",
  requireUserId,
  async (req, res) => {
    try {
      const programContext =
        await vaccinationSaveProgramContextSrv(
          req.userId,
          req.body?.programMode
        );

      return res.json({
        ok: true,

        message:
          "✅ تم اعتماد برنامج التحصينات بنجاح.",

        programContext
      });

    } catch (e) {
      console.error(
        "vaccination-program-mode-save",
        e
      );

      return res.status(400).json({
        ok: false,

        message:
          e.publicMessage ||
          "❌ تعذّر حفظ اختيار برنامج التحصينات.",

        programContext:
          vaccinationProgramContextSrv("")
      });
    }
  }
);
