function vaccinationFarmProgramTextSrv(raw) {
  return String(raw || "").trim().replace(/\s+/g, " ");
}

function vaccinationFarmProgramDateSrv(raw) {
  const value = String(raw || "").trim().slice(0, 10);

  if (!/^\d{4}-\d{2}-\d{2}$/.test(value)) {
    return "";
  }

  const ms = Date.parse(`${value}T00:00:00Z`);

  if (!Number.isFinite(ms)) {
    return "";
  }

  return new Date(ms).toISOString().slice(0, 10) === value
    ? value
    : "";
}

function vaccinationFarmProgramIntSrv(raw, fallback = 0) {
  if (
    raw === "" ||
    raw === null ||
    raw === undefined
  ) {
    return fallback;
  }

  const n = Number(raw);

  return Number.isInteger(n)
    ? n
    : NaN;
}

function vaccinationFarmProgramRowsSrv(body = {}) {
  const rows =
    body.rows ??
    body.items ??
    body.schedule ??
    body.programRows;

  return Array.isArray(rows)
    ? rows
    : null;
}

function vaccinationFarmProgramNormalizeRowsSrv(
  rawRows = []
) {
  const rows = [];
  const errors = [];

  const options =
    vaccinationFarmProgramOptionsSrv();

  const findOption = (list, raw) => {
    const value =
      String(raw || "").trim();

    if (!value || !Array.isArray(list)) {
      return null;
    }

    return (
      list.find(item =>
        String(item?.value || "") === value ||
        String(item?.label || "") === value
      ) ||
      null
    );
  };

  rawRows.forEach((raw, index) => {
    if (
      !raw ||
      typeof raw !== "object" ||
      Array.isArray(raw)
    ) {
      errors.push({
        rowIndex: index,
        field: "row",
        message:
          `السطر رقم ${index + 1} غير صالح.`
      });

      return;
    }

    const vaccine =
      findOption(
        options.vaccines,
        raw.vaccineCode ||
        raw.vaccineName ||
        raw.vaccine
         );
     const programSection =
      findOption(
        options.programSections,
        raw.programSection ||
        raw.section ||
        raw.programGroup
      );

    const isCalves =
      programSection?.value === "calves";
    const rawVaccineForm =
      raw.vaccineForm ||
      raw.vaccineType ||
      raw.formType ||
      "";

    const vaccineForm =
      vaccine
        ? (
            findOption(
              vaccine.formOptions,
              rawVaccineForm
            ) ||
            (
              !rawVaccineForm &&
              vaccine.formOptions?.length === 1
                ? vaccine.formOptions[0]
                : null
            )
          )
        : null;

    const doseType =
      findOption(
        options.doseTypes,
        raw.doseType
      );

    const startDate =
      vaccinationFarmProgramDateSrv(
        raw.startDate ||
        raw.date
      );

    const repeatEvery =
      vaccinationFarmProgramIntSrv(
        raw.repeatEvery,
        0
      );

    const repeatUnit =
      repeatEvery > 0
        ? findOption(
            options.repeatUnits,
            raw.repeatUnit
          )
        : null;

    const calfAgeRaw =
      raw.calfAgeValue ??
      raw.calfAge ??
      raw.ageAtVaccination ??
      "";

    const calfAgeUnitRaw =
      raw.calfAgeUnit ??
      raw.ageUnit ??
      "";

    const hasCalfAge =
      String(calfAgeRaw ?? "").trim() !== "" ||
      String(calfAgeUnitRaw || "").trim() !== "";

    const calfAgeValue =
      hasCalfAge
        ? vaccinationFarmProgramIntSrv(
            calfAgeRaw,
            NaN
          )
        : null;

    const calfAgeUnit =
      hasCalfAge
        ? findOption(
            options.calfAgeUnits,
            calfAgeUnitRaw
          )
        : null;

    const advanceNoticeDays =
      vaccinationFarmProgramIntSrv(
        raw.advanceNoticeDays,
        0
      );

    const notes =
      vaccinationFarmProgramTextSrv(
        raw.notes
      );
        if (!programSection) {
      errors.push({
        rowIndex: index,
        field: "programSection",
        message:
          `اختر قسم التحصين في السطر رقم ${index + 1}.`
      });
    }
    if (!vaccine) {
      errors.push({
        rowIndex: index,
        field: "vaccineCode",
        message:
          `اختر اسم التحصين من القائمة في السطر رقم ${index + 1}.`
      });
    }

    if (vaccine && !vaccineForm) {
      errors.push({
        rowIndex: index,
        field: "vaccineForm",
        message:
          `اختر نوع اللقاح في السطر رقم ${index + 1}.`
      });
    }

    if (!doseType) {
      errors.push({
        rowIndex: index,
        field: "doseType",
        message:
          `اختر نوع الجرعة في السطر رقم ${index + 1}.`
      });
    }

      if (
      isCalves &&
      (
        !Number.isInteger(calfAgeValue) ||
        calfAgeValue <= 0
      )
    ) {
      errors.push({
        rowIndex: index,
        field: "calfAgeValue",
        message:
          `أدخل عمر تحصين صحيحًا للعجول في السطر رقم ${index + 1}.`
      });
    }

    if (
      isCalves &&
      !calfAgeUnit
    ) {
      errors.push({
        rowIndex: index,
        field: "calfAgeUnit",
        message:
          `اختر وحدة عمر العجول في السطر رقم ${index + 1}.`
      });
    }

    if (
      !isCalves &&
      !startDate
    ) {
      errors.push({
        rowIndex: index,
        field: "startDate",
        message:
          `أدخل تاريخ بداية البرنامج في السطر رقم ${index + 1}.`
      });
    }

    if (
      !Number.isInteger(repeatEvery) ||
      repeatEvery <= 0 ||
      repeatEvery > 120
    ) {
      errors.push({
        rowIndex: index,
        field: "repeatEvery",
        message:
          `أدخل مدة تكرار صحيحة في السطر رقم ${index + 1}.`
      });
    }

    if (!repeatUnit) {
      errors.push({
        rowIndex: index,
        field: "repeatUnit",
        message:
          `اختر فترة التكرار في السطر رقم ${index + 1}.`
      });
    }


  
    if (
      !Number.isInteger(
        advanceNoticeDays
      ) ||
      advanceNoticeDays < 0 ||
      advanceNoticeDays > 90
    ) {
      errors.push({
        rowIndex: index,
        field: "advanceNoticeDays",
        message:
          `مدة التنبيه غير صحيحة في السطر رقم ${index + 1}.`
      });
    }

    if (notes.length > 500) {
      errors.push({
        rowIndex: index,
        field: "notes",
        message:
          `ملاحظات السطر رقم ${index + 1} أطول من المسموح.`
      });
    }

    if (
      errors.some(
        item => item.rowIndex === index
      )
    ) {
      return;
    }

    const rowId =
      String(
        raw.rowId ||
        raw.id ||
        ""
      )
        .trim()
        .replace(
          /[^A-Za-z0-9_-]/g,
          "_"
        )
        .slice(0, 80) ||
      crypto.randomUUID();

       rows.push({
      rowId,

      programSection:
        programSection.value,

      programSectionLabel:
        programSection.label,

      vaccineCode:
        vaccine.value,

      vaccineName:
        vaccine.label,

      vaccineForm:
        vaccineForm.value,

      vaccineFormLabel:
        vaccineForm.label,

      doseType:
        doseType.value,

      doseTypeLabel:
        doseType.label,

          startDate:
        isCalves
          ? ""
          : startDate,

      repeatEvery,

      repeatUnit:
        repeatUnit.value,

      repeatUnitLabel:
        repeatUnit.label,

      calfSchedule:
        isCalves,

      calfAgeValue:
        isCalves
          ? calfAgeValue
          : null,

      calfAgeUnit:
        isCalves
          ? calfAgeUnit.value
          : "",

      calfAgeUnitLabel:
        isCalves
          ? calfAgeUnit.label
          : "",
      advanceNoticeDays,
      notes,

      active:
        raw.active !== false
    });
  });

  return {
    rows,
    errors
  };
}
function vaccinationFarmProgramResponseSrv(
  data = {},
  exists = false
) {
  const rows =
    Array.isArray(data.rows)
      ? data.rows
      : [];

  return {
    exists:
      Boolean(exists),

    version:
      Number(data.version || 0),

    previousVersion:
      Number(
        data.previousVersion || 0
      ),

    programName:
      vaccinationFarmProgramTextSrv(
        data.programName ||
        "برنامج المزرعة"
      ),

    programNotes:
      vaccinationFarmProgramTextSrv(
        data.programNotes
      ),

    rowCount:
      rows.length,

    rows,

    contentHash:
      String(
        data.contentHash || ""
      )
  };
}
function vaccinationFarmProgramExecutionRowsSrv(
  data = {}
) {
  const rows =
    Array.isArray(data.rows)
      ? data.rows
      : [];

  return rows
    .filter(row =>
      row &&
      typeof row === "object" &&
      row.active !== false &&
      String(row.rowId || "").trim() &&
      String(row.vaccineCode || "").trim()
    )
    .map(row => ({
      programRowId:
        String(row.rowId || "").trim(),

      vaccineCode:
        String(row.vaccineCode || "").trim(),

      vaccine:
        String(row.vaccineName || "").trim(),

      programSection:
        String(row.programSection || "").trim(),

      programSectionLabel:
        String(row.programSectionLabel || "").trim(),

      vaccineForm:
        String(row.vaccineForm || "").trim(),

      vaccineFormLabel:
        String(row.vaccineFormLabel || "").trim(),

      doseType:
        String(row.doseType || "").trim(),

      doseTypeLabel:
        String(row.doseTypeLabel || "").trim(),

      startDate:
        String(row.startDate || "")
          .trim()
          .slice(0, 10),

      repeatEvery:
        Number(row.repeatEvery || 0),

      repeatUnit:
        String(row.repeatUnit || "").trim(),

      repeatUnitLabel:
        String(row.repeatUnitLabel || "").trim(),

      calfSchedule:
        row.calfSchedule === true,

      calfAgeValue:
        Number(row.calfAgeValue || 0),

      calfAgeUnit:
        String(row.calfAgeUnit || "").trim(),

      calfAgeUnitLabel:
        String(row.calfAgeUnitLabel || "").trim(),

      advanceNoticeDays:
        Math.max(
          0,
          Math.min(
            90,
            Number(
              row.advanceNoticeDays || 0
            ) || 0
          )
        ),

      notes:
        String(row.notes || "").trim()
    }));
}

async function vaccinationReadFarmProgramExecutionSrv(
  uid
) {
  if (!db || !uid) {
    return {
      exists: false,
      version: 0,
      rows: []
    };
  }

  const snap = await db
    .collection("vaccination_farm_programs")
    .doc(uid)
    .get();

  const data = snap.exists
    ? (snap.data() || {})
    : {};

  return {
    exists: snap.exists,
    version: Number(data.version || 0),

    rows:
      vaccinationFarmProgramExecutionRowsSrv(
        data
      )
  };
}
