app.post(
  "/api/vaccination/farm-program",
  requireUserId,
  async (req, res) => {
    try {
      if (!db) {
        return res.status(503).json({
          ok: false,

          message:
            "تعذّر حفظ برنامج المزرعة الآن. حاول مرة أخرى."
        });
      }

      const uid =
        req.userId;

      const body =
        req.body || {};

      const programContext =
        await vaccinationReadProgramContextSrv(
          uid
        );

      if (
        programContext.saved !== true ||
        programContext.programMode !==
          "farm"
      ) {
        return res.status(409).json({
          ok: false,

          error:
            "farm_program_not_active",

          message:
            "فعّل برنامج المزرعة أولًا قبل إدخال جدول التحصينات.",

          programContext
        });
      }

      const rawRows =
        vaccinationFarmProgramRowsSrv(
          body
        );

      if (
        !rawRows ||
        !rawRows.length ||
        rawRows.length > 100
      ) {
        return res.status(400).json({
          ok: false,

          error:
            "farm_program_rows_count",

          message:
            !rawRows
              ? "أرسل جدول التحصينات في صورة قائمة صفوف."
              : !rawRows.length
                ? "أضف تحصينًا واحدًا على الأقل قبل حفظ البرنامج."
                : "الحد الأقصى لجدول برنامج المزرعة هو 100 سطر.",

          errors: []
        });
      }

      const programName =
        vaccinationFarmProgramTextSrv(
          body.programName ||
          "برنامج المزرعة"
        );

      const programNotes =
        vaccinationFarmProgramTextSrv(
          body.programNotes ||
          body.notes
        );

      const normalized =
        vaccinationFarmProgramNormalizeRowsSrv(
          rawRows
        );

      const errors = [
        ...normalized.errors
      ];

      if (
        !programName ||
        programName.length > 120
      ) {
        errors.unshift({
          rowIndex: -1,

          field:
            "programName",

          message:
            "اسم برنامج المزرعة مطلوب وبحد أقصى 120 حرفًا."
        });
      }

      if (
        programNotes.length > 1000
      ) {
        errors.unshift({
          rowIndex: -1,

          field:
            "programNotes",

          message:
            "ملاحظات برنامج المزرعة أطول من المسموح."
        });
      }

      if (errors.length) {
        return res.status(400).json({
          ok: false,

          error:
            "farm_program_invalid",

          message:
            "راجع بيانات جدول التحصينات قبل الحفظ.",

          errors
        });
      }

      const rows =
        normalized.rows;

      const currentRef =
        db
          .collection(
            "vaccination_farm_programs"
          )
          .doc(uid);

      const settingsRef =
        db
          .collection(
            "vaccination_program_settings"
          )
          .doc(uid);

      const contentHash =
        crypto
          .createHash("sha256")
          .update(
            JSON.stringify({
              programName,
              programNotes,
              rows
            })
          )
          .digest("hex");

      const savedMeta =
        await db.runTransaction(
          async tx => {
            const currentSnap =
              await tx.get(
                currentRef
              );

            const old =
              currentSnap.exists
                ? (
                    currentSnap.data() ||
                    {}
                  )
                : {};

            const previousVersion =
              Math.max(
                0,
                Number(
                  old.version || 0
                )
              );

            const version =
              previousVersion + 1;

            const versionId =
              String(version)
                .padStart(
                  6,
                  "0"
                );

            const now =
              admin
                .firestore
                .FieldValue
                .serverTimestamp();

            const payload = {
              userId:
                uid,

              programMode:
                "farm",

              programName,

              programNotes,

              version,

              previousVersion,

              rowCount:
                rows.length,

              rows,

              contentHash,

              source:
                "server:/api/vaccination/farm-program",

              createdAt:
                old.createdAt ||
                now,

              updatedAt:
                now
            };

            tx.set(
              currentRef,
              payload
            );

            tx.set(
              currentRef
                .collection(
                  "versions"
                )
                .doc(
                  versionId
                ),
              {
                ...payload,

                versionId,

                savedAt:
                  now
              }
            );

            tx.set(
              settingsRef,
              {
                farmProgramVersion:
                  version,

                farmProgramRowCount:
                  rows.length,

                farmProgramUpdatedAt:
                  now,

                updatedAt:
                  now
              },
              {
                merge: true
              }
            );

            return {
              version,

              previousVersion,

              rowCount:
                rows.length
            };
          }
        );

      const savedSnap =
        await currentRef.get();

      return res.json({
        ok: true,

        message:
          "تم حفظ جدول برنامج المزرعة بنجاح.",

        programContext,

        savedMeta,

        program:
          vaccinationFarmProgramResponseSrv(
            savedSnap.exists
              ? (
                  savedSnap.data() ||
                  {}
                )
              : {},
            savedSnap.exists
          )
      });

    } catch (e) {
      console.error(
        "vaccination-farm-program-save",
        e
      );

      return res.status(500).json({
        ok: false,

        message:
          "تعذّر حفظ برنامج المزرعة الآن. حاول مرة أخرى."
      });
    }
  }
);

app.post("/api/vaccination/gate", requireUserId, async (req, res) => {
  try {
    if (!db) {
      return res.status(503).json({
        ok: false,
        allowed: false,
        stage: "firestore_disabled",
        message: "❌ تعذّر فحص بيانات التحصين الآن. حاول مرة أخرى.",
        acceptedCount: 0,
        rejectedCount: 0,
        accepted: [],
        rejected: []
      });
    }

        const uid = req.userId;
    const body = req.body || {};

    const programContext =
      await vaccinationReadProgramContextSrv(
        uid,
        body.programMode
      );
    const programLink =
  await vaccinationResolveProgramRowSrv({
    uid,
    programContext,
    body
  });

if (!programLink.ok) {
  return res.status(409).json({
    ok: false,
    allowed: false,

    stage:
      programLink.error ||
      "vaccination_program_link_failed",

    message:
      programLink.message ||
      "❌ تعذّر ربط التحصين بالبرنامج المختار.",

    programContext,

    acceptedCount: 0,
    rejectedCount: 0,
    accepted: [],
    rejected: []
  });
}
    const rawNumbers =
      body.animalNumbers ||
      body.numbers ||
      body.selectedNumbers ||
      body.groupNumbers ||
      body.animals ||
      body.animalNumber ||
      body.number ||
      "";

    const eventDate = String(
      body.eventDate ||
      body.date ||
      ""
    ).trim().slice(0, 10);

const vaccine = String(
  programLink.linked
    ? programLink.vaccine
    : (
        body.vaccine ||
        body.vaccineName ||
        ""
      )
).trim();

const vaccineCode = String(
  programLink.vaccineCode ||
  body.vaccineCode ||
  ""
).trim();

const programRowId = String(
  programLink.programRowId ||
  body.programRowId ||
  ""
).trim();

const doseType = String(
  programLink.linked
    ? programLink.doseType
    : (body.doseType || "")
).trim();
    const numbers = vaccinationParseNumbersSrv(rawNumbers);

        if (!numbers.length || !eventDate || !vaccine) {
      return res.json({
        ok: true,
        allowed: false,
        silent: true,
        stage: "missing_basic",

        message: programContext.programMode
          ? "أدخل رقم الحيوان وتاريخ التحصين ونوع التحصين."
          : "اختر برنامج المزرعة أو برنامج مُرَبِّيك الخبير، ثم أكمل بيانات التحصين.",

        programContext,

        acceptedCount: 0,
        rejectedCount: 0,
        accepted: [],
        rejected: []
      });
    }

    if (!programContext.programMode) {
      return res.status(400).json({
        ok: false,
        allowed: false,
        stage: "vaccination_program_required",

        message:
          "❌ اختر برنامج المزرعة أو برنامج مُرَبِّيك الخبير.",

        programContext,

        acceptedCount: 0,
        rejectedCount: 0,
        accepted: [],
        rejected: []
      });
    }

    if (!calvingIsDateSrv(eventDate)) {
      return res.status(400).json({
        ok: false,
        allowed: false,
        stage: "invalid_date",
        message: "❌ أدخل تاريخ تحصين صحيحًا.",
        acceptedCount: 0,
        rejectedCount: numbers.length,
        accepted: [],
        rejected: numbers.map(n => ({
          animalNumber: String(n || ""),
          reason: "أدخل تاريخ تحصين صحيحًا."
        }))
      });
    }

    const accepted = [];
    const rejected = [];

    for (const rawNum of numbers) {
      const animalNumber = calvingNormDigitsOnlySrv(rawNum);

      if (!animalNumber) {
        rejected.push({
          animalNumber: String(rawNum || ""),
          reason: "رقم الحيوان غير صحيح."
        });
        continue;
      }

      const animal = await fetchAnimalByNumberForCalvingGateSrv(uid, animalNumber);

      if (!animal) {
        rejected.push({
          animalNumber,
          reason: "لم أجد الحيوان في حسابك. راجع الرقم."
        });
        continue;
      }

      const doc = animal.data || {};
      const status = String(doc.status || "active").trim().toLowerCase();

      if (status === "inactive" || status === "archived") {
        rejected.push({
          animalNumber,
          reason: "الحيوان خارج القطيع، لذلك لا يمكن تسجيل تحصين له."
        });
        continue;
      }

      const duplicated = await vaccinationHasSameDaySrv(
        uid,
        animalNumber,
        eventDate,
        vaccine
      );

      if (duplicated) {
        rejected.push({
          animalNumber,
          reason: "سبق تسجيل التحصين نفسه لهذا الحيوان في التاريخ نفسه."
        });
        continue;
      }

const dueWarning = null;
accepted.push({
  animalNumber,
  animalId: animal.id || "",
  species: doc.species || doc.animalTypeAr || doc.animalType || "",
  status,
  vaccineCode,
  programRowId,

  programSection:
  programLink.programSection || "",

vaccinationProgramVersion:
  Number(
    programLink.vaccinationProgramVersion || 0
  ),

farmProgramVersion:
  Number(
    programLink.farmProgramVersion || 0
  ),

murabbikProgramVersion:
  Number(
    programLink.murabbikProgramVersion || 0
  ),

  warnings: dueWarning ? [dueWarning] : [],
  warning: dueWarning?.message || "",
  dueDate: dueWarning?.dueDate || ""
});
}
const firstReason = rejected[0]?.reason || "";

return res.json({
  ok: true,
  allowed: accepted.length > 0,
  stage: "vaccination_gate",
  message: accepted.length
    ? (
        rejected.length
          ? `راجعت ${numbers.length} حيوانًا: يمكن تسجيل التحصين لـ${accepted.length}، ولا يمكن تسجيله لـ${rejected.length}.`
          : accepted.length === 1
            ? `✅ راجعت بيانات الحيوان رقم ${accepted[0].animalNumber}، ويمكنك تسجيل التحصين الآن.`
            : `✅ راجعت البيانات، ويمكن تسجيل التحصين لعدد ${accepted.length} حيوانات.`
      )
    : (firstReason || "❌ لا يمكن تسجيل التحصين لأي من الأرقام المدخلة."),
  programContext,

  acceptedCount: accepted.length,
  rejectedCount: rejected.length,

  accepted,
  rejected
});
  } catch (e) {
    console.error("vaccination-gate", e);

    return res.status(500).json({
      ok: false,
      allowed: false,
      stage: "vaccination_gate_failed",
      message: "❌ تعذّر فحص بيانات التحصين الآن. حاول مرة أخرى.",
      acceptedCount: 0,
      rejectedCount: 0,
      accepted: [],
      rejected: []
    });
  }
});
// ============================================================
//          VACCINATION SMART TASKS — PROGRAM DRIVEN
//          المهمة الحالية لكل حيوان/سطر برنامج
// ============================================================

function vaccinationYmdAddDaysSrv(ymd, days) {
  return vaccinationYmdAddUnitSrv(
    ymd,
    Number(days || 0),
    "day"
  );
}

function vaccinationYmdAddUnitSrv(
  ymd,
  rawValue,
  rawUnit
) {
  const value =
    Number(rawValue);

  const unit =
    String(rawUnit || "")
      .trim()
      .toLowerCase();

  const s =
    String(ymd || "")
      .trim()
      .slice(0, 10);

  if (
    !/^\d{4}-\d{2}-\d{2}$/.test(s) ||
    !Number.isFinite(value) ||
    !Number.isInteger(value)
  ) {
    return "";
  }

  const [year, month, day] =
    s.split("-").map(Number);

  if (
    !year ||
    month < 1 ||
    month > 12 ||
    day < 1 ||
    day > 31
  ) {
    return "";
  }

  if (
    unit === "day" ||
    unit === "week"
  ) {
    const days =
      unit === "week"
        ? value * 7
        : value;

    const d =
      new Date(
        Date.UTC(
          year,
          month - 1,
          day + days
        )
      );

    return d
      .toISOString()
      .slice(0, 10);
  }

  if (
    unit === "month" ||
    unit === "year"
  ) {
    const addMonths =
      unit === "year"
        ? value * 12
        : value;

    const absoluteMonth =
      (year * 12) +
      (month - 1) +
      addMonths;

    const targetYear =
      Math.floor(
        absoluteMonth / 12
      );

    const targetMonth =
      (
        (absoluteMonth % 12) +
        12
      ) % 12;

    const lastDay =
      new Date(
        Date.UTC(
          targetYear,
          targetMonth + 1,
          0
        )
      ).getUTCDate();

    const safeDay =
      Math.min(day, lastDay);

    return new Date(
      Date.UTC(
        targetYear,
        targetMonth,
        safeDay
      )
    )
      .toISOString()
      .slice(0, 10);
  }

  return "";
}

function vaccinationYmdSubtractUnitSrv(
  ymd,
  rawValue,
  rawUnit
) {
  const value =
    Number(rawValue);

  if (!Number.isFinite(value)) {
    return "";
  }

  return vaccinationYmdAddUnitSrv(
    ymd,
    -Math.abs(
      Math.trunc(value)
    ),
    rawUnit
  );
}

function vaccinationAnimalExpectedCalvingDateSrv(
  animal = {}
) {
  const value =
    String(
      animal.expectedCalvingDate ||
      animal.expectedDateOfCalving ||
      animal.ecd ||
      ""
    )
      .trim()
      .slice(0, 10);

  return /^\d{4}-\d{2}-\d{2}$/.test(
    value
  )
    ? value
    : "";
}

function vaccinationProgramTaskIdSrv({
  uid,
  animalNumber,
  programMode,
  programRowId
} = {}) {
  const raw = [
    String(uid || "").trim(),

    calvingNormDigitsOnlySrv(
      animalNumber
    ),

    String(programMode || "").trim(),

    String(programRowId || "").trim()
  ].join("|");

  const hash =
    crypto
      .createHash("sha256")
      .update(raw)
      .digest("hex")
      .slice(0, 40);

  return `vax_program__${hash}`;
}

function vaccinationProgramNextTaskSrv({
  programLink = {},
  animalDoc = {},
  eventDate = "",
  doseType = ""
} = {}) {
  if (programLink.linked !== true) {
    return null;
  }

  const baseDate =
    String(eventDate || "")
      .trim()
      .slice(0, 10);

  if (
    !/^\d{4}-\d{2}-\d{2}$/.test(
      baseDate
    )
  ) {
    return null;
  }

  const currentDoseType =
    String(
      doseType ||
      programLink.doseType ||
      ""
    ).trim();

  const doseSchedule =
    Array.isArray(
      programLink.doseSchedule
    )
      ? programLink.doseSchedule
          .filter(step =>
            step &&
            typeof step === "object"
          )
      : [];

  const currentIndex =
    doseSchedule.findIndex(
      step =>
        String(
          step.doseType || ""
        ).trim() === currentDoseType
    );

  let nextStep =
    currentIndex >= 0
      ? (
          doseSchedule[
            currentIndex + 1
          ] ||
          null
        )
      : null;

  if (
    !nextStep &&
    currentDoseType === "periodic"
  ) {
    nextStep =
      doseSchedule.find(
        step =>
          String(
            step.timingBasis || ""
          ).trim() === "repeat"
      ) ||
      null;
  }

  if (
    !nextStep &&
    Number(
      programLink.repeatEvery || 0
    ) > 0 &&
    String(
      programLink.repeatUnit || ""
    ).trim()
  ) {
    nextStep = {
      doseType:
        currentDoseType ||
        String(
          programLink.doseType || ""
        ).trim(),

      doseTypeLabel:
        String(
          programLink.doseTypeLabel || ""
        ).trim(),

      timingBasis: "repeat",

      timingValue:
        Number(
          programLink.repeatEvery || 0
        ),

      timingUnit:
        String(
          programLink.repeatUnit || ""
        ).trim()
    };
  }

  if (!nextStep) {
    return null;
  }

  const timingBasis =
    String(
      nextStep.timingBasis || ""
    ).trim();

  const timingValue =
    Number(
      nextStep.timingValue || 0
    );

  const timingUnit =
    String(
      nextStep.timingUnit || ""
    ).trim();

  let dueDate = "";

  if (
    timingBasis ===
      "after_previous_dose" ||
    timingBasis === "repeat"
  ) {
    dueDate =
      vaccinationYmdAddUnitSrv(
        baseDate,
        timingValue,
        timingUnit
      );
  }

  if (
    timingBasis ===
      "before_expected_calving"
  ) {
    const expectedCalvingDate =
      vaccinationAnimalExpectedCalvingDateSrv(
        animalDoc
      );

    if (!expectedCalvingDate) {
      return null;
    }

    dueDate =
      vaccinationYmdSubtractUnitSrv(
        expectedCalvingDate,
        timingValue,
        timingUnit
      );
  }

  if (
    !/^\d{4}-\d{2}-\d{2}$/.test(
      dueDate
    )
  ) {
    return null;
  }

  const advanceNoticeDays =
    Math.max(
      0,
      Math.min(
        90,
        Number(
          programLink.advanceNoticeDays ??
          14
        ) || 0
      )
    );

  const nextDoseType =
    String(
      nextStep.doseType ||
      currentDoseType ||
      programLink.doseType ||
      ""
    ).trim();

  const nextDoseTypeLabel =
    String(
      nextStep.doseTypeLabel ||
      (
        doseSchedule.find(
          step =>
            String(
              step.doseType || ""
            ).trim() ===
            nextDoseType
        )?.doseTypeLabel
      ) ||
      programLink.doseTypeLabel ||
      ""
    ).trim();

  return {
    dueDate,

    alertFromDate:
      vaccinationYmdAddDaysSrv(
        dueDate,
        -advanceNoticeDays
      ),

    windowStart: dueDate,

    windowEnd:
      vaccinationYmdAddDaysSrv(
        dueDate,
        6
      ),

    doseType:
      nextDoseType,

    doseTypeLabel:
      nextDoseTypeLabel,

    timingBasis,
    timingValue,
    timingUnit,

    advanceNoticeDays
  };
}

function vaccinationBuildProgramTaskWriteSrv({
  uid,
  animalNumber,
  animalId = "",
  animalDoc = {},
  eventDate,
  eventId,
  campaignId = "",
  programContext = {},
  programLink = {},
  doseType
} = {}) {
  if (
    programLink.linked !== true
  ) {
    return null;
  }

  const num =
    calvingNormDigitsOnlySrv(
      animalNumber
    );

  const programMode =
    vaccinationProgramModeNormSrv(
      programLink.programMode ||
      programContext.programMode
    );

  const programRowId =
    String(
      programLink.programRowId || ""
    ).trim();

  if (
    !db ||
    !uid ||
    !num ||
    !programMode ||
    !programRowId
  ) {
    return null;
  }

  const taskId =
    vaccinationProgramTaskIdSrv({
      uid,
      animalNumber: num,
      programMode,
      programRowId
    });

  const taskRef =
    db.collection("tasks").doc(taskId);

  const nextTask =
    vaccinationProgramNextTaskSrv({
      programLink,
      animalDoc,
      eventDate,
      doseType
    });

  const common = {
    userId: uid,

    animalId:
      String(animalId || "").trim(),

    animalNumber: num,

    type: "task",
    taskType: "vaccination",

    engine:
      "vaccination_program_v1",

    programMode,

    programLabel:
      String(
        programContext.programLabel ||
        (
          programMode === "farm"
            ? "برنامج المزرعة"
            : "برنامج مُرَبِّيك"
        )
      ).trim(),

    programRowId,

    vaccinationProgramVersion:
      Number(
        programLink
          .vaccinationProgramVersion ||
        0
      ),

    farmProgramVersion:
      Number(
        programLink
          .farmProgramVersion ||
        0
      ),

    murabbikProgramVersion:
      Number(
        programLink
          .murabbikProgramVersion ||
        0
      ),

    vaccineCode:
      String(
        programLink.vaccineCode || ""
      ).trim(),

    vaccine:
      String(
        programLink.vaccine || ""
      ).trim(),

    vaccineKey:
      String(
        programLink.vaccineCode ||
        programLink.vaccine ||
        ""
      ).trim(),

    programSection:
      String(
        programLink.programSection || ""
      ).trim(),

    programSectionLabel:
      String(
        programLink
          .programSectionLabel || ""
      ).trim(),

    vaccineForm:
      String(
        programLink.vaccineForm || ""
      ).trim(),

    vaccineFormLabel:
      String(
        programLink
          .vaccineFormLabel || ""
      ).trim(),

    campaignId:
      String(campaignId || "").trim(),

    sourceEventId:
      String(eventId || "").trim(),

    basedOnEventDate:
      String(eventDate || "")
        .trim()
        .slice(0, 10),

    source:
      "server:vaccination-program-task-v1",

    updatedAt:
      admin.firestore.FieldValue
        .serverTimestamp()
  };

  if (!nextTask) {
    const currentDoseType =
      String(
        doseType ||
        programLink.doseType ||
        ""
      ).trim();

    const doseSchedule =
      Array.isArray(
        programLink.doseSchedule
      )
        ? programLink.doseSchedule
            .filter(step =>
              step &&
              typeof step === "object"
            )
        : [];

    const currentIndex =
      doseSchedule.findIndex(
        step =>
          String(
            step.doseType || ""
          ).trim() === currentDoseType
      );

    const currentStep =
      currentIndex >= 0
        ? doseSchedule[currentIndex]
        : null;

    const isOneTimeDose =
      programLink.oneTime === true ||
      programLink.onceLifetime === true ||
      String(
        programLink.cycle || ""
      ).trim() === "once_lifetime" ||
      String(
        currentStep?.cycle || ""
      ).trim() === "once_lifetime";

    if (isOneTimeDose) {
      return {
        taskId,
        taskRef,

        payload: {
          ...common,

          dueDate: "",
          alertFromDate: "",
          windowStart: "",
          windowEnd: "",

          doseType: "",
          doseTypeLabel: "",

          status: "completed",
          done: true,

          completionReason:
            "once_lifetime_completed",

          completedByEventId:
            String(eventId || "").trim(),

          completedEventDate:
            String(eventDate || "")
              .trim()
              .slice(0, 10),

          completedAt:
            admin.firestore.FieldValue
              .serverTimestamp()
        },

        publicTask: null
      };
    }

    let configuredNextStep =
      currentIndex >= 0
        ? (
            doseSchedule[
              currentIndex + 1
            ] || null
          )
        : null;

    if (
      !configuredNextStep &&
      currentDoseType === "periodic"
    ) {
      configuredNextStep =
        doseSchedule.find(
          step =>
            String(
              step.timingBasis || ""
            ).trim() === "repeat"
        ) || null;
    }

    const needsExpectedCalvingDate =
      String(
        configuredNextStep
          ?.timingBasis || ""
      ).trim() ===
        "before_expected_calving" &&
      !vaccinationAnimalExpectedCalvingDateSrv(
        animalDoc
      );

    const attentionCode =
      needsExpectedCalvingDate
        ? "expected_calving_date_required"
        : "next_vaccination_date_unresolved";

    const attentionMessage =
      needsExpectedCalvingDate
        ? "يلزم تاريخ الولادة المتوقع لحساب موعد الجرعة التالية."
        : "تعذّر حساب موعد الجرعة التالية من بيانات البرنامج الحالية.";

    const unresolvedDoseType =
      String(
        configuredNextStep?.doseType ||
        currentDoseType ||
        programLink.doseType ||
        ""
      ).trim();

    const unresolvedDoseTypeLabel =
      String(
        configuredNextStep
          ?.doseTypeLabel ||
        programLink.doseTypeLabel ||
        ""
      ).trim();

    const payload = {
      ...common,

      dueDate: "",
      alertFromDate: "",
      windowStart: "",
      windowEnd: "",

      doseType:
        unresolvedDoseType,

      doseTypeLabel:
        unresolvedDoseTypeLabel,

      status: "needs_data",
      done: false,

      attentionCode,
      attentionMessage,

      requiredField:
        needsExpectedCalvingDate
          ? "expectedCalvingDate"
          : "",

      completedByEventId: "",
      completedEventDate: "",
      completedAt: null
    };

    return {
      taskId,
      taskRef,
      payload,

      publicTask: {
        taskId,

        status:
          payload.status,

        attentionCode:
          payload.attentionCode,

        attentionMessage:
          payload.attentionMessage,

        programMode:
          payload.programMode,

        programRowId:
          payload.programRowId,

        vaccineCode:
          payload.vaccineCode,

        vaccine:
          payload.vaccine,

        doseType:
          payload.doseType
      }
    };
  }

  const payload = {
    ...common,

    ...nextTask,

    status: "pending",
    done: false,

    completedByEventId: "",
    completedEventDate: "",
    completedAt: null
  };

  return {
    taskId,
    taskRef,
    payload,

    publicTask: {
      taskId,

      dueDate:
        payload.dueDate,

      alertFromDate:
        payload.alertFromDate,

      programMode:
        payload.programMode,

      programRowId:
        payload.programRowId,

      vaccineCode:
        payload.vaccineCode,

      vaccine:
        payload.vaccine,

      doseType:
        payload.doseType
    }
  };
}
// ============================================================
//                 API: VACCINATION SAVE ONLY
//                 حفظ التحصين من السيرفر فقط — فردي/جماعي + Tasks
// ============================================================

function vaccinationSaveRowsFromBodySrv(body = {}) {
  if (Array.isArray(body.accepted) && body.accepted.length) return body.accepted;
  if (Array.isArray(body.rows) && body.rows.length) return body.rows;

  const rawNumbers =
    body.animalNumbers ||
    body.numbers ||
    body.selectedNumbers ||
    body.groupNumbers ||
    body.animals ||
    body.animalNumber ||
    body.number ||
    "";

  return vaccinationParseNumbersSrv(rawNumbers).map(n => ({
    animalNumber: n,
    animalId: ""
  }));
}

function vaccinationRequiredSrv(v) {
  return !(v === undefined || v === null || String(v).trim() === "");
}

app.post("/api/vaccination/save", requireUserId, async (req, res) => {
  try {
    if (!db) {
      return res.status(503).json({
        ok: false,
       message: "❌ تعذّر حفظ التحصين الآن. حاول مرة أخرى.",
        savedCount: 0,
        rejectedCount: 0,
        saved: [],
        rejected: []
      });
    }

        const uid = req.userId;
    const body = req.body || {};

    const requestedProgramMode =
      vaccinationProgramModeNormSrv(
        body.programMode
      );

    const programContext =
      requestedProgramMode
        ? await vaccinationSaveProgramContextSrv(
            uid,
            requestedProgramMode
          )
        : await vaccinationReadProgramContextSrv(
            uid
          );

    if (!programContext.programMode) {
      return res.status(400).json({
        ok: false,

        message:
          "❌ اختر برنامج المزرعة أو برنامج مُرَبِّيك الخبير.",

        programContext,

        savedCount: 0,
        rejectedCount: 0,
        saved: [],
        rejected: []
      });
    }
    const programLink =
  await vaccinationResolveProgramRowSrv({
    uid,
    programContext,
    body
  });

if (!programLink.ok) {
  return res.status(409).json({
    ok: false,

    message:
      programLink.message ||
     "❌ تعذّر ربط التحصين بالبرنامج المختار.",

    programContext,

    savedCount: 0,
    rejectedCount: 0,
    saved: [],
    rejected: []
  });
}
    const eventDate = String(
      body.eventDate ||
      body.date ||
      ""
    ).trim().slice(0, 10);

  const vaccine = String(
  programLink.linked
    ? programLink.vaccine
    : (
        body.vaccine ||
        body.vaccineName ||
        ""
      )
).trim();

const vaccineCode = String(
  programLink.vaccineCode ||
  body.vaccineCode ||
  ""
).trim();

const programRowId = String(
  programLink.programRowId ||
  body.programRowId ||
  ""
).trim();

    const doseType = String(
  programLink.linked
    ? programLink.doseType
    : (body.doseType || "")
).trim();
    const notes = String(body.notes || "").trim();
    const campaignId = String(body.campaignId || "").trim();

    const rows = vaccinationSaveRowsFromBodySrv(body);

    if (!rows.length) {
      return res.status(400).json({
        ok: false,
        message: "❌ أدخل رقم حيوان واحدًا على الأقل.",
        savedCount: 0,
        rejectedCount: 0,
        saved: [],
        rejected: []
      });
    }

    if (!calvingIsDateSrv(eventDate)) {
      return res.status(400).json({
        ok: false,
        message: "❌ أدخل تاريخ تحصين صحيحًا.",
        savedCount: 0,
        rejectedCount: rows.length,
        saved: [],
        rejected: rows.map(r => ({
          animalNumber: calvingNormDigitsOnlySrv(r.animalNumber || ""),
          reason: "أدخل تاريخ تحصين صحيحًا."
        }))
      });
    }

    if (!vaccinationRequiredSrv(vaccine)) {
      return res.status(400).json({
        ok: false,
       message: "❌ اختر نوع التحصين.",
        savedCount: 0,
        rejectedCount: rows.length,
        saved: [],
        rejected: rows.map(r => ({
          animalNumber: calvingNormDigitsOnlySrv(r.animalNumber || ""),
          reason: "اختر نوع التحصين."
        }))
      });
    }

    if (!vaccinationRequiredSrv(doseType)) {
      return res.status(400).json({
        ok: false,
        message: "❌ اختر نوع الجرعة.",
        savedCount: 0,
        rejectedCount: rows.length,
        saved: [],
        rejected: rows.map(r => ({
        animalNumber: calvingNormDigitsOnlySrv(r.animalNumber || ""),
        reason: "اختر نوع الجرعة."
        }))
      });
    }

    const saved = [];
    const rejected = [];

    for (const row of rows) {
      const animalNumber = calvingNormDigitsOnlySrv(row.animalNumber || row.number || "");

      if (!animalNumber) {
        rejected.push({
          animalNumber: "",
          reason: "رقم الحيوان غير صحيح."
        });
        continue;
      }

      let animalId = String(row.animalId || "").trim();
      let animalDoc = null;

      if (animalId) {
        const snap = await db.collection("animals").doc(animalId).get();
        if (snap.exists) {
          animalDoc = snap.data() || {};
        }
      }

      if (!animalDoc) {
        const animal = await fetchAnimalByNumberForCalvingGateSrv(uid, animalNumber);
        if (!animal) {
          rejected.push({
            animalNumber,
            reason: "لم أجد الحيوان في حسابك. راجع الرقم."
          });
          continue;
        }

        animalId = animal.id || "";
        animalDoc = animal.data || {};
      }

      const status = String(animalDoc.status || "active").trim().toLowerCase();

      if (status === "inactive" || status === "archived") {
        rejected.push({
          animalNumber,
          reason: "الحيوان خارج القطيع، لذلك لا يمكن تسجيل تحصين له."
        });
        continue;
      }

      const duplicated = await vaccinationHasSameDaySrv(
        uid,
        animalNumber,
        eventDate,
        vaccine
      );

      if (duplicated) {
        rejected.push({
          animalNumber,
          reason: "سبق تسجيل التحصين نفسه لهذا الحيوان في التاريخ نفسه."
        });
        continue;
      }
      const dueWarning = null;
const payload = {
  userId: uid,

  animalId,
  animalNumber,

  createdAt: admin.firestore.FieldValue.serverTimestamp(),

    date: eventDate,
  doseType,
  eventDate,

  vaccinationProgramMode:
    programContext.programMode,

  vaccinationProgramLabel:
    programContext.programLabel,

  eventType: "تحصين",
  source: "server:/api/vaccination/save",
  type: "vaccination",
  vaccine
};
if (programLink.linked) {
  payload.programRowId = programRowId;
  payload.vaccineCode = vaccineCode;
  payload.programSection =
    programLink.programSection || "";
  payload.programSectionLabel =
    programLink.programSectionLabel || "";
  payload.vaccineForm =
    programLink.vaccineForm || "";
  payload.vaccineFormLabel =
    programLink.vaccineFormLabel || "";
   payload.vaccinationProgramVersion = Number(
    programLink.vaccinationProgramVersion || 0
  );

  if (
    programLink.programMode === "farm"
  ) {
    payload.farmProgramVersion = Number(
      programLink.farmProgramVersion || 0
    );
  }

  if (
    programLink.programMode ===
      "murabbik_default"
  ) {
    payload.murabbikProgramVersion = Number(
      programLink.murabbikProgramVersion || 0
    );
  }
}
if (notes) {
  payload.notes = notes;
}

if (campaignId) {
  payload.campaignId = campaignId;
}
if (dueWarning) {
  payload.warnings = [dueWarning];
  payload.warning = dueWarning.message || "";
  payload.warningFlags = [dueWarning.code || "vaccination_due_timing"];
}
const vaccineKeyForDoc = String(vaccine || "")
  .trim()
  .replace(/[^\p{L}\p{N}]+/gu, "_")
  .replace(/^_+|_+$/g, "");

const vaccinationEventId = [
  "vaccination",
  uid,
  animalNumber,
  eventDate,
  vaccineKeyForDoc || "vaccine"
].join("__");

const eventRef = db.collection("events").doc(vaccinationEventId);

const existingEventSnap = await eventRef.get();

if (existingEventSnap.exists) {
  rejected.push({
    animalNumber,
    reason: "سبق تسجيل التحصين نفسه لهذا الحيوان في التاريخ نفسه."
  });
  continue;
}

const taskWrite =
  vaccinationBuildProgramTaskWriteSrv({
    uid,

    animalNumber,
    animalId,
    animalDoc,

    eventDate,
    eventId:
      eventRef.id,

    campaignId,

    programContext,
    programLink,
    doseType
  });

const writeBatch =
  db.batch();

writeBatch.set(
  eventRef,
  payload
);

if (animalId) {
  writeBatch.set(
    db.collection("animals").doc(
      animalId
    ),
    {
      lastVaccinationDate:
        eventDate,

      lastVaccine:
        vaccine,

      lastVaccinationDoseType:
        doseType,

      ...(programLink.linked
        ? {
            lastVaccineCode:
              vaccineCode,

            lastVaccinationProgramRowId:
              programRowId
          }
        : {}),

      updatedAt:
        admin.firestore.FieldValue
          .serverTimestamp()
    },
    {
      merge: true
    }
  );
}

if (taskWrite) {
  writeBatch.set(
    taskWrite.taskRef,
    taskWrite.payload,
    {
      merge: true
    }
  );
}

await writeBatch.commit();

const tasks =
  taskWrite?.publicTask
    ? [taskWrite.publicTask]
    : [];
saved.push({
  animalNumber,
  animalId,
  eventId: eventRef.id,
  eventDate,
   vaccine,
  doseType,

  vaccinationProgramMode:
    programContext.programMode,

  vaccinationProgramLabel:
    programContext.programLabel,

  warning: dueWarning?.message || "",
  warnings: dueWarning ? [dueWarning] : [],
  tasksCount: tasks.length,
  tasks
});
    }

    return res.json({
      ok: saved.length > 0,
 message: saved.length
  ? (
      rejected.length
        ? `✅ سجلت التحصين لعدد ${saved.length} حيوانات، ولم أتمكن من تسجيله لعدد ${rejected.length}.`
        : saved.length === 1
          ? `✅ سجلت التحصين للحيوان رقم ${saved[0].animalNumber} بنجاح.`
          : `✅ سجلت التحصين لعدد ${saved.length} حيوانات بنجاح.`
    )
  : "❌ لم أتمكن من تسجيل التحصين لأي حيوان.",
           programContext,

      savedCount: saved.length,
      rejectedCount: rejected.length,

      saved,
      rejected,
      redirectUrl: saved.length === 1
        ? `/event-list.html?number=${encodeURIComponent(saved[0].animalNumber)}`
        : ""
    });

  } catch (e) {
    console.error("vaccination-save", e);

    return res.status(500).json({
      ok: false,
      message: "❌ تعذّر حفظ التحصين الآن. حاول مرة أخرى.",
      savedCount: 0,
      rejectedCount: 0,
      saved: [],
      rejected: []
    });
  }
});
// ============================================================
//                 API: DAILY MILK HELPERS
//                 السيرفر يجهز القرار + العرض بالكامل
// ============================================================

function dailyMilkParseNumbersSrv(raw) {
  let arr = [];

  if (Array.isArray(raw)) {
    arr = raw;
  } else {
    const txt = String(raw || "").trim();
    if (!txt) return [];
    arr = txt.split(/\n|,|;|،|\s+/g);
  }

  return [...new Set(
    arr
      .map(x => calvingNormDigitsOnlySrv(x))
      .filter(Boolean)
  )];
}

function dailyMilkSpeciesSrv(doc = {}) {
  const raw = String(
    doc.species ||
    doc.animalTypeAr ||
    doc.animalType ||
    doc.type ||
    ""
  ).trim();

  if (/buffalo|جاموس/i.test(raw)) return "جاموس";
  if (/cow|بقر|أبقار/i.test(raw)) return "أبقار";

  return raw || "أبقار";
}

function dailyMilkKindSrv(species) {
  return String(species || "").trim() === "جاموس" ? "buffalo" : "cow";
}

function dailyMilkIsOutOfHerdSrv(doc = {}) {
  const st = String(doc.status || "active").trim().toLowerCase();
  return st === "inactive" || st === "archived";
}

function dailyMilkNumStrictSrv(v) {
  if (v === undefined || v === null || String(v).trim() === "") return 0;

  const n = Number(String(v).trim().replace(",", "."));
  return Number.isFinite(n) ? n : NaN;
}

function dailyMilkRowsFromBodySrv(body = {}) {
  if (Array.isArray(body.rows) && body.rows.length) return body.rows;
  if (Array.isArray(body.items) && body.items.length) return body.items;

  const rawNumbers =
    body.animalNumbers ||
    body.numbers ||
    body.selectedNumbers ||
    body.groupNumbers ||
    body.animals ||
    body.animalNumber ||
    body.number ||
    "";

  const nums = dailyMilkParseNumbersSrv(rawNumbers);

  return nums.map(n => ({
    animalNumber: n,
    animalId: "",
    milkS1: body.milkS1 ?? body.s1 ?? body.session1,
    milkS2: body.milkS2 ?? body.s2 ?? body.session2,
    milkS3: body.milkS3 ?? body.s3 ?? body.session3
  }));
}

async function dailyMilkHasSameDaySrv(uid, animalNumber, eventDate) {
  const num = calvingNormDigitsOnlySrv(animalNumber);
  const dt = String(eventDate || "").trim().slice(0, 10);

  if (!db || !uid || !num || !calvingIsDateSrv(dt)) return false;

  const fixedId = ["daily_milk", uid, num, dt].join("__");
  const fixedSnap = await db.collection("events").doc(fixedId).get();
  if (fixedSnap.exists) return true;

  const snap = await db.collection("events")
    .where("userId", "==", uid)
    .where("animalNumber", "==", num)
    .limit(120)
    .get();

  let found = false;

  snap.forEach(docSnap => {
    const ev = docSnap.data() || {};
    const d = String(ev.eventDate || ev.date || "").trim().slice(0, 10);

    const t = String(
      ev.eventTypeNorm ||
      ev.type ||
      ev.eventType ||
      ""
    ).trim().toLowerCase();

    const isDailyMilk =
      t === "daily_milk" ||
      t === "لبن يومي" ||
      t.includes("daily_milk");

    if (isDailyMilk && d === dt) {
      found = true;
    }
  });

  return found;
}

function dailyMilkSessionSpecSrv(kind) {
  if (kind === "buffalo") {
    return {
      sessionCount: 2,
      showThirdMilking: false,
      sessionLabels: ["حلبة صباح (كجم)", "حلبة مساء (كجم)"],
      inputs: [
        { key: "milkS1", label: "حلبة صباح (كجم)", visible: true, disabled: false },
        { key: "milkS2", label: "حلبة مساء (كجم)", visible: true, disabled: false },
        { key: "milkS3", label: "حلبة 3 (كجم)", visible: false, disabled: true }
      ]
    };
  }

  return {
    sessionCount: 3,
    showThirdMilking: true,
    sessionLabels: ["حلبة 1 (كجم)", "حلبة 2 (كجم)", "حلبة 3 (كجم)"],
    inputs: [
      { key: "milkS1", label: "حلبة 1 (كجم)", visible: true, disabled: false },
      { key: "milkS2", label: "حلبة 2 (كجم)", visible: true, disabled: false },
      { key: "milkS3", label: "حلبة 3 (كجم)", visible: true, disabled: false }
    ]
  };
}

function dailyMilkRejectedUiRowSrv(animalNumber, reason) {
  return {
    animalNumber: calvingNormDigitsOnlySrv(animalNumber || ""),
    number: calvingNormDigitsOnlySrv(animalNumber || ""),
    eligible: false,
    canEdit: false,
    canSave: false,
    reason: String(reason || "مرفوض"),
    species: "",
    speciesLabel: "مرفوض",
    kind: "",
    sessionCount: 0,
    showThirdMilking: false,
    sessionLabels: [],
    inputs: [
      { key: "milkS1", label: "حلبة 1", visible: true, disabled: true },
      { key: "milkS2", label: "حلبة 2", visible: true, disabled: true },
      { key: "milkS3", label: "حلبة 3", visible: true, disabled: true }
    ]
  };
}

function dailyMilkAcceptedUiRowSrv(item = {}) {
  const species = String(item.species || "").trim() || "أبقار";
  const kind = String(item.kind || dailyMilkKindSrv(species)).trim();
  const spec = dailyMilkSessionSpecSrv(kind);

  return {
    animalNumber: calvingNormDigitsOnlySrv(item.animalNumber || item.number || ""),
    number: calvingNormDigitsOnlySrv(item.animalNumber || item.number || ""),
    animalId: String(item.animalId || "").trim(),
    eligible: true,
    canEdit: true,
    canSave: true,
    reason: "",
    species,
    speciesLabel: species,
    kind,
    sessionCount: spec.sessionCount,
    showThirdMilking: spec.showThirdMilking,
    sessionLabels: spec.sessionLabels,
    inputs: spec.inputs
  };
}

function dailyMilkBuildGateUiSrv({ accepted = [], rejected = [], message = "", eventDate = "" } = {}) {
  const acceptedRows = accepted.map(dailyMilkAcceptedUiRowSrv);
  const rejectedRows = rejected.map(r => dailyMilkRejectedUiRowSrv(r.animalNumber || r.number, r.reason));

  const rows = [...acceptedRows, ...rejectedRows];
  const first = acceptedRows[0] || null;
  const canSave = acceptedRows.length > 0;

  return {
    screen: "daily_milk",
    mode: rows.length > 1 ? "bulk" : "single",
    eventDate: String(eventDate || "").slice(0, 10),
    status: canSave ? "success" : "error",
    message: message || (canSave ? "✅ تم التحقق — أكمل إدخال اللبن." : "❌ لا يوجد رقم مؤهل لتسجيل اللبن."),
    canSave,
    acceptedCount: acceptedRows.length,
    rejectedCount: rejectedRows.length,
    rows,

    single: first ? {
      animalNumber: first.animalNumber,
      animalId: first.animalId,
      species: first.species,
      speciesLabel: first.speciesLabel,
      kind: first.kind,
      sessionCount: first.sessionCount,
      showThirdMilking: first.showThirdMilking,
      sessionLabels: first.sessionLabels,
      inputs: first.inputs
    } : null,

    bulk: {
      rows,
      columns: [
        { key: "animalNumber", label: "رقم الحيوان", visible: true },
        { key: "speciesLabel", label: "النوع", visible: true },
        { key: "milkS1", label: "حلبة 1", visible: true },
        { key: "milkS2", label: "حلبة 2", visible: true },
        { key: "milkS3", label: "حلبة 3", visible: true },
        { key: "total", label: "الإجمالي", visible: true }
      ]
    }
  };
}

function dailyMilkBuildSaveUiSrv({ saved = [], rejected = [], message = "", eventDate = "" } = {}) {
  const savedCount = saved.length;
  const rejectedCount = rejected.length;
  const first = saved[0] || null;

  const redirectUrl = savedCount === 1
    ? `/event-list.html?number=${encodeURIComponent(first.animalNumber)}`
    : "/dashboard.html";

  return {
    screen: "daily_milk",
    status: savedCount ? "success" : "error",
    message: message || (savedCount ? "✅ تم حفظ اللبن اليومي بنجاح" : "❌ لم يتم حفظ أي سجل لبن."),
    savedCount,
    rejectedCount,
    canRedirect: savedCount > 0,
    redirectUrl,
    saved: saved.map(x => ({
      animalNumber: x.animalNumber,
      animalId: x.animalId,
      eventId: x.eventId,
      eventDate: x.eventDate,
      milkKg: x.milkKg
    })),
    rejected: rejected.map(x => ({
      animalNumber: x.animalNumber || "",
      reason: x.reason || "تعذّر الحفظ"
    })),
    eventDate: String(eventDate || "").slice(0, 10)
  };
}
function dailyMilkFormatTotalSrv(v) {
  const n = Number(v);
  if (!Number.isFinite(n) || n <= 0) return "—";
  return Number.isInteger(n) ? String(n) : n.toFixed(1);
}

function dailyMilkPreviewRowSrv(row = {}, kind = "cow") {
  const s1 = dailyMilkNumStrictSrv(row.milkS1 ?? row.s1 ?? row.session1);
  const s2 = dailyMilkNumStrictSrv(row.milkS2 ?? row.s2 ?? row.session2);
  const s3 = dailyMilkNumStrictSrv(row.milkS3 ?? row.s3 ?? row.session3);

  if (![s1, s2, s3].every(Number.isFinite)) {
    return {
      ok: false,
      milkKg: null,
      totalText: "—",
      reason: "أدخل كمية لبن رقمية صحيحة."
    };
  }

  if (s1 < 0 || s2 < 0 || s3 < 0) {
    return {
      ok: false,
      milkKg: null,
      totalText: "—",
     message: "❌ تعذّر حساب إجمالي اللبن الآن. حاول مرة أخرى.",
    };
  }

  const milkKg = kind === "buffalo"
    ? Number((s1 + s2).toFixed(1))
    : Number((s1 + s2 + s3).toFixed(1));

  return {
    ok: true,
    milkKg,
    totalText: dailyMilkFormatTotalSrv(milkKg),
    reason: ""
  };
}

function dailyMilkBuildPreviewUiSrv({ rows = [], message = "" } = {}) {
  const safeRows = Array.isArray(rows) ? rows : [];

  return {
    screen: "daily_milk",
    mode: safeRows.length > 1 ? "bulk" : "single",
    status: "info",
    message: message || "",
    rows: safeRows,
    single: safeRows[0] || null
  };
}
// ============================================================
//                 API: DAILY MILK GATE ONLY
//                 السيرفر يجهز أهلية + UI كامل
// ============================================================

app.post("/api/daily-milk/gate", requireUserId, async (req, res) => {
  try {
    if (!db) {
      const ui = dailyMilkBuildGateUiSrv({
       message: "❌ تعذّر فحص بيانات اللبن اليومي الآن. حاول مرة أخرى."
      });

      return res.status(503).json({
        ok: false,
        allowed: false,
        stage: "firestore_disabled",
        message: ui.message,
        acceptedCount: 0,
        rejectedCount: 0,
        accepted: [],
        valid: [],
        rejected: [],
        ui
      });
    }

    const uid = req.userId;
    const body = req.body || {};

    const eventDate = String(
      body.eventDate ||
      body.date ||
      ""
    ).trim().slice(0, 10);

    const rawNumbers =
      body.animalNumbers ||
      body.numbers ||
      body.selectedNumbers ||
      body.groupNumbers ||
      body.animals ||
      body.animalNumber ||
      body.number ||
      "";

    const numbers = dailyMilkParseNumbersSrv(rawNumbers);

    if (!numbers.length || !eventDate) {
      const ui = dailyMilkBuildGateUiSrv({
        message: "أدخل رقم الحيوان وتاريخ تسجيل اللبن.",
        eventDate
      });

      return res.json({
        ok: true,
        allowed: false,
        silent: true,
        stage: "missing_basic",
        message: ui.message,
        acceptedCount: 0,
        rejectedCount: 0,
        accepted: [],
        valid: [],
        rejected: [],
        ui
      });
    }

    if (!calvingIsDateSrv(eventDate)) {
      const rejected = numbers.map(n => ({
        animalNumber: String(n || ""),
        reason: "أدخل تاريخ تسجيل لبن صحيحًا."
      }));

      const ui = dailyMilkBuildGateUiSrv({
        rejected,
        message: "❌ أدخل تاريخ تسجيل لبن صحيحًا.",
        eventDate
      });

      return res.status(400).json({
        ok: false,
        allowed: false,
        stage: "invalid_date",
        message: ui.message,
        acceptedCount: 0,
        rejectedCount: rejected.length,
        accepted: [],
        valid: [],
        rejected,
        ui
      });
    }

    const accepted = [];
    const rejected = [];

    for (const rawNum of numbers) {
      const animalNumber = calvingNormDigitsOnlySrv(rawNum);

      if (!animalNumber) {
        rejected.push({
          animalNumber: String(rawNum || ""),
          reason: "رقم الحيوان غير صحيح."
        });
        continue;
      }

      const animal = await fetchAnimalByNumberForCalvingGateSrv(uid, animalNumber);

      if (!animal) {
        rejected.push({
          animalNumber,
          reason: "لم أجد الحيوان في حسابك. راجع الرقم."
        });
        continue;
      }

      const doc = animal.data || {};

      if (dailyMilkIsOutOfHerdSrv(doc)) {
        rejected.push({
          animalNumber,
          reason: "الحيوان خارج القطيع، لذلك لا يمكن تسجيل اللبن له."
        });
        continue;
      }

      const duplicated = await dailyMilkHasSameDaySrv(uid, animalNumber, eventDate);

      if (duplicated) {
        rejected.push({
          animalNumber,
          reason: "سبق تسجيل اللبن لهذا الحيوان في التاريخ نفسه."
        });
        continue;
      }

      const species = dailyMilkSpeciesSrv(doc);
      const kind = dailyMilkKindSrv(species);

      accepted.push({
        animalNumber,
        number: animalNumber,
        animalId: animal.id || "",
        species,
        kind
      });
    }

    const acceptedCount = accepted.length;
    const rejectedCount = rejected.length;
    const allowed = acceptedCount > 0;

    const message = allowed
  ? (
      rejectedCount
        ? `راجعت ${numbers.length} حيوانًا: يمكن تسجيل اللبن لـ${acceptedCount}، ولا يمكن تسجيله لـ${rejectedCount}.`
        : acceptedCount === 1
          ? `✅ راجعت بيانات الحيوان رقم ${accepted[0].animalNumber}، ويمكنك إدخال كميات اللبن الآن.`
          : `✅ راجعت البيانات، ويمكن تسجيل اللبن لعدد ${acceptedCount} حيوانات.`
    )
  : (rejected[0]?.reason || "❌ لا يمكن تسجيل اللبن لأي من الأرقام المدخلة.");
    const ui = dailyMilkBuildGateUiSrv({
      accepted,
      rejected,
      message,
      eventDate
    });

    return res.json({
      ok: true,
      allowed,
      stage: "daily_milk_gate",
      message,
      acceptedCount,
      rejectedCount,
      accepted,
      valid: accepted,
      rejected,

      animalNumber: accepted[0]?.animalNumber || "",
      animalId: accepted[0]?.animalId || "",
      species: accepted[0]?.species || "",
      kind: accepted[0]?.kind || "",

      ui
    });

  } catch (e) {
    console.error("daily-milk-gate", e);

    const ui = dailyMilkBuildGateUiSrv({
      message: "❌ تعذّر فحص بيانات اللبن اليومي الآن. حاول مرة أخرى."
    });

    return res.status(500).json({
      ok: false,
      allowed: false,
      stage: "daily_milk_gate_failed",
      message: ui.message,
      acceptedCount: 0,
      rejectedCount: 0,
      accepted: [],
      valid: [],
      rejected: [],
      ui
    });
  }
});
// ============================================================
//                 API: DAILY MILK PREVIEW ONLY
//                 حساب إجمالي اللبن من السيرفر — بدون حفظ
// ============================================================

app.post("/api/daily-milk/preview", requireUserId, async (req, res) => {
  try {
    if (!db) {
      const ui = dailyMilkBuildPreviewUiSrv({
       message: "❌ تعذّر حساب إجمالي اللبن الآن. حاول مرة أخرى.",
        rows: []
      });

      return res.status(503).json({
        ok: false,
        message: ui.message,
        ui
      });
    }

    const uid = req.userId;
    const body = req.body || {};
    const rows = dailyMilkRowsFromBodySrv(body);

    if (!rows.length) {
      const ui = dailyMilkBuildPreviewUiSrv({
        message: "",
        rows: []
      });

      return res.json({
        ok: true,
        message: "",
        ui
      });
    }

    const outRows = [];

    for (const row of rows) {
      const animalNumber = calvingNormDigitsOnlySrv(row.animalNumber || row.number || "");

      if (!animalNumber) {
        outRows.push({
          animalNumber: "",
          milkKg: null,
          totalText: "—",
          ok: false,
          reason: "أدخل رقم الحيوان."
        });
        continue;
      }

      const animal = await fetchAnimalByNumberForCalvingGateSrv(uid, animalNumber);

      if (!animal) {
        outRows.push({
          animalNumber,
          milkKg: null,
          totalText: "—",
          ok: false,
          reason: "لم أجد الحيوان في حسابك. راجع الرقم."
        });
        continue;
      }

      const animalDoc = animal.data || {};
      const species = dailyMilkSpeciesSrv(animalDoc);
      const kind = dailyMilkKindSrv(species);

      const preview = dailyMilkPreviewRowSrv(row, kind);

      outRows.push({
        animalNumber,
        animalId: animal.id || "",
        species,
        kind,
        milkKg: preview.milkKg,
        totalText: preview.totalText,
        ok: preview.ok,
        reason: preview.reason || ""
      });
    }

    const ui = dailyMilkBuildPreviewUiSrv({
      rows: outRows,
      message: ""
    });

    return res.json({
      ok: true,
      message: "",
      rows: outRows,
      ui
    });

  } catch (e) {
    console.error("daily-milk-preview", e);

    const ui = dailyMilkBuildPreviewUiSrv({
      message: "❌ تعذّر حساب إجمالي اللبن الآن. حاول مرة أخرى.",
      rows: []
    });

    return res.status(500).json({
      ok: false,
      message: ui.message,
      ui
    });
  }
});
// ============================================================
//                 API: DAILY MILK IMPORT HELPERS
//                 الصفحة ترفع/ترسل فقط — السيرفر يقرأ ويعاين ويحفظ
// ============================================================

const dailyMilkImportRawParserSrv = express.raw({
  type: (req) => {
    const ct = String(req.headers["content-type"] || "").toLowerCase();
    return (
      ct.includes("multipart/form-data") ||
      ct.includes("text/plain") ||
      ct.includes("text/csv") ||
      ct.includes("application/octet-stream")
    );
  },
  limit: "15mb"
});

function dailyMilkImportLatinDigitsSrv(v) {
  const map = {
    "٠":"0","١":"1","٢":"2","٣":"3","٤":"4","٥":"5","٦":"6","٧":"7","٨":"8","٩":"9",
    "۰":"0","۱":"1","۲":"2","۳":"3","۴":"4","۵":"5","۶":"6","۷":"7","۸":"8","۹":"9"
  };

  return String(v ?? "").replace(/[٠-٩۰-۹]/g, d => map[d] || d);
}

function dailyMilkImportNormAnimalSrv(v) {
  return dailyMilkImportLatinDigitsSrv(v)
    .replace(/[^\d]/g, "")
    .trim();
}

function dailyMilkImportNumSrv(v) {
  const s = dailyMilkImportLatinDigitsSrv(v)
    .trim()
    .replace(",", ".");

  if (!s) return null;

  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

function dailyMilkImportParseMultipartSrv(req) {
  const ct = String(req.headers["content-type"] || "");
  const m = ct.match(/boundary=(?:"([^"]+)"|([^;]+))/i);
  const boundary = m ? (m[1] || m[2] || "").trim() : "";

  const out = {
    fields: {},
    file: null
  };

  if (!boundary || !Buffer.isBuffer(req.body)) return out;

  const raw = req.body.toString("binary");
  const parts = raw.split("--" + boundary);

  for (const part of parts) {
    const p = String(part || "");
    const cut = p.indexOf("\r\n\r\n");
    if (cut < 0) continue;

    const head = p.slice(0, cut);
    let body = p.slice(cut + 4);

    body = body.replace(/\r\n$/, "");
    body = body.replace(/--$/, "");

    const nameM = head.match(/name="([^"]+)"/i);
    const fileM = head.match(/filename="([^"]*)"/i);
    const typeM = head.match(/content-type:\s*([^\r\n]+)/i);

    const name = nameM ? nameM[1] : "";
    if (!name) continue;

    const buf = Buffer.from(body, "binary");

    if (fileM && fileM[1]) {
      out.file = {
        fieldname: name,
        originalname: fileM[1],
        mimetype: typeM ? typeM[1].trim() : "",
        buffer: buf
      };
    } else {
      out.fields[name] = buf.toString("utf8").trim();
    }
  }

  return out;
}

function dailyMilkImportNormalizeHeaderSrv(v) {
  return dailyMilkImportLatinDigitsSrv(v)
    .trim()
    .toLowerCase()
    .replace(/[()]/g, " ")
    .replace(/[\/_-]+/g, " ")
    .replace(/[أإآ]/g, "ا")
    .replace(/[ة]/g, "ه")
    .replace(/\s+/g, " ")
    .trim();
}

function dailyMilkImportSplitLineSrv(line) {
  const raw = dailyMilkImportLatinDigitsSrv(String(line || "").trim());
  if (!raw) return [];

  if (raw.includes("\t")) return raw.split("\t").map(x => x.trim());
  if (raw.includes(";")) return raw.split(";").map(x => x.trim());

  return raw
    .replace(/[،]+/g, ",")
    .split(",")
    .map(x => x.trim());
}

function dailyMilkImportLooksLikeHeaderSrv(line) {
  const s = dailyMilkImportNormalizeHeaderSrv(line);
  if (!s) return false;

  return [
    "رقم الحيوان",
    "رقم",
    "الحيوان",
    "animal",
    "animal number",
    "animal no",
    "animal id",
    "cow id",
    "tag",
    "ear tag",
    "اجمالي",
    "اجمالي اللبن",
    "total",
    "total milk",
    "milk total",
    "yield",
    "حلبه 1",
    "حلبة 1",
    "session 1",
    "milking 1",
    "morning",
    "حلبه 2",
    "حلبة 2",
    "session 2",
    "milking 2",
    "evening",
    "حلبه 3",
    "حلبة 3",
    "session 3",
    "milking 3",
    "night"
  ].some(x => s.includes(x));
}

function dailyMilkImportDetectColumnsSrv(parts = []) {
  const cols = parts.map(dailyMilkImportNormalizeHeaderSrv);

  const out = {
    animalIdx: -1,
    totalIdx: -1,
    s1Idx: -1,
    s2Idx: -1,
    s3Idx: -1
  };

  function has(cell, arr) {
    return arr.some(x => cell === x || cell.includes(x));
  }

  cols.forEach((c, i) => {
    if (out.animalIdx < 0 && has(c, ["رقم الحيوان", "الحيوان", "animal number", "animal no", "animal id", "cow id", "tag", "ear tag", "animal"])) {
      out.animalIdx = i;
      return;
    }

    if (out.s1Idx < 0 && has(c, ["حلبه 1", "حلبة 1", "session 1", "milking 1", "morning", "milk 1"])) {
      out.s1Idx = i;
      return;
    }

    if (out.s2Idx < 0 && has(c, ["حلبه 2", "حلبة 2", "session 2", "milking 2", "evening", "milk 2"])) {
      out.s2Idx = i;
      return;
    }

    if (out.s3Idx < 0 && has(c, ["حلبه 3", "حلبة 3", "session 3", "milking 3", "night", "milk 3"])) {
      out.s3Idx = i;
      return;
    }

    if (out.totalIdx < 0 && has(c, ["اجمالي", "اجمالي اللبن", "total", "total milk", "milk total", "yield", "daily milk", "production"])) {
      out.totalIdx = i;
    }
  });

  return out;
}

function dailyMilkImportReadExcelSrv(file) {
  let XLSX_NODE = null;

  try {
    XLSX_NODE = require("xlsx");
  } catch (_) {
    const err = new Error("تعذّر قراءة ملف Excel على السيرفر.");
    err.code = "XLSX_UNAVAILABLE";
    throw err;
  }

  const workbook = XLSX_NODE.read(file.buffer, { type: "buffer" });
  const names = workbook.SheetNames || [];
  if (!names.length) return "";

  let bestRows = [];
  let bestScore = -1;

  for (const name of names) {
    const sheet = workbook.Sheets[name];
    if (!sheet) continue;

    const rows = XLSX_NODE.utils.sheet_to_json(sheet, {
      header: 1,
      defval: "",
      blankrows: false,
      raw: false
    });

    let score = 0;

    rows.slice(0, 50).forEach(r => {
      const line = (Array.isArray(r) ? r : []).join(",");
      if (dailyMilkImportLooksLikeHeaderSrv(line)) score += 30;

      const n = dailyMilkImportNormAnimalSrv(r?.[0]);
      const nums = (Array.isArray(r) ? r.slice(1) : [])
        .map(dailyMilkImportNumSrv)
        .filter(x => Number.isFinite(x));

      if (n) score += 2;
      score += nums.length;
    });

    if (score > bestScore) {
      bestScore = score;
      bestRows = rows;
    }
  }

  return bestRows
    .map(r => (Array.isArray(r) ? r : []).map(x => String(x ?? "").trim()).join(","))
    .filter(Boolean)
    .join("\n");
}

function dailyMilkImportTextFromReqSrv(req) {
  const ct = String(req.headers["content-type"] || "").toLowerCase();

  if (ct.includes("multipart/form-data")) {
    const mp = dailyMilkImportParseMultipartSrv(req);
    if (mp.file) {
      const name = String(mp.file.originalname || "").toLowerCase();
      const mime = String(mp.file.mimetype || "").toLowerCase();

      const isExcel =
        name.endsWith(".xlsx") ||
        name.endsWith(".xls") ||
        mime.includes("spreadsheet") ||
        mime.includes("excel");

      if (isExcel) return dailyMilkImportReadExcelSrv(mp.file);

      return mp.file.buffer.toString("utf8");
    }

    return String(mp.fields.rawText || mp.fields.text || mp.fields.data || "").trim();
  }

  if (Buffer.isBuffer(req.body)) {
    return req.body.toString("utf8").trim();
  }

  return String(req.body?.rawText || req.body?.text || req.body?.data || "").trim();
}

function dailyMilkImportRowsFromReqSrv(req) {
  if (!Buffer.isBuffer(req.body) && Array.isArray(req.body?.rows)) {
    return req.body.rows;
  }

  const rawText = dailyMilkImportTextFromReqSrv(req);
  return dailyMilkImportParseTextSrv(rawText);
}

function dailyMilkImportParseTextSrv(text) {
  const lines = String(text || "")
    .replace(/\r/g, "")
    .split("\n")
    .map(x => x.trim())
    .filter(Boolean);

  const rows = [];
  let colMap = null;

  for (const line of lines) {
    const parts = dailyMilkImportSplitLineSrv(line);
    if (!parts.length) continue;

    if (!colMap && dailyMilkImportLooksLikeHeaderSrv(line)) {
      colMap = dailyMilkImportDetectColumnsSrv(parts);
      continue;
    }

    let animalNumber = "";
    let milkS1 = 0;
    let milkS2 = 0;
    let milkS3 = 0;
    let importMode = "sessions";

    if (colMap && colMap.animalIdx >= 0) {
      animalNumber = dailyMilkImportNormAnimalSrv(parts[colMap.animalIdx]);

      const total =
        colMap.totalIdx >= 0
          ? dailyMilkImportNumSrv(parts[colMap.totalIdx])
          : null;

      const s1 =
        colMap.s1Idx >= 0
          ? dailyMilkImportNumSrv(parts[colMap.s1Idx])
          : null;

      const s2 =
        colMap.s2Idx >= 0
          ? dailyMilkImportNumSrv(parts[colMap.s2Idx])
          : null;

      const s3 =
        colMap.s3Idx >= 0
          ? dailyMilkImportNumSrv(parts[colMap.s3Idx])
          : null;

      if (Number.isFinite(total) && !Number.isFinite(s1) && !Number.isFinite(s2) && !Number.isFinite(s3)) {
        milkS1 = total;
        milkS2 = 0;
        milkS3 = 0;
        importMode = "total_only";
      } else {
        milkS1 = Number.isFinite(s1) ? s1 : 0;
        milkS2 = Number.isFinite(s2) ? s2 : 0;
        milkS3 = Number.isFinite(s3) ? s3 : 0;
      }
    } else {
      animalNumber = dailyMilkImportNormAnimalSrv(parts[0]);

      const nums = parts
        .slice(1)
        .map(dailyMilkImportNumSrv)
        .filter(x => Number.isFinite(x));

      if (nums.length === 1) {
        milkS1 = nums[0];
        milkS2 = 0;
        milkS3 = 0;
        importMode = "total_only";
      } else {
        milkS1 = nums[0] ?? 0;
        milkS2 = nums[1] ?? 0;
        milkS3 = nums[2] ?? 0;
        importMode = nums.length >= 3 ? "sessions_3" : "sessions_2";
      }
    }

    if (!animalNumber) continue;

    rows.push({
      animalNumber,
      milkS1,
      milkS2,
      milkS3,
      importMode
    });
  }

  return rows;
}

function dailyMilkImportCalcSrv(row = {}, kind = "cow") {
  const s1 = dailyMilkNumStrictSrv(row.milkS1);
  const s2 = dailyMilkNumStrictSrv(row.milkS2);
  const s3 = dailyMilkNumStrictSrv(row.milkS3);

  if (![s1, s2, s3].every(Number.isFinite)) {
    return { ok: false, milkKg: 0, totalText: "—", reason: "أدخل كمية لبن رقمية صحيحة." };
  }

  if (s1 < 0 || s2 < 0 || s3 < 0) {
    return { ok: false, milkKg: 0, totalText: "—", reason: "كمية اللبن لا يمكن أن تكون سالبة." };
  }

  const importMode = String(row.importMode || "").trim();

  const milkKg =
    importMode === "total_only"
      ? Number(s1.toFixed(1))
      : (
          kind === "buffalo"
            ? Number((s1 + s2).toFixed(1))
            : Number((s1 + s2 + s3).toFixed(1))
        );

  if (!Number.isFinite(milkKg) || milkKg <= 0) {
    return { ok: false, milkKg: 0, totalText: "—", reason: "إجمالي اللبن صفر." };
  }

  return {
    ok: true,
    milkKg,
    totalText: dailyMilkFormatTotalSrv(milkKg),
    reason: ""
  };
}

function dailyMilkImportBuildUiSrv({ rows = [], message = "" } = {}) {
  const safeRows = Array.isArray(rows) ? rows : [];
  const validRows = safeRows.filter(r => r.valid === true);
  const invalidRows = safeRows.filter(r => r.valid !== true);

  const totalMilk = validRows.reduce((s, r) => s + Number(r.milkKg || 0), 0);

  return {
    screen: "daily_milk_import",
    status: validRows.length ? "success" : "warning",
    message: message || (
  validRows.length
    ? (
        invalidRows.length
          ? `راجعت ${safeRows.length} سجلًا: ${validRows.length} جاهز للحفظ، و${invalidRows.length} يحتاج مراجعة.`
          : `✅ تمت معاينة ${validRows.length} سجلًا، وكلها جاهزة للحفظ.`
      )
    : "❌ لا توجد سجلات صالحة للحفظ."
),
    canSave: validRows.length > 0,
    rows: safeRows,
    kpi: {
      totalRows: safeRows.length,
      validRows: validRows.length,
      invalidRows: invalidRows.length,
      totalMilk: Number(totalMilk.toFixed(1))
    }
  };
}

async function dailyMilkImportPreviewRowsSrv(uid, eventDate, inputRows = []) {
  const rows = [];

  for (const rawRow of inputRows) {
    const animalNumber = calvingNormDigitsOnlySrv(rawRow.animalNumber || rawRow.number || "");

    if (!animalNumber) {
      rows.push({ ...rawRow, animalNumber: "", valid: false, reason: "رقم الحيوان غير صحيح.", totalText: "—" });
      continue;
    }

    const animal = await fetchAnimalByNumberForCalvingGateSrv(uid, animalNumber);

    if (!animal) {
      rows.push({ ...rawRow, animalNumber, valid: false, reason: "الحيوان خارج القطيع، لذلك لا يمكن تسجيل اللبن له.", totalText: "—" });
      continue;
    }

    const animalDoc = animal.data || {};

    if (dailyMilkIsOutOfHerdSrv(animalDoc)) {
      rows.push({ ...rawRow, animalNumber, valid: false, reason: "سبق تسجيل اللبن لهذا الحيوان في التاريخ نفسه.", totalText: "—" });
      continue;
    }

    const duplicated = await dailyMilkHasSameDaySrv(uid, animalNumber, eventDate);

    if (duplicated) {
      rows.push({ ...rawRow, animalNumber, valid: false, reason: "تم تسجيل لبن اليوم لهذا الحيوان بالفعل.", totalText: "—" });
      continue;
    }

    const species = dailyMilkSpeciesSrv(animalDoc);
    const kind = dailyMilkKindSrv(species);
    const calc = dailyMilkImportCalcSrv(rawRow, kind);

    rows.push({
      ...rawRow,
      animalNumber,
      animalId: animal.id || "",
      species,
      kind,
      milkKg: calc.milkKg,
      totalText: calc.totalText,
      valid: calc.ok,
      reason: calc.reason || "",
      eventDate
    });
  }

  return rows;
}

