app.post("/api/daily-milk/import/save", requireUserId, async (req, res) => {
  try {
    if (!db) {
      const ui = dailyMilkImportBuildUiSrv({
        rows: [],
        message: "❌ تعذّر حفظ بيانات المحلب الآن. حاول مرة أخرى."
      });

      return res.status(503).json({
        ok: false,
        message: ui.message,
        savedCount: 0,
        rejectedCount: 0,
        saved: [],
        rejected: [],
        ui
      });
    }

    const uid = req.userId;
    const body = req.body || {};

    const eventDate = String(body.eventDate || body.date || "").trim().slice(0, 10);

    if (!calvingIsDateSrv(eventDate)) {
      const ui = dailyMilkImportBuildUiSrv({
        rows: [],
       message: "❌ أدخل تاريخ تسجيل لبن صحيحًا."
      });

      return res.status(400).json({
        ok: false,
        message: ui.message,
        savedCount: 0,
        rejectedCount: 0,
        saved: [],
        rejected: [],
        ui
      });
    }

    const inputRows = Array.isArray(body.rows) ? body.rows : [];

    if (!inputRows.length) {
      const ui = dailyMilkImportBuildUiSrv({
        rows: [],
        message: "❌ لا توجد سجلات جاهزة للحفظ. راجع بيانات المعاينة."
      });

      return res.status(400).json({
        ok: false,
        message: ui.message,
        savedCount: 0,
        rejectedCount: 0,
        saved: [],
        rejected: [],
        ui
      });
    }

    const checkedRows = await dailyMilkImportPreviewRowsSrv(uid, eventDate, inputRows);

    const saved = [];
    const rejected = [];

    for (const row of checkedRows) {
      if (row.valid !== true) {
        rejected.push({
          animalNumber: row.animalNumber || "",
          reason: row.reason || "راجع بيانات هذا الحيوان قبل الحفظ."
        });
        continue;
      }

      const animalNumber = calvingNormDigitsOnlySrv(row.animalNumber);
      const animalId = String(row.animalId || "").trim();
      const kind = String(row.kind || "").trim();
      const species = String(row.species || "").trim();

      const s1 = dailyMilkNumStrictSrv(row.milkS1);
      const s2 = dailyMilkNumStrictSrv(row.milkS2);
      const s3 = dailyMilkNumStrictSrv(row.milkS3);
      const calc = dailyMilkImportCalcSrv(row, kind);

      if (!calc.ok) {
        rejected.push({
          animalNumber,
          reason: calc.reason || "أدخل كمية لبن رقمية صحيحة."
        });
        continue;
      }

      const milkSessions =
        String(row.importMode || "") === "total_only"
          ? [{ n: 1, kg: calc.milkKg }]
          : (
              kind === "buffalo"
                ? [{ n: 1, kg: s1 }, { n: 2, kg: s2 }]
                : [{ n: 1, kg: s1 }, { n: 2, kg: s2 }, { n: 3, kg: s3 }]
            );

      const eventId = ["daily_milk", uid, animalNumber, eventDate].join("__");
      const eventRef = db.collection("events").doc(eventId);

      const existing = await eventRef.get();
      if (existing.exists) {
        rejected.push({
          animalNumber,
         reason: "سبق تسجيل اللبن لهذا الحيوان في التاريخ نفسه."
        });
        continue;
      }

      const payload = {
        userId: uid,
        ownerUid: uid,

        animalId,
        animalNumber,

        createdAt: admin.firestore.FieldValue.serverTimestamp(),
        updatedAt: admin.firestore.FieldValue.serverTimestamp(),

        date: eventDate,
        eventDate,

        eventType: "لبن يومي",
        eventTypeNorm: "daily_milk",
        type: "daily_milk",

        species,
        kind,
        importMode: String(row.importMode || "").trim() || "sessions",

        milkSessions,
        milkKg: calc.milkKg,
        dailyMilk: calc.milkKg,
        totalMilk: calc.milkKg,

        source: "server:/api/daily-milk/import/save"
      };

      const batch = db.batch();

      batch.set(eventRef, payload);

      if (animalId) {
        batch.set(db.collection("animals").doc(animalId), {
          dailyMilk: calc.milkKg,
          milkTodayKg: calc.milkKg,
          lastMilkKg: calc.milkKg,
          lastMilkDate: eventDate,
          updatedAt: admin.firestore.FieldValue.serverTimestamp()
        }, { merge: true });
      }

      await batch.commit();

      saved.push({
        animalNumber,
        animalId,
        eventId,
        eventDate,
        milkKg: calc.milkKg,
        species,
        kind,
        totalText: dailyMilkFormatTotalSrv(calc.milkKg),
        valid: true,
        reason: ""
      });
    }

    if (saved.length && typeof scheduleGroupsRebuildSrv === "function") {
      scheduleGroupsRebuildSrv(uid, "daily_milk_import_save");
    }

    const rejectedRows = rejected.map(x => ({
      ...x,
      valid: false,
      totalText: "—"
    }));

    const ui = dailyMilkImportBuildUiSrv({
      rows: [...saved, ...rejectedRows],
     message: saved.length
  ? (
      rejected.length
        ? `✅ تم حفظ ${saved.length} سجل لبن، ولم يتم حفظ ${rejected.length} سجل يحتاج مراجعة.`
        : `✅ تم حفظ ${saved.length} سجل لبن بنجاح.`
    )
  : "❌ لم يتم حفظ أي سجل لبن. راجع أسباب الرفض الظاهرة."
    });

    return res.json({
      ok: saved.length > 0,
      message: ui.message,
      savedCount: saved.length,
      rejectedCount: rejected.length,
      saved,
      rejected,
      ui
    });

  } catch (e) {
    console.error("daily-milk-import-save", e);

    const ui = dailyMilkImportBuildUiSrv({
      rows: [],
      message: "❌ تعذّر حفظ بيانات المحلب الآن. حاول مرة أخرى."
    });

    return res.status(500).json({
      ok: false,
      message: ui.message,
      savedCount: 0,
      rejectedCount: 0,
      saved: [],
      rejected: [],
      ui
    });
  }
});
