app.post('/api/heat/gate', requireUserId, async (req, res) => {
  try {
   if (!db) {
  return res.status(503).json({
    ok:false,
    allowed:false,
    error:"firestore_disabled",
    message:"❌ تعذّر فحص بيانات الشياع الآن. حاول مرة أخرى."
  });
}

    const body = req.body || {};
    const raw = String(body.animalNumber || body.animalNumbers || body.number || "").trim();
    const eventDate = String(body.eventDate || body.date || "").slice(0,10);

    const nums = raw
      .split(/[\s,،;]+/)
      .map(x => normalizeDigitsSrv(x))
      .filter(Boolean);

    if (!nums.length) {
      return res.status(400).json({
        ok:false,
        allowed:false,
       message:"❌ أدخل رقم الحيوان."
      });
    }

    const results = [];

    for (const n of nums) {
      const ctx = await buildHeatContextSrv(req.userId, n, eventDate);

      results.push({
        animalNumber: n,
        ok: !!ctx.ok,
        allowed: !!ctx.allowed,
        message: ctx.message || ctx.error || "❌ تعذّر فحص بيانات هذا الحيوان.",
        animalId: ctx.animalId || "",
        species: ctx.species || "",
        reproductiveStatus: ctx.reproductiveStatus || "",
        reproductiveCategory: ctx.reproductiveCategory || "",
        requiresPregnancyConfirmation: ctx.requiresPregnancyConfirmation === true,
        actionRequired: ctx.actionRequired || "",
        pregnancyConfirmationRedirectUrl: ctx.pregnancyConfirmationRedirectUrl || "",
        redirectUrl: ctx.redirectUrl || "",
        dimAtEvent: ctx.dimAtEvent ?? null,
        lastEventType: ctx.lastEventType || null,
        lastEventDate: ctx.lastEventDate || null,
        daysSinceLastHeatOrAI: ctx.daysSinceLastHeatOrAI ?? null
      });
    }

    const allowedNumbers = results.filter(x => x.allowed).map(x => x.animalNumber);
    const rejected = results.filter(x => !x.allowed);
    const pregnancyItem = rejected.find(x =>
  x.requiresPregnancyConfirmation === true ||
  x.actionRequired === "pregnancy_confirmation"
);
const gateAllowedNumbersMessage = allowedNumbers.length
  ? `يمكن تسجيل الشياع للأرقام التالية: ${heatNumbersTextSrv(allowedNumbers)}.`
  : "";
const gateBaseMessage = rejected.length
  ? `راجعت ${results.length} حيوانًا: يمكن تسجيل الشياع لـ${allowedNumbers.length}، ولا يمكن تسجيله لـ${rejected.length}.`
  : `✅ راجعت البيانات، ويمكن تسجيل الشياع${gateAllowedNumbersMessage ? `.\n${gateAllowedNumbersMessage}` : "."}`;

const gateRejectedMessage = heatRejectedReasonsTextSrv(
  rejected,
 "الأرقام التي لا يمكن تسجيل الشياع لها"
);
    return res.json({
      ok: true,
      allowed: allowedNumbers.length > 0,
      animalNumbers: allowedNumbers,
      rejected,
      results,
      actionRequired: pregnancyItem ? "pregnancy_confirmation" : "",
      requiresPregnancyConfirmation: !!pregnancyItem,
      pregnancyConfirmationRedirectUrl: pregnancyItem?.pregnancyConfirmationRedirectUrl || "",
      redirectUrl: pregnancyItem?.redirectUrl || pregnancyItem?.pregnancyConfirmationRedirectUrl || "",
message: heatJoinMessageSrv(gateBaseMessage, gateRejectedMessage)
    });

  } catch (e) {
    console.error('heat-gate', e);
    return res.status(500).json({
      ok:false,
      allowed:false,
      error:'heat_gate_failed',
      message:"❌ تعذّر فحص بيانات الشياع الآن. حاول مرة أخرى."
    });
  }
});
