app.get("/api/bcs/training/gate", requireUserId, async (req, res) => {
  try {
    const canTrain = bcsIsTrainingAdminSrv(req.userId);

    return res.json({
      ok: true,
      canTrain,
      trainingEnabled: canTrain,
      mode: canTrain ? "expert_bcs_correction" : "hidden",
      message: canTrain
        ? "أدوات تدريب نموذج حالة الجسم متاحة لهذا الحساب."
        : "أدوات تدريب نموذج حالة الجسم غير متاحة لهذا الحساب."
    });
  } catch (e) {
    console.error("bcs training gate failed:", e.message || e);
    return res.status(500).json({
      ok: false,
      canTrain: false,
      message: "تعذّر فتح أدوات تدريب نموذج حالة الجسم."
    });
  }
});

app.post("/api/bcs/training/save", requireUserId, async (req, res) => {
  try {
    if (!bcsIsTrainingAdminSrv(req.userId)) {
      return res.status(403).json({
        ok: false,
        canTrain: false,
        error: "bcs_training_forbidden",
        message: "أدوات تدريب نموذج حالة الجسم متاحة لحساب دكتور محمد فقط."
      });
    }

    if (!db) {
      return res.status(503).json({
        ok: false,
        error: "firestore_disabled",
        message: "تعذّر حفظ تصحيح التدريب — قاعدة البيانات غير متاحة."
      });
    }

    const uid = req.userId;
    const body = req.body || {};
    const analysis = body.analysis && typeof body.analysis === "object" ? body.analysis : {};

    const kind = bcsNormalizeKindSrv(
      body.kind ||
      analysis.kind ||
      body.animalKind ||
      body.species
    );

    const animalType = String(
      body.animalType ||
      analysis.animalType ||
      body.typeLabel ||
      ""
    ).trim();

    const predictedScore = bcsClampScoreSrv(
      body.predictedScore ??
      body.modelScore ??
      analysis.score,
      kind
    );

    const correctedScore = bcsClampScoreSrv(
      body.correctedScore ??
      body.expertScore ??
      body.correctScore,
      kind
    );

    if (!Number.isFinite(Number(predictedScore))) {
      return res.status(400).json({
        ok: false,
        message: "درجة النموذج الأصلية غير صالحة."
      });
    }

    if (!Number.isFinite(Number(correctedScore))) {
      return res.status(400).json({
        ok: false,
        message: "اختر درجة BCS الصحيحة من 1.00 إلى 5.00."
      });
    }

    const eventDateRaw = String(
      body.eventDate ||
      body.date ||
      (typeof cairoTodayISO === "function"
        ? cairoTodayISO()
        : new Date().toISOString().slice(0, 10))
    ).trim().slice(0, 10);

    const eventDate = /^\d{4}-\d{2}-\d{2}$/.test(eventDateRaw)
      ? eventDateRaw
      : (typeof cairoTodayISO === "function"
        ? cairoTodayISO()
        : new Date().toISOString().slice(0, 10));

    const animalNumber = bcsDigitsOnlySrv(
      body.animalNumber ||
      body.number ||
      body.sampleAnimalNumber ||
      ""
    );

    const captures = body.captures && typeof body.captures === "object"
      ? body.captures
      : {};

    const captureHash = bcsCaptureHashSrv(captures);

    const rearFindings = bcsShortTextSrv(
      body.rearFindings ||
      analysis.rearFindings ||
      analysis.findings?.rear ||
      "",
      600
    );

    const sideFindings = bcsShortTextSrv(
      body.sideFindings ||
      analysis.sideFindings ||
      analysis.findings?.side ||
      "",
      600
    );

    const expertNote = bcsShortTextSrv(
      body.expertNote ||
      body.note ||
      body.trainingNote ||
      "",
      800
    );

    const payload = cleanObj({
      userId: uid,
      ownerUid: uid,
      adminUid: uid,

      eventType: "تدريب نموذج حالة الجسم",
      eventTypeNorm: "bcs_training_correction",
      date: eventDate,
      eventDate,

      mode: "individual",
      animalNumber: animalNumber || null,

      kind,
      species: bcsKindArabicSrv(kind),
      animalType: animalType || null,

      predictedScore,
      predictedLabel: bcsLabelSrv(predictedScore),
      correctedScore,
      correctedLabel: bcsLabelSrv(correctedScore),
      delta: Number((correctedScore - predictedScore).toFixed(2)),

      modelReason: bcsShortTextSrv(analysis.reason || body.modelReason || "", 800),
      rearFindings,
      sideFindings,
      expertNote,

      modelQuality: analysis.quality || null,
      modelAnalysis: cleanObj({
        score: analysis.score ?? predictedScore,
        label: analysis.label || bcsLabelSrv(predictedScore),
        kind: analysis.kind || kind,
        species: analysis.species || bcsKindArabicSrv(kind),
        animalType: analysis.animalType || animalType || null,
        quality: analysis.quality || null,
        rangeText: analysis.rangeText || "1–5",
        reason: analysis.reason || null,
        rearFindings: analysis.rearFindings || null,
        sideFindings: analysis.sideFindings || null,
        findings: analysis.findings || null,
        note: analysis.note || null
      }),

      captureHash: captureHash || null,
      rearImageReceived: Boolean(captures.rear),
      sideImageReceived: Boolean(captures.side),
      imageStored: false,

      status: "accepted",
      source: "server:/api/bcs/training/save",
      createdAt: admin.firestore.FieldValue.serverTimestamp(),
      updatedAt: admin.firestore.FieldValue.serverTimestamp()
    });

    const ref = await db
      .collection(BCS_TRAINING_CORRECTIONS_COLLECTION_SRV)
      .add(payload);

    await db
      .collection(BCS_TRAINING_SUMMARY_COLLECTION_SRV)
      .doc("global")
      .set({
        lastCorrectionAt: admin.firestore.FieldValue.serverTimestamp(),
        lastCorrectionId: ref.id,
        lastPredictedScore: predictedScore,
        lastCorrectedScore: correctedScore,
        totalCorrections: admin.firestore.FieldValue.increment(1),
        updatedAt: admin.firestore.FieldValue.serverTimestamp()
      }, { merge: true });

    return res.json({
      ok: true,
      canTrain: true,
      id: ref.id,
      correctionId: ref.id,
      predictedScore,
      correctedScore,
      message: `✅ تم حفظ تصحيح تدريب BCS: النموذج ${predictedScore} → الصحيح ${correctedScore}.`
    });

  } catch (e) {
    console.error("bcs training save failed:", e.message || e);
    return res.status(500).json({
      ok: false,
      message: "تعذّر حفظ تصحيح تدريب نموذج حالة الجسم."
    });
  }
});
// ============================================================
//          API: FECES VISION ANALYZE (OpenAI Vision)
//          تقييم الروث بالرؤية — السيرفر فقط
// ============================================================

function fecesClampScoreSrv(v) {
  const n = Number(v);
  if (!Number.isFinite(n)) return null;
  return Math.max(1, Math.min(5, Math.round(n)));
}

function fecesLabelSrv(score) {
  const s = Number(score);

  if (s === 1) return "إسهال شديد";
  if (s === 2) return "لين زيادة";
  if (s === 3) return "نموذجي";
  if (s === 4) return "جاف زيادة";
  if (s === 5) return "جاف جدًا";

  return "غير محدد";
}

function fecesBuildNoteSrv(score) {
  const s = Number(score);

  if (s === 1) {
    return "روث مائي جدًا؛ مؤشر بصري لاحتمال إسهال أو سرعة مرور عالية. يحتاج ربطه بحالة الحيوان والعليقة.";
  }

  if (s === 2) {
    return "روث لين أكثر من المطلوب؛ قد يشير إلى سرعة مرور أعلى أو نقص ألياف فعالة أو زيادة تخمر سريع.";
  }

  if (s === 3) {
    return "قوام نموذجي؛ الروث متماسك بدرجة مناسبة ويكوّن كومة واضحة بدون جفاف أو سيولة زائدة.";
  }

  if (s === 4) {
    return "روث متماسك أو جاف زيادة؛ قد يرتبط بزيادة الألياف أو قلة الماء أو بطء المرور.";
  }

  if (s === 5) {
    return "روث جاف جدًا أو صلب؛ مؤشر بصري لاحتمال جفاف/إمساك أو خلل واضح في الاتزان الغذائي.";
  }

  return "";
}
const FECES_DAILY_LIMIT_SRV = 10;
const FECES_GROUP_SESSION_SAMPLE_LIMIT_SRV = 4;
const FECES_TRAINING_ADMIN_UID_SRV =
  process.env.FECES_TRAINING_ADMIN_UID || "DEQ98faBPYSFikEMtaPTTynJ6iI2";

const FECES_TRAINING_CORRECTIONS_COLLECTION_SRV = "feces_training_corrections";
const FECES_TRAINING_SUMMARY_COLLECTION_SRV = "feces_training_summary";

function fecesIsTrainingAdminSrv(uid) {
  return String(uid || "").trim() === String(FECES_TRAINING_ADMIN_UID_SRV || "").trim();
}

function fecesShortTextSrv(v, max = 280) {
  const s = String(v || "").trim().replace(/\s+/g, " ");
  if (!s) return "";
  return s.length > max ? s.slice(0, max).trim() : s;
}

function fecesImageHashSrv(image = "") {
  const raw = String(image || "");
  if (!raw) return "";

  try {
    const crypto = require("crypto");
    return crypto.createHash("sha1").update(raw.slice(0, 300000)).digest("hex");
  } catch {
    return "";
  }
}

async function fecesBuildExpertCalibrationPromptSrv() {
  if (!db) return "";

  try {
    const snap = await db
      .collection(FECES_TRAINING_CORRECTIONS_COLLECTION_SRV)
      .orderBy("createdAt", "desc")
      .limit(12)
      .get();

    const rows = snap.docs
      .map(doc => doc.data() || {})
      .filter(r => {
        const predicted = Number(r.predictedScore);
        const corrected = Number(r.correctedScore);

        return (
          Number.isFinite(predicted) &&
          Number.isFinite(corrected) &&
          predicted >= 1 && predicted <= 5 &&
          corrected >= 1 && corrected <= 5 &&
          predicted !== corrected
        );
      })
      .slice(0, 6);

    if (!rows.length) return "";

    const lines = rows.map((r, idx) => {
      const note = fecesShortTextSrv(r.expertNote || r.note || r.reason || "", 160);
      const visual = fecesShortTextSrv(r.visualFindings || r.findings?.visual || "", 160);

      return [
        `${idx + 1}) توقع النموذج سابقًا درجة ${r.predictedScore} وصحح الخبير الدرجة إلى ${r.correctedScore}.`,
        visual ? `العلامات البصرية المصححة: ${visual}.` : "",
        note ? `ملاحظة الخبير: ${note}.` : ""
      ].filter(Boolean).join(" ");
    });

    return `
Expert correction memory from Dr. Mohamed:
Use these recent expert corrections only as calibration guidance when similar visual signs appear.
Do not copy a correction blindly; always score the current TARGET image from its visible manure signs.
${lines.join("\n")}
`.trim();

  } catch (e) {
    console.warn("feces training calibration skipped:", e.message || e);
    return "";
  }
}


function fecesDailyCounterIdSrv(uid, eventDate, counterType = "save") {
  return eventsPageStableDocIdSrv(
    uid,
    "feces_eval_daily",
    counterType,
    eventDate
  );
}

function fecesDailyEventDocIdSrv(uid, eventDate, sequence) {
  return eventsPageStableDocIdSrv(
    uid,
    "feces_eval",
    eventDate,
    String(sequence).padStart(2, "0")
  );
}

function fecesGroupValueSrv(...vals) {
  for (const v of vals) {
    const s = String(v || "").trim();
    if (s) return s;
  }
  return "";
}
function fecesDigitsOnlySrv(v) {
  const map = {
    "٠":"0","١":"1","٢":"2","٣":"3","٤":"4","٥":"5","٦":"6","٧":"7","٨":"8","٩":"9",
    "۰":"0","۱":"1","۲":"2","۳":"3","۴":"4","۵":"5","۶":"6","۷":"7","۸":"8","۹":"9"
  };

  return String(v || "")
    .trim()
    .replace(/[٠-٩۰-۹]/g, d => map[d] || d)
    .replace(/[^0-9]/g, "");
}

function fecesRoundOneSrv(v) {
  const n = Number(v);
  if (!Number.isFinite(n)) return null;
  return Math.round(n * 10) / 10;
}

function fecesSessionLabelSrv(score) {
  const n = Number(score);
  if (!Number.isFinite(n)) return "غير محدد";
  return fecesLabelSrv(Math.max(1, Math.min(5, Math.round(n))));
}

function fecesNormalizeSamplesSrv(body = {}, fallbackAnalysis = {}, fallbackScore = null) {
  const rawSamples = Array.isArray(body.samples)
    ? body.samples
    : Array.isArray(body.sampleResults)
      ? body.sampleResults
      : Array.isArray(body.analyses)
        ? body.analyses
        : [];

  const source = rawSamples.length
    ? rawSamples
    : [{
        score: fallbackScore,
        analysis: fallbackAnalysis
      }];

  return source
    .map((sample, idx) => {
      const item = sample && typeof sample === "object" ? sample : {};
      const analysis = item.analysis || item.result || item;
      const score = fecesClampScoreSrv(
        item.score ??
        item.fecesScore ??
        analysis.score
      );

      if (!Number.isFinite(Number(score))) return null;

      return cleanObj({
        sampleNo: Number(item.sampleNo || item.no || idx + 1),
        score,
        fecesScore: score,
        label: item.label || analysis.label || fecesLabelSrv(score),
        quality: item.quality || analysis.quality || null,
        reason: item.reason || analysis.reason || null,
        findings: item.findings || analysis.findings || null,
        note: item.note || analysis.note || fecesBuildNoteSrv(score),
        rangeText: item.rangeText || analysis.rangeText || "1–5",
        source: item.source || analysis.source || "server:/api/feces/vision-analyze"
      });
    })
    .filter(Boolean);
}
async function fecesConsumeDailySlotSrv({
  uid,
  eventDate,
  counterType = "save",
  limit = FECES_DAILY_LIMIT_SRV
} = {}) {
  const counterRef = db.collection("event_counters").doc(
    fecesDailyCounterIdSrv(uid, eventDate, counterType)
  );

  let allowed = false;
  let dailySequence = 0;
  let currentDailyCount = 0;

  await db.runTransaction(async (tx) => {
    const snap = await tx.get(counterRef);
    const current = Number(snap.exists ? (snap.data()?.count || 0) : 0);

    currentDailyCount = Number.isFinite(current) && current > 0 ? current : 0;

    if (currentDailyCount >= limit) {
      allowed = false;
      return;
    }

    dailySequence = currentDailyCount + 1;
    allowed = true;

    const payload = {
      userId: uid,
      ownerUid: uid,
      counterType,
      eventType: "تقييم الروث",
      eventTypeNorm: "feces_eval",
      eventDate,
      date: eventDate,
      scope: "feeding_group_daily",
      dailyLimit: limit,
      count: dailySequence,
      updatedAt: admin.firestore.FieldValue.serverTimestamp()
    };

    if (!snap.exists) {
      payload.createdAt = admin.firestore.FieldValue.serverTimestamp();
    }

    tx.set(counterRef, payload, { merge: true });
  });

  return {
    allowed,
    dailySequence,
    currentDailyCount,
    dailyLimit: limit
  };
}
