    'montbéliarde': 'مونتبليارد',
    'jersey': 'جيرسي',
    'simmental': 'سيمنتال',
    'fleckvieh': 'فليكفيه',
    'charolais': 'شاروليه',
    'ayrshire': 'أيرشاير',

    'buffalo': 'جاموسي',
