//                 CARD HELPERS — cow/calves server source
// ============================================================
function cardTextSrv(v, fallback = '—') {
  if (v === null || v === undefined || v === '') return fallback;
  if (Array.isArray(v)) return v.map(x => cardTextSrv(x, '')).filter(Boolean).join('، ') || fallback;
  if (typeof v === 'object') {
    const d = cardISODateSrv(v);
    if (d) return d;
    const txt = Object.values(v).map(x => cardTextSrv(x, '')).filter(Boolean).join('، ');
    return txt || fallback;
  }
  return String(v).trim() || fallback;
}

function cardFirstSrv(obj = {}, keys = [], fallback = null) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== null && v !== undefined && String(v).trim() !== '') return v;
  }
  return fallback;
}

function cardISODateSrv(v) {
  if (!v) return null;
  if (typeof v === 'string') {
    const m = v.match(/\d{4}-\d{2}-\d{2}/);
    if (m) return m[0];
  }
  try {
    const d = toDate(v);
    if (d && !Number.isNaN(d.getTime())) return toYYYYMMDD(d);
  } catch (_) {}
  return null;
}

function cardAgeTextSrv(birthDate) {
  const bd = cardISODateSrv(birthDate);
  if (!bd) return { ageDays: null, ageText: '—' };

  const ageDays = daysBetweenIsoSrv(bd, cairoTodayISO());
  if (!Number.isFinite(ageDays) || ageDays < 0) return { ageDays: null, ageText: '—' };

  if (ageDays < 30) return { ageDays, ageText: `${ageDays} يوم` };

  if (ageDays < 365) {
    const months = Math.floor(ageDays / 30);
    const days = ageDays % 30;
    return {
      ageDays,
      ageText: days ? `${months} شهر و ${days} يوم` : `${months} شهر`
    };
  }

  const years = Math.floor(ageDays / 365);
  const months = Math.floor((ageDays % 365) / 30);

  return {
    ageDays,
    ageText: months ? `${years} سنة و ${months} شهر` : `${years} سنة`
  };
}

function cardNormalizeSexSrv(v) {
  const s = String(v || '').trim().toLowerCase();
  if (!s) return null;

  if (/female|f\b|انث|أنث|عجلة|عجله/.test(s)) return 'أنثى';
  if (/male|m\b|ذكر|عجل/.test(s)) return 'ذكر';

  return String(v).trim();
}

function cardSubjectNumberSrv(obj = {}) {
  return normalizeDigitsSrv(
    obj.animalNumber ?? obj.number ?? obj.calfNumber ?? obj.no ?? obj.tag ?? ''
  );
}

function cardNumberSetSrv(values = []) {
  const out = new Set();

  for (const v of values) {
    if (v === null || v === undefined || v === '') continue;

    const raw = String(v).trim();
    if (raw) out.add(raw);

    const dig = normalizeDigitsSrv(raw);
    if (dig) out.add(dig);

    const n = Number(dig || raw);
    if (Number.isFinite(n)) out.add(String(n));
  }

  return out;
}

function cardSubjectNumbersSrv(subject = {}) {
  return cardNumberSetSrv([
    subject.animalNumber,
    subject.number,
    subject.calfNumber,
    subject.no,
    subject.tag
  ]);
}

function cardSubjectIdsSrv(subject = {}) {
  return new Set([
    subject.id,
    subject.animalId,
    subject.calfId,
    subject.docId
  ].map(v => String(v || '').trim()).filter(Boolean));
}

async function findCardDocByIdSrv(uid, collectionName, id) {
  const docId = String(id || '').trim();
  if (!db || !uid || !collectionName || !docId) return null;

  try {
    const d = await db.collection(collectionName).doc(docId).get();
    if (!d.exists) return null;

    const row = d.data() || {};
    const owner = String(row.userId || row.ownerUid || '').trim();

    if (owner && owner !== uid) return null;

    return {
      id: d.id,
      _collection: collectionName,
      ...row
    };
  } catch (_) {
    return null;
  }
}

async function findCardDocByNumberSrv(uid, collectionName, number, numberFields = ['animalNumber', 'number']) {
  if (!db || !uid || !collectionName) return null;

  const numberStr = normalizeDigitsSrv(number);
  if (!numberStr) return null;

  const seen = new Set();

  const push = d => {
    if (!d || !d.exists || seen.has(d.id)) return null;

    seen.add(d.id);

    return {
      id: d.id,
      _collection: collectionName,
      ...(d.data() || {})
    };
  };

  const tenantNumberKey = `${uid}#${numberStr}`;

  try {
    const s = await db.collection(collectionName)
      .where('userId_number', '==', tenantNumberKey)
      .limit(1)
      .get();

    if (!s.empty) return push(s.docs[0]);
  } catch (_) {}

  const vals = findAnimalNumberMatches(numberStr);

  for (const ownerField of ['userId', 'ownerUid']) {
    for (const field of numberFields) {
      for (const v of vals) {
        try {
          const s = await db.collection(collectionName)
            .where(ownerField, '==', uid)
            .where(field, '==', v)
            .limit(1)
            .get();

          if (!s.empty) return push(s.docs[0]);
        } catch (_) {}
      }
    }
  }

  return null;
}

async function findCowCardDocSrv(uid, { number, animalId } = {}) {
  const byId = await findCardDocByIdSrv(uid, 'animals', animalId);
  if (byId) return byId;

  return findCardDocByNumberSrv(uid, 'animals', number, ['animalNumber', 'number']);
}

async function findCalfCardDocSrv(uid, { number, calfId } = {}) {
  const byId = await findCardDocByIdSrv(uid, 'calves', calfId);
  if (byId) return byId;

  return findCardDocByNumberSrv(uid, 'calves', number, ['calfNumber', 'animalNumber', 'number']);
}

async function fetchCardEventsSrv(uid, subject = {}) {
  if (!db || !uid || !subject) return [];

  const rows = [];
  const seen = new Set();

  const pushDocs = (docs = []) => {
    for (const d of docs) {
      if (!d || !d.id || seen.has(d.id)) continue;

      seen.add(d.id);
      rows.push({
        id: d.id,
        ...(d.data() || {})
      });
    }
  };

  const ids = cardSubjectIdsSrv(subject);

  for (const id of ids) {
    for (const field of ['animalId', 'calfId', 'subject.animalId', 'subject.calfId']) {
      try {
        const s = await db.collection('events')
          .where('userId', '==', uid)
          .where(field, '==', id)
          .limit(300)
          .get();

        pushDocs(s.docs);
      } catch (_) {}
    }
  }

  const nums = [...cardSubjectNumbersSrv(subject)];

  for (const field of ['animalNumber', 'number', 'calfNumber']) {
    for (const raw of nums) {
      const vals = findAnimalNumberMatches(raw);

      for (const v of vals) {
        try {
          const s = await db.collection('events')
            .where('userId', '==', uid)
            .where(field, '==', v)
            .limit(300)
            .get();

          pushDocs(s.docs);
        } catch (_) {}
      }
    }
  }

  return rows.sort((a, b) =>
    String(computeEventDateFromDoc(a) || '').localeCompare(String(computeEventDateFromDoc(b) || ''))
  );
}

function cardEventTitleSrv(e = {}) {
  const direct = cardFirstSrv(e, [
    'displayName',
    'eventNameAr',
    'pageTitleAr',
    'nameAr',
    'titleAr',
    'labelAr',
    'eventName',
    'name',
    'title',
    'label',
    'eventTypeAr',
    'eventType',
    'type',
    'kind',
    'diseaseName',
    'diagnosis',
    'pregnancyResult',
    'heatStatus'
  ], '');

  const raw = String(direct || '').trim();

  if (raw && /[\u0600-\u06FF]/.test(raw)) return raw;

  const type = eventTypeForCardSrv(e);

  const map = {
    milk: 'لبن يومي',
    calving: 'ولادة',
    insemination: 'تلقيح',
    pregnancy: 'تشخيص حمل',
    heat: 'شياع',
    dry: 'تجفيف',
    disease: 'حالة صحية',
    other: 'حدث'
  };

  return map[type] || raw || 'حدث';
}

function cardEventSummarySrv(e = {}) {
  const existing = cardFirstSrv(e, ['summary', 'shortSummary', 'message', 'detailsText'], '');
  if (existing) return cardTextSrv(existing, '—');

  const type = eventTypeForCardSrv(e);

  if (type === 'milk') {
    const kg = milkKgFromEventSrv(e);
    return kg > 0 ? `${Math.round(kg * 100) / 100} كجم` : '—';
  }

  if (type === 'insemination') {
    const bull = cardFirstSrv(e, ['semenCode', 'bull', 'sire', 'sireNumber', 'straw'], '');
    const method = cardFirstSrv(e, ['method', 'inseminationMethod'], '');

    return [
      method ? `الطريقة: ${method}` : '',
      bull ? `الطلوقة: ${bull}` : ''
    ].filter(Boolean).join(' — ') || 'تلقيح مسجل';
  }

  if (type === 'pregnancy') {
    const result = cardFirstSrv(e, ['result', 'status', 'pregnancyResult', 'diagnosis'], '');
    return result ? `النتيجة: ${cardTextSrv(result, '')}` : 'تشخيص حمل مسجل';
  }

  if (type === 'calving') {
    const calfNo = cardFirstSrv(e, ['calfNumber', 'calf1Number', 'newCalfNumber'], '');
    const sex = cardFirstSrv(e, ['calfSex', 'sex', 'calf1Sex'], '');

    return [
      calfNo ? `رقم المولود: ${calfNo}` : '',
      sex ? `الجنس: ${sex}` : ''
    ].filter(Boolean).join(' — ') || 'ولادة مسجلة';
  }

  const note = cardFirstSrv(e, ['notes', 'note', 'comment', 'reason', 'description'], '');

  return note ? cardTextSrv(note, '—') : '—';
}

function cardEventRowSrv(e = {}) {
  const date = computeEventDateFromDoc(e) || cardISODateSrv(e.createdAt) || null;

  return {
    id: e.id || '',
    date,
    title: cardEventTitleSrv(e),
    summary: cardEventSummarySrv(e),
    type: eventTypeForCardSrv(e)
  };
}

function cardMatchSubjectSrv(row = {}, subject = {}) {
  const nums = cardSubjectNumbersSrv(subject);
  const ids = cardSubjectIdsSrv(subject);

  const rowNums = cardNumberSetSrv([
    row.animalNumber,
    row.number,
    row.calfNumber,
    row.subject?.animalNumber,
    row.subject?.number,
    row.subject?.calfNumber,
    row.animal?.animalNumber,
    row.animal?.number,
    row.calf?.calfNumber,
    row.calf?.number
  ]);

  for (const n of rowNums) {
    if (nums.has(n)) return true;
  }

  const rowIds = new Set([
    row.animalId,
    row.calfId,
    row.subject?.animalId,
    row.subject?.calfId,
    row.subject?.id,
    row.animal?.id,
    row.calf?.id
  ].map(v => String(v || '').trim()).filter(Boolean));

  for (const id of rowIds) {
    if (ids.has(id)) return true;
  }

  return false;
}

function cardAlertRowSrv(row = {}, fallbackTitle = 'تنبيه') {
  return {
    id: row.id || row.taskId || '',
    level: String(row.level || row.severity || row.priority || 'info').toLowerCase(),
    title: cardTextSrv(row.title || row.name || fallbackTitle, fallbackTitle),
    message: cardTextSrv(row.message || row.summary || row.note || row.description || row.reason, '—'),
    dueDate: cardISODateSrv(row.dueDate || row.plannedDate || row.date || row.ts || row.createdAt),
    source: row.source || row.taskType || row.type || ''
  };
}

async function fetchCardAlertsSrv(uid, subject = {}) {
  if (!db || !uid || !subject) return [];

  const out = [];
  const seen = new Set();

  const add = row => {
    const key = String(row.id || row.taskId || `${row.title || ''}_${row.message || ''}_${row.dueDate || ''}`);
    if (seen.has(key)) return;

    seen.add(key);
    out.push(row);
  };

  try {
    const snap = await db.collection('alerts')
      .where('userId', '==', uid)
      .limit(400)
      .get();

    snap.docs.forEach(d => {
      const row = {
        id: d.id,
        ...(d.data() || {})
      };

      if (cardMatchSubjectSrv(row, subject)) {
        add(cardAlertRowSrv(row, 'تنبيه'));
      }
    });
  } catch (_) {}

  try {
    const snap = await db.collection('tasks')
      .where('userId', '==', uid)
      .where('status', '==', 'pending')
      .limit(500)
      .get();

    snap.docs.forEach(d => {
      const t = {
        id: d.id,
        ...(d.data() || {})
      };

      if (t.done === true) return;
      if (!cardMatchSubjectSrv(t, subject)) return;

      const title = cardTextSrv(
        t.title || t.taskTitle || t.stepName || t.taskType || 'مهمة مستحقة',
        'مهمة مستحقة'
      );

      const msg = cardTextSrv(
        t.message || t.note || t.description || t.vaccineKey || t.protocol || title,
        title
      );

      add(cardAlertRowSrv({
        ...t,
        title,
        message: msg,
        level: t.level || 'warn'
      }, 'مهمة مستحقة'));
    });
  } catch (_) {}

  out.sort((a, b) => String(a.dueDate || '').localeCompare(String(b.dueDate || '')));

  return out.slice(0, 8);
}
function cardMilkCurveAnimalClassSrv(a = {}) {
  const s = String(
    a.kind ||
    a.animalTypeAr ||
    a.animaltype ||
    a.species ||
    a.type ||
    ''
  ).trim().toLowerCase();

  if (s.includes('جاموس') || s.includes('buffalo')) return 'buffalo';
  if (s.includes('بقر') || s.includes('cow')) return 'cow';

  return '';
}

function cardMilkDimSrv(e = {}, animal = {}) {
  const direct = Number(
    e.dim ??
    e.DIM ??
    e.daysInMilk ??
    e.daysInMilkAtEvent ??
    e.milkDim ??
    NaN
  );

  if (Number.isFinite(direct) && direct >= 0 && direct <= 500) {
    return direct;
  }

  const eventDate = computeEventDateFromDoc(e);
  const calvingDate = cardISODateSrv(
    animal.lastCalvingDate ||
    animal.lastCalving ||
    animal.calvingDate
  );

  if (!eventDate || !calvingDate) return null;

  const dim = daysBetweenIsoSrv(calvingDate, eventDate);
  return Number.isFinite(dim) && dim >= 0 ? dim : null;
}

async function fetchCardHerdMilkCurveSrv(uid, currentAnimal = {}) {
  if (!db || !uid) return [];

  const targetClass = cardMilkCurveAnimalClassSrv(currentAnimal);
  const animalsByNumber = new Map();

  try {
    const animalsSnap = await db.collection('animals')
      .where('userId', '==', uid)
      .limit(1500)
      .get();

    animalsSnap.docs.forEach(d => {
      const a = {
        id: d.id,
        ...(d.data() || {})
      };

      const st = String(a.status || 'active').trim().toLowerCase();
      if (st === 'archived' || st === 'inactive') return;

      const cls = cardMilkCurveAnimalClassSrv(a);
      if (targetClass && cls && cls !== targetClass) return;

      const nums = cardSubjectNumbersSrv(a);
      for (const n of nums) {
        animalsByNumber.set(String(n), a);
      }
    });
  } catch (e) {
    console.warn('card herd milk animals failed:', e.message || e);
    return [];
  }

  if (!animalsByNumber.size) return [];

  const buckets = new Map();

  try {
    const eventsSnap = await db.collection('events')
      .where('userId', '==', uid)
      .limit(5000)
      .get();

    eventsSnap.docs.forEach(d => {
      const e = {
        id: d.id,
        ...(d.data() || {})
      };

      if (eventTypeForCardSrv(e) !== 'milk') return;

      const kg = milkKgFromEventSrv(e);
      if (!Number.isFinite(kg) || kg <= 0) return;

      let animal = null;
      const nums = cardSubjectNumbersSrv(e);

      for (const n of nums) {
        if (animalsByNumber.has(String(n))) {
          animal = animalsByNumber.get(String(n));
          break;
        }
      }

      if (!animal) return;

      const dim = cardMilkDimSrv(e, animal);
      if (!Number.isFinite(dim) || dim < 0 || dim > 305) return;

      const bucketDim = Math.round(dim / 7) * 7;

      if (!buckets.has(bucketDim)) {
        buckets.set(bucketDim, {
          dim: bucketDim,
          sum: 0,
          count: 0
        });
      }

      const b = buckets.get(bucketDim);
      b.sum += kg;
      b.count += 1;
    });
  } catch (e) {
    console.warn('card herd milk events failed:', e.message || e);
    return [];
  }

  return [...buckets.values()]
    .filter(b => b.count > 0)
    .map(b => ({
      dim: b.dim,
      kg: Math.round((b.sum / b.count) * 100) / 100,
      count: b.count
    }))
    .sort((a, b) => a.dim - b.dim)
    .slice(0, 60);
}
function cardTwinWarningSrv(calf = {}) {
  const sex = cardNormalizeSexSrv(cardFirstSrv(calf, ['sex', 'gender', 'followerSex'], ''));

  const text = [
    calf.litterComposition,
    calf.birthComposition,
    calf.birthType,
    calf.calvingKind
  ].map(v => String(v || '')).join(' ');

  if (sex === 'أنثى' && /ذكر|male|عجل/i.test(text) && /توأم|twin|\+|2/i.test(text)) {
    return 'ملاحظة مهمة: العِجلة مولودة توأم مع عجل ذكر — يوجد احتمال Freemartin.';
  }

  return '';
}
function cardDairyTraitsNumSrv(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function cardDairyTraitsGradeTextSrv(score, fallback = '') {
  const fb = String(fallback || '').trim();
  if (fb) return fb;

  if (typeof dairyTraitsGradeSrv === 'function') {
    return dairyTraitsGradeSrv(score);
  }

  const s = Number(score);
  if (s >= 90) return 'ممتاز';
  if (s >= 85) return 'جيد جدًا';
  if (s >= 80) return 'جيد مرتفع';
  if (s >= 75) return 'جيد';
  if (s >= 65) return 'متوسط';
  if (s >= 50) return 'ضعيف';
  return 'ضعيف جدًا';
}

function cardDairyTraitsPartSrv(breakdown = {}, keys = [], max = 0) {
  for (const k of keys) {
    const n = cardDairyTraitsNumSrv(breakdown?.[k]);
    if (n !== null) {
      return {
        value: Math.max(0, Math.min(Number(max) || 0, Math.round(n))),
        max: Number(max) || 0
      };
    }
  }

  return {
    value: null,
    max: Number(max) || 0
  };
}

function cardDairyTraitsSummarySrv(score, grade, reason = '') {
  const r = String(reason || '').trim();
  if (r) return r;

  const s = Number(score);

  if (s >= 90) return 'تركيب إنتاجي ممتاز وملائم بقوة لإنتاج اللبن.';
  if (s >= 85) return 'تركيب إنتاجي جيد جدًا مع صفات لبنية واضحة.';
  if (s >= 80) return 'تركيب إنتاجي جيد مرتفع مع بعض الملاحظات البسيطة.';
  if (s >= 75) return 'تركيب إنتاجي جيد لكنه يحتاج متابعة في بعض السمات.';
  if (s >= 65) return 'تركيب إنتاجي متوسط مع نقاط تحتاج تحسين.';
  return 'التقييم الإنتاجي منخفض نسبيًا حسب السمات الظاهرة.';
}

function cardDairyTraitsFromAnimalSrv(animal = {}, events = []) {
  const dairyEvents = (Array.isArray(events) ? events : [])
    .filter(e => {
      const txt = eventTextSrv(e);
      return (
        txt.includes('dairy_traits_eval') ||
        txt.includes('dairy traits') ||
        txt.includes('تقييم سمات إنتاج اللبن')
      );
    })
    .sort((a, b) =>
      String(computeEventDateFromDoc(b) || '').localeCompare(String(computeEventDateFromDoc(a) || ''))
    );

  const lastEvent = dairyEvents[0] || null;
  const analysis = lastEvent?.analysis || {};
  const eventBreakdown = analysis.breakdown || {};

  const score = cardDairyTraitsNumSrv(
    animal.lastDairyTraitsScore ??
    animal.dairyTraitsScore ??
    animal.milkTraitsScore ??
    lastEvent?.dairyTraitsScore ??
    lastEvent?.score ??
    analysis.score
  );

  if (score === null) return null;

  const breakdown =
    animal.lastDairyTraitsBreakdown ||
    animal.dairyTraitsBreakdown ||
    eventBreakdown ||
    {};

  const grade = cardDairyTraitsGradeTextSrv(
    score,
    animal.lastDairyTraitsGrade ||
    animal.dairyTraitsGrade ||
    lastEvent?.grade ||
    analysis.grade ||
    ''
  );

  const date = cardISODateSrv(
    animal.lastDairyTraitsDate ||
    animal.dairyTraitsDate ||
    lastEvent?.eventDate ||
    lastEvent?.date ||
    lastEvent?.createdAt
  );

  return {
    score: Math.max(0, Math.min(100, Math.round(score))),
    grade,
    date,
    rangeText: '0–100',
    summary: cardDairyTraitsSummarySrv(score, grade, analysis.reason || lastEvent?.notes || lastEvent?.comment || ''),

    breakdown: {
      udder: cardDairyTraitsPartSrv(breakdown, ['udder'], 40),
      feetAndLegs: cardDairyTraitsPartSrv(breakdown, ['feetAndLegs', 'feetLegs', 'legs'], 20),
      dairyStrength: cardDairyTraitsPartSrv(breakdown, ['dairyStrength', 'strength'], 20),
      frontEndAndCapacity: cardDairyTraitsPartSrv(breakdown, ['frontEndAndCapacity', 'frontEndCapacity', 'capacity', 'bodyCapacity'], 15),
      rump: cardDairyTraitsPartSrv(breakdown, ['rump'], 5)
    }
  };
}
// ============================================================
//                 API: ANIMAL CARD (server-only)
// ============================================================
app.get('/api/animal-card', requireUserId, async (req, res) => {
  try {
    if (!db) {
      return res.status(503).json({
        ok: false,
        error: 'firestore_disabled',
        message: 'قاعدة البيانات غير متاحة الآن.'
      });
    }

    const uid = req.userId;
    const number = normalizeDigitsSrv(req.query.number || req.query.animalNumber || '');
    const animalId = String(req.query.animalId || req.query.id || '').trim();

    if (!number && !animalId) {
      return res.status(400).json({
        ok: false,
        error: 'animalNumber_required',
        message: 'رقم الحيوان مطلوب.'
      });
    }

    const animal = await findCowCardDocSrv(uid, { number, animalId });

    if (!animal) {
      const calf = await findCalfCardDocSrv(uid, { number });

      if (calf) {
        const calfNumber = cardSubjectNumberSrv(calf) || number;

        return res.json({
          ok: false,
          error: 'wrong_card_type',
          cardType: 'calf',
          message: 'هذا الرقم مسجّل كعجل. سيتم فتح بطاقة العجل.',
          redirectUrl: `calf-card.html?number=${encodeURIComponent(calfNumber)}`
        });
      }

     return res.status(404).json({
  ok: false,
  error: 'animal_not_found',
  message: 'هذا الحيوان غير موجود بمزرعتك'
});
    }

    const events = await fetchCardEventsSrv(uid, animal);
    const groupNameFromMembership = await findAnimalGroupNameSrv(uid, animal);

    const state = {
      number: animal.animalNumber ?? animal.number ?? number,

      kind: animal.animalType || animal.kind || animal.type || animal.animalTypeAr || null,

      breed:
        animal.breed ||
        animal.breedName ||
        animal.breedAr ||
        animal.animalBreed ||
        animal.animalBreedAr ||
        animal.strain ||
        animal.line ||
        null,

      group:
        animal.group ||
        animal.groupName ||
        animal.currentGroup ||
        animal.pen ||
        animal.lot ||
        animal.section ||
        groupNameFromMembership ||
        null,

      birthDate: animal.birthDate || animal.birth_date || animal.dob || null,
      lastCalvingDate: animal.lastCalvingDate || animal.lastCalving || animal.calvingDate || null,
      lactationNumber: animal.lactationNumber ?? animal.lactNo ?? null,
      daysInMilk: Number.isFinite(Number(animal.daysInMilk)) ? Number(animal.daysInMilk) : null,

      reproductiveStatus: String(animal.reproductiveStatus || animal.reproStatus || '').trim() || null,
      productionStatus: String(animal.productionStatus || animal.prodStatus || '').trim() || null,
      healthStatus: String(animal.healthStatus || animal.lastDisease || animal.disease || 'سليم').trim(),

      pregnancyDate: animal.pregnancyDate || animal.pregnantFrom || null,
      lastInseminationDate: animal.lastInseminationDate || null,
      servicesCount: Number.isFinite(Number(animal.servicesCount)) ? Number(animal.servicesCount) : null,
      serviceIntervalDays: Number.isFinite(Number(animal.serviceIntervalDays)) ? Number(animal.serviceIntervalDays) : null,
      heatIntervalDays: Number.isFinite(Number(animal.heatIntervalDays)) ? Number(animal.heatIntervalDays) : null,

      milkTraitsScore: Number(animal.milkTraitsScore || animal.milk_score || 0) || 0,
      ovsynch: animal.ovsynch || null,

      milkTodayKg: Number.isFinite(Number(animal.milkTodayKg)) ? Number(animal.milkTodayKg) : null,
      seasonTotalKg: Number.isFinite(Number(animal.seasonTotalKg)) ? Number(animal.seasonTotalKg) : null,
      m305Kg: Number.isFinite(Number(animal.m305Kg)) ? Number(animal.m305Kg) : null,

      lastCheckDate: animal.lastCheckDate || animal.healthCheckDate || null,

      inseminations: [],
      estrusDates: Array.isArray(animal.estrusDates) ? [...animal.estrusDates] : [],
      healthHistory: [],
      milkSeries: []
    };

    let seasonMilk = 0;

    for (const e of events) {
      const t = eventTypeForCardSrv(e);
      const d = computeEventDateFromDoc(e);

      if (t === 'calving' && d) {
        state.lastCalvingDate = d;
      }

      if (t === 'dry') {
        state.productionStatus = 'جاف';
      }

      if (t === 'insemination' && d) {
        state.inseminations.push(d);
      }

      if (t === 'heat' && d) {
        state.estrusDates.push(d);
      }

      if (t === 'pregnancy') {
        if (positivePregnancyEventSrv(e)) {
          if (d) state.pregnancyDate = state.pregnancyDate || d;
          state.reproductiveStatus = 'عِشار';
        } else if (negativePregnancyEventSrv(e)) {
          if (!state.pregnancyDate) state.reproductiveStatus = 'مفتوحة';
        }
      }

      if (t === 'disease') {
        state.healthHistory.push({
          date: d || null,
          name: e.diseaseName || e.eventType || e.type || 'حالة صحية',
          diagnosis: e.diseaseName || e.eventType || e.type || 'حالة صحية',
          note: e.notes || e.note || ''
        });

        if (d && !state.lastCheckDate) {
          state.lastCheckDate = d;
        }
      }

      if (t === 'milk' && d) {
        const kg = milkKgFromEventSrv(e);

        if (kg > 0) {
          const dim = state.lastCalvingDate
            ? daysBetweenIsoSrv(String(state.lastCalvingDate).slice(0, 10), d)
            : null;

          state.milkSeries.push({
            date: d,
            kg,
            dim: Number.isFinite(dim) && dim >= 0 ? dim : null
          });

          seasonMilk += kg;
        }
      }
    }

    state.inseminations = [...new Set(state.inseminations.filter(Boolean))].sort();
    state.estrusDates = [...new Set(state.estrusDates.filter(Boolean))].sort();

    state.milkSeries = state.milkSeries.sort((a, b) =>
      String(a.date).localeCompare(String(b.date))
    );

    state.lastInseminationDate = state.lastInseminationDate || lastOfSrv(state.inseminations);

    state.servicesCount =
      Number.isFinite(Number(state.servicesCount)) && Number(state.servicesCount) > 0
        ? Number(state.servicesCount)
        : (state.inseminations.length || null);

    state.serviceIntervalDays =
      Number.isFinite(Number(state.serviceIntervalDays)) && Number(state.serviceIntervalDays) > 0
        ? Number(state.serviceIntervalDays)
        : avgIntervalDaysSrv(state.inseminations);

    const lastHeatDate = lastOfSrv(state.estrusDates);
    state.lastHeatDate = state.lastHeatDate || lastHeatDate || null;

    state.heatIntervalDays =
      Number.isFinite(Number(state.heatIntervalDays)) && Number(state.heatIntervalDays) > 0
        ? Number(state.heatIntervalDays)
        : avgIntervalDaysSrv(state.estrusDates);

    let gestationDays = null;

    if (state.reproductiveStatus && /عشار|preg/i.test(String(state.reproductiveStatus))) {
      if (state.pregnancyDate) {
        gestationDays = daysBetweenIsoSrv(String(state.pregnancyDate).slice(0, 10), cairoTodayISO());

        if (Number.isFinite(gestationDays) && gestationDays < 0) {
          gestationDays = null;
        }
      }
    }

    state.gestationDays = gestationDays;

    if (!Number.isFinite(Number(state.daysInMilk)) && state.lastCalvingDate) {
      const dim = daysBetweenIsoSrv(String(state.lastCalvingDate).slice(0, 10), cairoTodayISO());
      state.daysInMilk = Number.isFinite(dim) && dim >= 0 ? dim : null;
    }

    if (state.milkSeries.length) {
      const lastMilk = state.milkSeries[state.milkSeries.length - 1];

      state.milkTodayKg =
        Number.isFinite(Number(state.milkTodayKg)) && Number(state.milkTodayKg) > 0
          ? Number(state.milkTodayKg)
          : Number(lastMilk.kg || 0);

      state.seasonTotalKg =
        Number.isFinite(Number(state.seasonTotalKg)) && Number(state.seasonTotalKg) > 0
          ? Number(state.seasonTotalKg)
          : Math.round(seasonMilk * 100) / 100;

      const proj = projectLactation305AliSchaefferSrv({
        milkSeries: state.milkSeries,
        lastCalvingDate: state.lastCalvingDate,
        species: state.kind,
        breed: state.breed,
        parity: state.lactationNumber
      });

      state.m305Kg = proj?.m305Kg ?? null;
    }

    const eventRows = events
      .map(cardEventRowSrv)
      .filter(e => e.date || e.title)
      .slice(-80);

   const alerts = await fetchCardAlertsSrv(uid, animal);
   const dairyTraits = cardDairyTraitsFromAnimalSrv(animal, events);
   const herdMilkCurve = await fetchCardHerdMilkCurveSrv(uid, animal);

    return res.json({
      ok: true,
      cardType: 'cow',
      page: 'cow-card',
      title: 'بطاقة الحيوان',

      animal: {
        id: animal.id,
        animalNumber: state.number,
        number: state.number,
        kind: state.kind,
        breed: state.breed,
        group: state.group,

        birthDate: cardISODateSrv(state.birthDate),
        lastCalvingDate: cardISODateSrv(state.lastCalvingDate),
        lactationNumber: state.lactationNumber,
        daysInMilk: state.daysInMilk,

        reproductiveStatus: state.reproductiveStatus,
        pregnancyDate: cardISODateSrv(state.pregnancyDate),
        gestationDays: state.gestationDays,
        lastInseminationDate: cardISODateSrv(state.lastInseminationDate),
        servicesCount: state.servicesCount,
        serviceIntervalDays: state.serviceIntervalDays,
        lastHeatDate: cardISODateSrv(state.lastHeatDate),
        heatIntervalDays: state.heatIntervalDays,

        productionStatus: state.productionStatus,
        milkTodayKg: state.milkTodayKg,
        seasonTotalKg: state.seasonTotalKg,
        m305Kg: state.m305Kg,
        milkTraitsScore: state.milkTraitsScore,

        healthStatus: state.healthStatus,
        lastCheckDate: cardISODateSrv(state.lastCheckDate),
        ovsynch: state.ovsynch
      },
      dairyTraits,
      milkSeries: state.milkSeries,
      herdMilkCurve,
      healthHistory: state.healthHistory.slice(-20).reverse(),
      alerts,
      events: eventRows,
      recentEvents: [...eventRows].reverse().slice(0, 12)
    });

  } catch (e) {
    console.error('animal-card', e);

    return res.status(500).json({
      ok: false,
      error: 'animal_card_failed',
      message: 'تعذّر تحميل بطاقة الحيوان.'
    });
  }
});
async function findCalfBirthEventForCardSrv(uid, calfNumber) {
  if (!db || !uid || !calfNumber) return null;

  const raw = String(calfNumber).trim();
  const asNum = Number(raw);
  const values = Number.isFinite(asNum) ? [raw, asNum] : [raw];

  const fields = ['calfId', 'calf2Id', 'calf3Id'];
  const found = [];
  const seen = new Set();

  for (const field of fields) {
    for (const value of values) {
      try {
        const snap = await db.collection('events')
          .where('userId', '==', uid)
          .where(field, '==', value)
          .limit(10)
          .get();

        snap.forEach(doc => {
          if (seen.has(doc.id)) return;
          seen.add(doc.id);

          found.push({
            id: doc.id,
            ...(doc.data() || {})
          });
        });
      } catch (_) {}
    }
  }

  return found
    .filter(e => {
      const t = String(e.eventType || e.type || e.eventTypeNorm || '').trim();
      return t.includes('ولادة') || t.includes('calving') || t.includes('birth');
    })
    .sort((a, b) =>
      String(b.eventDate || '').localeCompare(String(a.eventDate || ''))
    )[0] || null;
}
async function findCalfSireFromBirthEventSrv(uid, birthEvent = {}) {
  if (!db || !uid || !birthEvent) return null;

  const directSire = cardFirstSrv(birthEvent, [
    'sireNumber',
    'fatherNumber',
    'sireId',
    'bullNumber',
    'bullCode',
    'semenCode',
    'semenNumber',
    'strawCode',
    'sire',
    'bull',
    'semen'
  ], '');

  const directName = cardFirstSrv(birthEvent, [
    'sireName',
    'fatherName',
    'bullName'
  ], '');

  if (directSire || directName) {
    return {
      sireNumber: directSire || '',
      sireName: directName || ''
    };
  }

  const damNumber = String(
    birthEvent.animalNumber ||
    birthEvent.damNumber ||
    birthEvent.motherNumber ||
    birthEvent.number ||
    ''
  ).trim();

  const aiDate = String(
    birthEvent.lastFertileInseminationDate ||
    birthEvent.lastInseminationDate ||
    birthEvent.inseminationDate ||
    ''
  ).trim().slice(0, 10);

  if (!damNumber || !aiDate) return null;

  const values = Number.isFinite(Number(damNumber))
    ? [damNumber, Number(damNumber)]
    : [damNumber];

  for (const v of values) {
    try {
      const snap = await db.collection('events')
        .where('userId', '==', uid)
        .where('animalNumber', '==', v)
        .where('eventDate', '==', aiDate)
        .limit(10)
        .get();

      for (const doc of snap.docs) {
        const e = { id: doc.id, ...(doc.data() || {}) };
        const t = String(e.eventType || e.type || e.eventTypeNorm || '').trim();

        if (!(t.includes('تلقيح') || t.includes('insemination'))) continue;

        return {
          sireNumber: cardFirstSrv(e, [
            'sireNumber',
            'fatherNumber',
            'sireId',
            'bullNumber',
            'bullCode',
            'semenCode',
            'semenNumber',
            'strawCode',
            'sire',
            'bull',
            'semen'
          ], ''),
          sireName: cardFirstSrv(e, [
            'sireName',
            'fatherName',
            'bullName'
          ], '')
        };
      }
    } catch (_) {}
  }

  return null;
}
